// Codigo fuente completo del paquete Python (housing_generator, 78
// archivos) incrustado tal cual, para poder escribirlo en el sistema
// de ficheros virtual de Pyodide y ejecutar el generador REAL
// (recocido simulado + los 20 validadores) directamente en el propio
// navegador -- sin terminal, sin descargar/subir archivos. Retomado
// tras una pregunta directa del usuario ("realmente es la forma de
// trabajar?"): el hueco real no era visual, era que el dashboard y
// el generador nunca se hablaban directamente. Ver PYTHON_ENGINE mas
// abajo para la carga de Pyodide + shapely/networkx + este codigo.
const PYTHON_SOURCES = {"housing_generator/__init__.py": "", "housing_generator/infrastructure/browser_bridge.py": "\"\"\"Funcion puente para el Visor de plano en el navegador (Pyodide).\n\nEnvuelve el mismo camino real que ya usa el CLI (--import-seleccion +\nreintento automatico de semillas), pero como funcion que recibe/devuelve\nJSON en vez de leer/escribir archivos -- para poder llamarla directamente\ndesde JavaScript sin pasar por disco.\n\"\"\"\nimport json\nfrom housing_generator.infrastructure.persistence.seleccion_plantas_importer import import_seleccion_plantas\nfrom housing_generator.config.container import build_generate_building_use_case\nfrom housing_generator.domain.entities.lot import Lot\nfrom housing_generator.domain.value_objects.boundary import Boundary\nfrom housing_generator.domain.exceptions import LayoutGenerationError\nfrom housing_generator.infrastructure.algorithms.adjacency.door_graph import build_door_graph\nfrom shapely.geometry import box\n\n\ndef generar_en_navegador(\n    seleccion_json_str: str,\n    lot_width: float,\n    lot_height: float,\n    retranqueo_m: float,\n    seed_inicial: int,\n    max_iterations: int,\n    retry_seeds: int,\n    vivienda_accesible: bool,\n) -> str:\n    \"\"\"Genera un edificio completo a partir del mismo formato de JSON que\n    exporta la pestaña \"Sección vertical\", devolviendo un JSON con el\n    resultado de TODAS las plantas a la vez (a diferencia del CLI, que\n    escribe un archivo por planta) -- listo para pasarselo directamente a\n    LOADED_PLANS en el visor, sin descargar/subir nada.\n    \"\"\"\n    payload = json.loads(seleccion_json_str)\n    seleccion = import_seleccion_plantas(payload)\n    program = seleccion.program\n\n    lot = Lot(\n        boundary=Boundary(polygon=box(0, 0, lot_width, lot_height)),\n        retranqueo_m=retranqueo_m if retranqueo_m > 0 else None,\n        medianera_sides=seleccion.medianera_sides,\n    )\n\n    last_error = None\n    for attempt in range(max(1, retry_seeds)):\n        seed = seed_inicial + attempt\n        use_case = build_generate_building_use_case(\n            adjacency_requirements=program.adjacency_requirements,\n            seed=seed, max_iterations=max_iterations,\n            vivienda_accesible=vivienda_accesible,\n        )\n        try:\n            building = use_case.execute(program, lot)\n        except LayoutGenerationError as e:\n            last_error = str(e)\n            continue\n\n        floors_out = {}\n        for level, layout in building.floors.items():\n            door_graph = build_door_graph(layout, program.adjacency_requirements)\n            floors_out[level.value] = {\n                \"rooms\": [\n                    {\n                        \"id\": r.id, \"name\": r.name, \"type\": r.room_type.value,\n                        \"zone\": r.zone.value, \"area_m2\": r.dimensions.area_m2,\n                        \"bounds\": list(r.boundary.polygon.bounds) if r.boundary else None,\n                    }\n                    for r in layout.rooms\n                ],\n                \"doors\": [{\"room_a\": a, \"room_b\": b} for a, b in door_graph.edges()],\n                \"metadata\": layout.metadata,\n            }\n        return json.dumps({\n            \"ok\": True, \"seed_used\": seed, \"attempts\": attempt + 1,\n            \"medianera_sides\": sorted(seleccion.medianera_sides), \"floors\": floors_out,\n        })\n\n    return json.dumps({\"ok\": False, \"error\": last_error, \"attempts\": retry_seeds})\n", "housing_generator/infrastructure/__init__.py": "", "housing_generator/infrastructure/persistence/json_layout_repository.py": "import json\nfrom typing import List, Optional\nfrom housing_generator.application.ports.layout_repository_port import LayoutRepositoryPort\nfrom housing_generator.domain.entities.layout import Layout\nfrom housing_generator.domain.value_objects.adjacency import AdjacencyRequirement\nfrom housing_generator.infrastructure.algorithms.adjacency.door_graph import build_door_graph\n\n\nclass JsonLayoutRepository(LayoutRepositoryPort):\n    \"\"\"Serializa los datos esenciales de un Layout. El round-trip completo\n    de geometria (via shapely.wkt) se puede anadir cuando haga falta cargar\n    layouts guardados, no solo inspeccionarlos.\"\"\"\n\n    def save(\n        self, layout: Layout, path: str,\n        adjacency_requirements: Optional[List[AdjacencyRequirement]] = None,\n    ) -> None:\n        doors = []\n        if adjacency_requirements:\n            door_graph = build_door_graph(layout, adjacency_requirements)\n            doors = [{\"room_a\": a, \"room_b\": b} for a, b in door_graph.edges()]\n\n        data = {\n            \"rooms\": [\n                {\n                    \"id\": r.id,\n                    \"name\": r.name,\n                    \"type\": r.room_type.value,\n                    \"zone\": r.zone.value,\n                    \"area_m2\": r.dimensions.area_m2,\n                    \"bounds\": list(r.boundary.polygon.bounds) if r.boundary else None,\n                }\n                for r in layout.rooms\n            ],\n            \"doors\": doors,\n            \"metadata\": layout.metadata,\n        }\n        with open(path, \"w\", encoding=\"utf-8\") as f:\n            json.dump(data, f, indent=2, ensure_ascii=False)\n\n    def load(self, path: str) -> Layout:\n        raise NotImplementedError(\"La carga completa de un Layout desde JSON aun no esta implementada\")\n", "housing_generator/infrastructure/persistence/__init__.py": "", "housing_generator/infrastructure/persistence/seleccion_plantas_importer.py": "\"\"\"Importador de `seleccion_plantas.json` (exportacion del dashboard,\npestaña \"Sección vertical\") hacia un `Program` real utilizable por el\ngenerador -- retomado de docs/CONTINUIDAD.md, ultimo pendiente real.\n\n**[RESUELTO] Limitaciones eliminadas de raiz, no solo documentadas**: el\ndashboard ahora captura CANTIDAD real (cuantas estancias de cada tipo\npor planta, ya no maximo 1) y AREA real declarada por el usuario (ya no\nun valor generico de relleno) -- ver `docs/architecture.md`. El formato\nnuevo (`version: 2`) trae `{\"type\": ..., \"count\": ..., \"area_m2\": ...}`\npor entrada en vez de un simple nombre de tipo. Compatibilidad hacia\natras con el formato anterior (solo nombres de tipo, sin version)\npreservada -- por si existe algun `seleccion_plantas.json` exportado\nantes de este cambio: en ese caso SI se sigue usando\n`AREAS_POR_DEFECTO_M2` como aproximacion, exactamente como antes.\n\n**[RESUELTO] `tipo_vivienda` conectado de verdad, no solo exportado.**\nHallazgo real de la auditoria de flujo completo: el dashboard exportaba\n`tipo_vivienda` (aislada/pareada/adosada) desde hace varias rondas,\npero NINGUN sitio de Python lo leia -- elegir \"adosada\" en el panel\nautomatico no tenia ningun efecto real al generar, se perdia en\nsilencio. `import_seleccion_plantas` ahora tambien resuelve\n`medianera_sides` a partir de ese campo, listo para pasarselo a `Lot`.\n\"\"\"\nimport json\nfrom pathlib import Path\nfrom typing import Dict, FrozenSet, List, NamedTuple, Optional, Union\nfrom housing_generator.domain.entities.program import Program\nfrom housing_generator.domain.entities.room import Room\nfrom housing_generator.domain.value_objects.dimensions import Dimensions\nfrom housing_generator.domain.enums import RoomType, NivelPlanta, DISPLAY_NAMES\nfrom housing_generator.domain.services.type_adjacency_catalog import generate_adjacency_requirements\n\n# Areas por defecto, genericas -- solo se usan con el formato ANTIGUO\n# (sin cantidad/area declaradas) o si una entrada del formato nuevo no\n# trae area_m2 valida. NO derivadas de Tabla 1/2 (esas dependen del\n# numero total de estancias del programa completo, que no se puede\n# conocer de antemano sin ya haber decidido las areas).\nAREAS_POR_DEFECTO_M2: Dict[RoomType, float] = {\n    RoomType.LIVING_ROOM: 25.0,\n    RoomType.DINING_ROOM: 14.0,\n    RoomType.KITCHEN: 10.0,\n    RoomType.BEDROOM: 12.0,\n    RoomType.MASTER_BEDROOM: 15.0,\n    RoomType.BATHROOM: 5.5,\n    RoomType.TOILET: 3.0,\n    RoomType.ENTRANCE_HALL: 4.5,\n    RoomType.STUDY: 9.0,\n    RoomType.LAUNDRY: 3.0,\n    RoomType.DRYING_AREA: 2.0,\n    RoomType.STORAGE: 3.0,\n    RoomType.STORAGE_ROOM: 4.0,\n    RoomType.GARAGE: 18.0,\n    RoomType.TECHNICAL_ROOM: 3.0,\n    RoomType.CORRIDOR: 4.0,\n}\n\n# tipo_vivienda (dashboard) -> Lot.medianera_sides. \"pareada\" usa UN\n# lado (elegido \"east\" por convencion propia -- el dashboard no\n# pregunta orientacion real, no hay forma de saber cual lado concreto\n# corresponde a la parcela real del usuario); \"adosada\" usa DOS lados\n# opuestos (este y oeste), el patron tipico de vivienda entre\n# medianeras a ambos lados. Sin sorpresas: quien necesite una\n# orientacion real distinta puede construir su propio `Lot` en Python\n# en vez de depender de esta convencion por defecto.\nMEDIANERA_SIDES_BY_TIPO_VIVIENDA: Dict[str, FrozenSet[str]] = {\n    \"aislada\": frozenset(),\n    \"pareada\": frozenset({\"east\"}),\n    \"adosada\": frozenset({\"east\", \"west\"}),\n}\n\n\nclass SeleccionImportada(NamedTuple):\n    \"\"\"Resultado de `import_seleccion_plantas`: el `Program` real, y los\n    `medianera_sides` resueltos a partir de `tipo_vivienda` -- listos\n    para pasarselos directamente a `Lot(medianera_sides=...)`.\"\"\"\n    program: Program\n    medianera_sides: FrozenSet[str]\n\n\ndef import_seleccion_plantas(\n    source: Union[str, Path, dict],\n    areas_m2: Optional[Dict[RoomType, float]] = None,\n) -> SeleccionImportada:\n    \"\"\"Construye un `Program` real a partir del JSON exportado por el\n    dashboard, y resuelve `medianera_sides` a partir de `tipo_vivienda`\n    (si el JSON lo trae -- formato antiguo no lo tiene, resuelve a\n    aislada/sin medianera). `source` puede ser una ruta de archivo o el\n    dict ya cargado. `areas_m2` sobreescribe `AREAS_POR_DEFECTO_M2` por\n    tipo, usado como respaldo si una entrada no trae area propia.\n\n    Soporta el formato nuevo (`version: 2`, con cantidad y area reales\n    por entrada) y el antiguo (lista plana de nombres de tipo, sin\n    cantidad ni area -- una estancia por tipo/planta, area generica).\n\n    Las relaciones de adyacencia del `Program` resultante se derivan\n    automaticamente del catalogo formalizado\n    (`generate_adjacency_requirements`), no hace falta declararlas.\n\n    Devuelve `SeleccionImportada(program, medianera_sides)` -- ver esa\n    clase para como usar `medianera_sides` con `Lot`.\n    \"\"\"\n    if isinstance(source, (str, Path)):\n        with open(source, encoding=\"utf-8\") as f:\n            payload = json.load(f)\n    else:\n        payload = source\n\n    default_areas = {**AREAS_POR_DEFECTO_M2, **(areas_m2 or {})}\n    rooms: List[Room] = []\n\n    for level_name, entries in payload.get(\"levels\", {}).items():\n        level = NivelPlanta[level_name]\n        for entry in entries:\n            if isinstance(entry, str):\n                # formato antiguo: solo el nombre de tipo, sin cantidad ni area\n                type_name, count, area = entry, 1, None\n            else:\n                # formato nuevo: {\"type\": ..., \"count\": ..., \"area_m2\": ...}\n                type_name = entry[\"type\"]\n                count = max(1, int(entry.get(\"count\", 1)))\n                area = entry.get(\"area_m2\")\n\n            room_type = RoomType[type_name]\n            final_area = area if area else default_areas.get(room_type, 10.0)\n\n            for i in range(1, count + 1):\n                suffix = f\"_{i}\" if count > 1 else \"\"\n                room_id = f\"{type_name.lower()}_{level_name.lower()}{suffix}\"\n                display_name = DISPLAY_NAMES.get(room_type, room_type.value)\n                if count > 1:\n                    display_name = f\"{display_name} {i}\"\n                rooms.append(Room(\n                    id=room_id,\n                    name=display_name,\n                    room_type=room_type,\n                    dimensions=Dimensions(area_m2=final_area),\n                    level=level,\n                ))\n\n    adjacency = generate_adjacency_requirements(rooms)\n    program = Program(rooms=rooms, adjacency_requirements=adjacency)\n\n    tipo_vivienda = payload.get(\"tipo_vivienda\", \"aislada\")\n    medianera_sides = MEDIANERA_SIDES_BY_TIPO_VIVIENDA.get(tipo_vivienda, frozenset())\n\n    return SeleccionImportada(program=program, medianera_sides=medianera_sides)\n", "housing_generator/infrastructure/geometry/shapely_utils.py": "\"\"\"Utilidades geometricas compartidas basadas en shapely.\n\nSe deja como modulo separado para que los generadores de layout no\ndupliquen logica de particionado/interseccion cuando se anadan nuevas\nestrategias (CSP, genetico, etc.).\n\"\"\"\nimport math\nfrom typing import List, Optional, Tuple\nfrom shapely.geometry import Polygon, LineString\n\n\ndef _is_axis_or_rotated_rectangle(polygon: Polygon, relative_tolerance: float = 0.01) -> bool:\n    \"\"\"Comprueba que `polygon` es (aproximadamente) un rectangulo, con\n    cualquier rotacion -- no solo alineado a ejes. Compara el area real\n    contra la del rectangulo minimo que lo envuelve (`minimum_rotated_rectangle`):\n    si coinciden, el poligono ES ese rectangulo.\"\"\"\n    mrr_area = polygon.minimum_rotated_rectangle.area\n    if mrr_area <= 0:\n        return False\n    return abs(polygon.area - mrr_area) <= relative_tolerance * mrr_area\n\n\ndef rectangle_side_lengths(polygon: Polygon) -> Tuple[float, float]:\n    \"\"\"Longitudes de los dos lados adyacentes del rectangulo minimo que\n    envuelve `polygon` (valido tanto si esta alineado a ejes como rotado).\"\"\"\n    mrr = polygon.minimum_rotated_rectangle\n    coords = list(mrr.exterior.coords)  # 5 puntos, el ultimo repite el primero\n    side_a = math.hypot(coords[1][0] - coords[0][0], coords[1][1] - coords[0][1])\n    side_b = math.hypot(coords[2][0] - coords[1][0], coords[2][1] - coords[1][1])\n    return side_a, side_b\n\n\ndef can_fit_rectangle(polygon: Polygon, side_a_m: float, side_b_m: float) -> Optional[bool]:\n    \"\"\"¿Cabe un rectangulo de `side_a_m` x `side_b_m` dentro de `polygon`\n    (en cualquiera de las dos orientaciones)?\n\n    Mismos TRES estados que `can_inscribe_square` (del que esta funcion\n    es la generalizacion): True / False / None (\"no verificable\", nunca\n    confundido con \"aprobado\").\n    \"\"\"\n    if not _is_axis_or_rotated_rectangle(polygon):\n        return None\n    width, height = rectangle_side_lengths(polygon)\n    return (width >= side_a_m and height >= side_b_m) or (width >= side_b_m and height >= side_a_m)\n\n\ndef can_inscribe_square(polygon: Polygon, side_length_m: float) -> Optional[bool]:\n    \"\"\"¿Cabe un cuadrado de `side_length_m` de lado dentro de `polygon`?\n    Caso particular de `can_fit_rectangle` con los dos lados iguales.\"\"\"\n    return can_fit_rectangle(polygon, side_length_m, side_length_m)\n\n\ndef meets_minimum_width(polygon: Polygon, min_width_m: float) -> Optional[bool]:\n    \"\"\"Ancho libre entre paramentos enfrentados (A.3.2.1 / A.3.2.3): el\n    lado MAS CORTO del rectangulo debe ser >= min_width_m. A diferencia\n    de `can_fit_rectangle`, aqui el lado corto de LA PROPIA estancia es\n    el que se mide directamente, no si cabe otra forma dentro.\"\"\"\n    if not _is_axis_or_rotated_rectangle(polygon):\n        return None\n    width, height = rectangle_side_lengths(polygon)\n    return min(width, height) >= min_width_m\n\n\ndef count_exterior_sides(\n    room_polygon: Polygon,\n    lot_polygon: Polygon,\n    min_contact_m: float = 0.3,\n    excluded_segments: Optional[List[LineString]] = None,\n) -> Optional[int]:\n    \"\"\"Cuenta cuantos de los 4 lados de `room_polygon` tienen contacto\n    real con el limite de `lot_polygon` (al menos `min_contact_m` de\n    borde compartido -- umbral distinto y mayor que el de adyacencia\n    interior entre estancias, 0.1m, confirmado por el usuario para\n    contacto con el exterior).\n\n    `excluded_segments`: lados de la parcela que NO cuentan como\n    contacto exterior real aunque toquen `lot_polygon.boundary` --\n    retomado de docs/CONTINUIDAD.md (\"vivienda pareada/adosada\"): una\n    pared de medianera (`Lot.medianera_boundary_segments()`) no tiene\n    luz ni ventilacion propia, aunque geometricamente sea un \"borde de\n    la parcela\" igual que cualquier otro. `None` (por defecto) preserva\n    el comportamiento anterior sin cambios (vivienda aislada, todos los\n    lados de la parcela cuentan).\n\n    Devuelve None (no verificable) si `room_polygon` no es rectangular,\n    igual que el resto de utilidades de este modulo -- nunca se asume\n    un numero de lados exteriores sin poder confirmarlo geometricamente.\n    \"\"\"\n    if not _is_axis_or_rotated_rectangle(room_polygon):\n        return None\n\n    mrr = room_polygon.minimum_rotated_rectangle\n    coords = list(mrr.exterior.coords)  # 5 puntos, el ultimo repite el primero\n    lot_boundary = lot_polygon.boundary\n    if excluded_segments:\n        for seg in excluded_segments:\n            lot_boundary = lot_boundary.difference(seg.buffer(1e-6))\n\n    count = 0\n    for i in range(4):\n        side = LineString([coords[i], coords[i + 1]])\n        overlap_length = side.intersection(lot_boundary).length\n        if overlap_length >= min_contact_m:\n            count += 1\n    return count\n\n\ndef evaluate_minimum_width(\n    room_id: str,\n    polygon: Polygon,\n    threshold_m: float,\n    violation_message: str,\n    warning_message: str,\n) -> tuple:\n    \"\"\"Evalua el ancho libre minimo (meets_minimum_width, 3 estados) de\n    una estancia y devuelve (violaciones, avisos) -- listas de 0 o 1\n    elemento cada una, listas para que el llamador haga\n    `violations.extend(v); warnings.extend(w)`.\n\n    `violation_message`/`warning_message` ya vienen formateados por\n    completo por el llamador (incluido el umbral y cualquier referencia\n    normativa) -- este helper solo antepone `'{room_id}': ` y decide\n    cual de los dos usar segun el resultado de 3 estados. Diseño\n    deliberadamente flexible tras un primer intento mas rigido (umbral\n    siempre al final entre parentesis) que no encajaba con\n    EscaleraAnchoLibreValidator, cuyo mensaje pone la referencia\n    normativa DENTRO del mismo parentesis que el umbral.\n\n    DUPLICACION REAL encontrada en auditoria (deteccion sistematica de\n    bloques repetidos entre archivos, no solo intuicion): tres\n    validadores distintos (pasillo A.3.2.3, escalera CTE DB-SUA 1,\n    trastero B.2.5) repetian exactamente el manejo de los 3 estados de\n    `meets_minimum_width`, solo cambiaba el umbral y el texto.\"\"\"\n    cumple = meets_minimum_width(polygon, threshold_m)\n    if cumple is False:\n        return ([f\"'{room_id}': {violation_message}\"], [])\n    elif cumple is None:\n        return ([], [f\"'{room_id}': {warning_message}\"])\n    return ([], [])\n", "housing_generator/infrastructure/geometry/__init__.py": "", "housing_generator/infrastructure/algorithms/__init__.py": "", "housing_generator/infrastructure/algorithms/adjacency/__init__.py": "", "housing_generator/infrastructure/algorithms/adjacency/geometry_adjacency_graph_builder.py": "from typing import Optional\nimport networkx as nx\nfrom housing_generator.application.ports.adjacency_graph_builder_port import AdjacencyGraphBuilderPort\nfrom housing_generator.domain.entities.layout import Layout\nfrom housing_generator.domain.entities.room import Room\n\n\nclass GeometryAdjacencyGraphBuilder(AdjacencyGraphBuilderPort):\n    \"\"\"Construye el grafo de adyacencia real midiendo la longitud del\n    segmento de borde compartido entre cada par de estancias colocadas.\n\n    Un simple `touches()` de shapely tambien da positivo con un contacto\n    de una sola esquina (un punto), que no es una pared real. Por eso se\n    mide la LONGITUD de la interseccion de los bordes y se exige un\n    minimo configurable (`min_shared_edge_m`) para que cuente como\n    adyacencia real -- un punto de contacto mide longitud 0 y queda\n    descartado automaticamente, sin caso especial.\n\n    `min_shared_edge_m` es deliberadamente un parametro, no una constante\n    fija: la distincion entre adyacencia interior (pared entre dos\n    estancias) y contacto con el exterior (fachada/limite de solar) usa\n    umbrales distintos segun el caso de uso.\n\n    CACHE de una sola entrada (bug de rendimiento real encontrado en\n    auditoria, no una optimizacion especulativa): `container.py` conecta\n    la MISMA instancia de esta clase a 5 validadores distintos (nucleo\n    humedo, zonificacion dia/noche/servicio, topologia de pasillo), y\n    los 5 se ejecutan sobre el MISMO `Layout` dentro de una unica llamada\n    a `CompositeConstraintValidator.validate()` -- sin cache, cada uno\n    reconstruye el grafo desde cero (O(n^2) intersecciones geometricas),\n    5 veces por iteracion del recocido simulado. Medido con el programa\n    de ejemplo del CLI: 9.35s -> 4.52s (mas del doble de rapido) solo con\n    esta cache.\n\n    BUG REAL encontrado y corregido durante la propia auditoria: la\n    primera version cacheaba por `id(layout)` (un entero). Comprobado\n    con un experimento directo: en un bucle de creacion/descarte de\n    `Layout` como el que hace el recocido simulado, de 1000 objetos\n    creados solo 6 `id()` distintos aparecieron -- Python REUTILIZA\n    agresivamente direcciones de memoria de objetos ya liberados. Cachear\n    solo por `id()` habria devuelto resultados de un Layout COMPLETAMENTE\n    DISTINTO que por pura casualidad reutilizo la misma direccion,\n    silenciosamente. Corregido guardando una REFERENCIA real al objeto\n    (no solo su id): mientras esa referencia siga viva, Python no puede\n    liberar esa memoria ni reutilizarla para otro objeto, eliminando la\n    colision de raiz -- coste: mantener UN Layout adicional vivo un poco\n    mas, insignificante frente al ahorro.\n    \"\"\"\n\n    def __init__(self, min_shared_edge_m: float = 0.1):\n        self._min_shared_edge_m = min_shared_edge_m\n        self._cache_layout_ref: Optional[Layout] = None\n        self._cache_result: Optional[nx.Graph] = None\n\n    def build(self, layout: Layout) -> nx.Graph:\n        if layout is self._cache_layout_ref:\n            return self._cache_result\n\n        graph = nx.Graph()\n        placed_rooms = [r for r in layout.rooms if r.is_placed]\n\n        for room in placed_rooms:\n            graph.add_node(\n                room.id,\n                name=room.name,\n                room_type=room.room_type,\n                zone=room.zone,\n                is_wet=room.is_wet,\n            )\n\n        for i, room_a in enumerate(placed_rooms):\n            for room_b in placed_rooms[i + 1:]:\n                shared_length = self._shared_boundary_length(room_a, room_b)\n                if shared_length >= self._min_shared_edge_m:\n                    graph.add_edge(room_a.id, room_b.id, shared_length_m=shared_length)\n\n        self._cache_layout_ref = layout\n        self._cache_result = graph\n        return graph\n\n    @staticmethod\n    def _shared_boundary_length(room_a: Room, room_b: Room) -> float:\n        boundary_a = room_a.boundary.polygon.boundary\n        boundary_b = room_b.boundary.polygon.boundary\n        return boundary_a.intersection(boundary_b).length\n", "housing_generator/infrastructure/algorithms/adjacency/door_graph.py": "from typing import List\nimport networkx as nx\nfrom housing_generator.domain.entities.layout import Layout\nfrom housing_generator.domain.value_objects.adjacency import AdjacencyRequirement\nfrom housing_generator.domain.enums import AdjacencyStrength\nfrom housing_generator.infrastructure.algorithms.constraints.adjacency_validator import (\n    MUST_BE_NEAR_MIN_SHARED_LENGTH_M,\n)\n\n# Hueco de modelo identificado en relaciones_espaciales.md: \"acceso/\n# puertas -- 'cerca pero sin puerta directa' no se podia expresar con la\n# geometria actual\". Resuelto aqui de forma deliberadamente minima,\n# inspirado en el patron \"Door Connectivity Graph\" (grafo de puertas\n# como capa SEPARADA y mas dispersa que la de adyacencia geometrica,\n# en vez de modelar geometria real de puertas -- posicion, ancho,\n# sentido de apertura) encontrado en investigacion externa (paper\n# \"Automatic Rendering of Building Floor Plan Images from Textual\n# Descriptions\"). Infinigen Indoors (2024) confirma ademas que la\n# colocacion de puertas es tipicamente un paso POSTERIOR a resolver las\n# posiciones, no algo que compita con la busqueda del generador -- este\n# grafo se construye sobre un Layout ya generado, no durante la busqueda.\n#\n# Regla de \"tiene puerta\" (deliberadamente simple, no exhaustiva):\n# un par de estancias tiene puerta si y solo si hay un\n# AdjacencyRequirement(MUST_BE_NEAR) declarado para ese par Y la\n# geometria final realmente los coloco adyacentes. El umbral de\n# MUST_BE_NEAR (1.0m de borde compartido) ya se eligio especificamente\n# \"para que quepa una puerta\" (confirmado por el usuario al implementar\n# AdjacencyConstraintValidator) -- este grafo simplemente hace explicito\n# lo que ese umbral ya representaba implicitamente, sin inventar una\n# regla nueva. Cualquier otro par de estancias adyacentes (comparten\n# pared por optimizacion geometrica, sin requisito declarado) queda\n# fuera: \"cerca pero sin puerta directa\", exactamente el caso que antes\n# no se podia distinguir.\n\n\ndef build_door_graph(layout: Layout, adjacency_requirements: List[AdjacencyRequirement]) -> nx.Graph:\n    \"\"\"Grafo de puertas: subconjunto DISPERSO del grafo de adyacencia\n    geometrica real, solo los pares con un AdjacencyRequirement(MUST_BE_NEAR)\n    declarado Y satisfecho por la geometria final. No modela geometria de\n    puertas (posicion/ancho/apertura) -- solo si existe una, a nivel de\n    grafo, igual que la propia adyacencia no modela grosor de muro.\"\"\"\n    graph = nx.Graph()\n    placed_ids = {r.id for r in layout.rooms if r.is_placed}\n    rooms_by_id = {r.id: r for r in layout.rooms if r.is_placed}\n\n    for room_id in placed_ids:\n        room = rooms_by_id[room_id]\n        graph.add_node(room_id, name=room.name, room_type=room.room_type)\n\n    for req in adjacency_requirements:\n        if req.strength != AdjacencyStrength.MUST_BE_NEAR:\n            continue\n        if req.room_a_id not in placed_ids or req.room_b_id not in placed_ids:\n            continue\n\n        room_a = rooms_by_id[req.room_a_id]\n        room_b = rooms_by_id[req.room_b_id]\n        shared_length = room_a.boundary.polygon.boundary.intersection(\n            room_b.boundary.polygon.boundary\n        ).length\n        if shared_length >= MUST_BE_NEAR_MIN_SHARED_LENGTH_M:  # mismo umbral que AdjacencyConstraintValidator\n            graph.add_edge(req.room_a_id, req.room_b_id, shared_length_m=shared_length)\n\n    return graph\n", "housing_generator/infrastructure/algorithms/constraints/servicio_minimum_area_validator.py": "from typing import List, Dict, Optional\nfrom housing_generator.application.ports.constraint_validator_port import ConstraintValidatorPort\nfrom housing_generator.application.dto.validation_result import ValidationResult\nfrom housing_generator.domain.entities.layout import Layout\nfrom housing_generator.domain.enums import SpaceCategory\n\n# Tabla 2 (A.3.2.2 en nhv.lua / Decreto 29/2010): superficie util minima\n# por TIPO DE SERVICIO, segun el numero de estancias de la vivienda (no\n# el tamano del servicio en si). Portado literalmente de la fuente\n# normativa. \"aseo\" no aparece como clave hasta 4 estancias -- eso es\n# fiel al original, no un olvido: con menos de 4 estancias la norma no\n# exige un aseo independiente, asi que si el programa declara uno de\n# todas formas, no hay minimo que comprobar (ver nota en el validador).\nTABLA_2: Dict[int, Dict[str, float]] = {\n    1: {\"cocina\": 5, \"bano\": 5, \"lavadero\": 1.5, \"tendedero\": 1.5, \"almacenamiento\": 1},\n    2: {\"cocina\": 7, \"bano\": 5, \"lavadero\": 1.5, \"tendedero\": 1.5, \"almacenamiento\": 2},\n    3: {\"cocina\": 7, \"bano\": 5, \"lavadero\": 1.5, \"tendedero\": 1.5, \"almacenamiento\": 3},\n    4: {\"cocina\": 9, \"bano\": 5, \"aseo\": 1.5, \"lavadero\": 1.5, \"tendedero\": 1.5, \"almacenamiento\": 4},\n    5: {\"cocina\": 9, \"bano\": 5, \"aseo\": 1.5, \"lavadero\": 1.5, \"tendedero\": 1.5, \"almacenamiento\": 5},\n}\nTABLA_2_MAS_DE_CINCO: Dict[str, float] = {\n    \"cocina\": 10, \"bano\": 5, \"aseo\": 1.5, \"lavadero\": 1.5, \"tendedero\": 1.5, \"almacenamiento\": 6,\n}\n\n\ndef tabla_servicios_para(num_estancias: int) -> Dict[str, float]:\n    \"\"\"Fila de Tabla 2 correspondiente a `num_estancias` (numero de\n    estancias -- categoria ESTANCIA, no numero total de piezas).\"\"\"\n    if num_estancias in TABLA_2:\n        return TABLA_2[num_estancias]\n    if num_estancias < 1:\n        return TABLA_2[1]\n    return TABLA_2_MAS_DE_CINCO\n\n\nclass ServicioMinimumAreaValidator(ConstraintValidatorPort):\n    \"\"\"Tabla 2: superficie minima por tipo de servicio (cocina, bano,\n    aseo, lavadero, tendedero, almacenamiento), segun el numero de\n    estancias de la vivienda.\n\n    NOTA DE ALCANCE: \"cocina integrada en estancia mayor\" (superficie\n    combinada distinta) y \"trastero\" B.2.5 (regla fija de 4.00m2,\n    distinta de \"almacenamiento\") NO se comprueban en ESTE validador --\n    pero SÍ están cubiertas, cada una en su propio validador dedicado\n    (`CocinaIntegradaValidator`, `TrasteroMinimumAreaValidator`),\n    construidos en incrementos posteriores a como se escribió\n    originalmente esta nota. No son pendientes: son piezas propias,\n    exactamente como esta nota anticipaba que deberían resolverse.\n\n    `total_num_estancias_override`: mismo motivo que en\n    `EstanciaMinimumAreaValidator` -- para vivienda MULTI-PLANTA, Tabla 2\n    depende del numero de estancias del EDIFICIO COMPLETO, no solo de\n    las de esta planta.\n    \"\"\"\n\n    def __init__(self, total_num_estancias_override: Optional[int] = None):\n        self._total_override = total_num_estancias_override\n\n    def validate(self, layout: Layout) -> ValidationResult:\n        local_count = sum(1 for r in layout.rooms if r.space_category == SpaceCategory.ESTANCIA)\n        num_estancias = self._total_override if self._total_override is not None else local_count\n        tabla = tabla_servicios_para(num_estancias)\n\n        violations: List[str] = []\n        for room in layout.rooms:\n            if room.service_subtype is None:\n                continue\n            if room.integrated_in_largest_room:\n                # cocina integrada: se valida con CocinaIntegradaValidator\n                # (superficie combinada con la estancia mayor), no aqui --\n                # misma exclusion que en nhv.lua (`not e.integradaEnEstanciaMayor`).\n                continue\n            minimo = tabla.get(room.service_subtype)\n            if minimo is None:\n                continue\n            if room.dimensions.area_m2 < minimo:\n                violations.append(\n                    f\"'{room.id}' ({room.service_subtype}): {room.dimensions.area_m2:.1f}m2, \"\n                    f\"por debajo del minimo de Tabla 2 para {num_estancias} estancias \"\n                    f\"({minimo:.1f}m2)\"\n                )\n\n        return ValidationResult(violations=violations)\n", "housing_generator/infrastructure/algorithms/constraints/pasillo_topologia_validator.py": "from typing import List, Set\nimport networkx as nx\nfrom housing_generator.application.ports.constraint_validator_port import ConstraintValidatorPort\nfrom housing_generator.application.ports.adjacency_graph_builder_port import AdjacencyGraphBuilderPort\nfrom housing_generator.application.dto.validation_result import ValidationResult\nfrom housing_generator.domain.entities.layout import Layout\nfrom housing_generator.domain.enums import RoomType, SpaceCategory\n\n# Segundo hueco de modelo de relaciones_espaciales.md: \"topologia de\n# circulacion (de paso vs. terminal)\". KITCHEN-CORRIDOR senalaba \"el\n# pasillo debe llevar a la cocina, no atravesarla\" -- formalizado aqui\n# con deteccion de puntos de corte (articulation points) sobre el\n# grafo de ADYACENCIA GEOMETRICA REAL (misma fuente que ya usan nucleo\n# humedo y zonificacion dia/noche/servicio -- GeometryAdjacencyGraphBuilder,\n# umbral 0.1m de pared compartida), NO sobre el grafo de puertas\n# disperso (build_door_graph).\n#\n# CORRECCION REAL tras un primer intento fallido: la primera version\n# usaba el grafo de puertas (solo relaciones Obligatorio cerca\n# declaradas explicitamente) -- con programas reales, donde la mayoria\n# de \"cercanias\" son Preferencia (no Obligatorio), ese grafo resulto\n# demasiado disperso: casi CUALQUIER estancia parecia un \"paso\n# obligado\" simplemente porque no habia redundancia de conexiones\n# declaradas (rompio 9 tests, incluido el CLI). Usar la adyacencia\n# geometrica real (que existe siempre, declarada o no) resuelve esto:\n# refleja lo que de verdad se construyo, no solo lo que se pidio\n# explicitamente.\n#\n# Regla (confirmada con el usuario, con excepcion explicita): ninguna\n# estancia que NO sea de circulacion (CORRIDOR/ENTRANCE_HALL/STAIRCASE,\n# SpaceCategory.CIRCULACION) puede ser un punto de corte obligado entre\n# la circulacion y OTRA estancia -- EXCEPTO LIVING_ROOM y DINING_ROOM,\n# exentas (en un salon-comedor abierto es arquitectonicamente normal\n# atravesarlos para llegar a otras zonas).\nEXENTOS_DE_LA_REGLA = {RoomType.LIVING_ROOM, RoomType.DINING_ROOM}\n\n\nclass PasilloTopologiaValidator(ConstraintValidatorPort):\n    \"\"\"Ninguna estancia protegida (no circulacion, no exenta) puede ser\n    un punto de corte obligado entre la circulacion y otra estancia\n    protegida -- si quitarla del grafo de adyacencia geometrica real\n    deja a otra sin camino hacia ninguna estancia de circulacion, se\n    esta obligando a atravesarla para llegar a algun sitio.\"\"\"\n\n    def __init__(self, graph_builder: AdjacencyGraphBuilderPort):\n        self._graph_builder = graph_builder\n\n    def validate(self, layout: Layout) -> ValidationResult:\n        graph = self._graph_builder.build(layout)\n        rooms_by_id = {r.id: r for r in layout.rooms if r.is_placed}\n\n        circulation_ids: Set[str] = {\n            rid for rid in graph.nodes\n            if rooms_by_id[rid].space_category == SpaceCategory.CIRCULACION\n        }\n        if not circulation_ids:\n            return ValidationResult()  # nada de circulacion en el grafo -- no hay nada que comprobar\n\n        protected_ids: Set[str] = {\n            rid for rid in graph.nodes\n            if rooms_by_id[rid].space_category != SpaceCategory.CIRCULACION\n            and rooms_by_id[rid].room_type not in EXENTOS_DE_LA_REGLA\n        }\n\n        violations: List[str] = []\n        for candidate_id in protected_ids:\n            reduced = graph.copy()\n            reduced.remove_node(candidate_id)\n\n            for other_id in protected_ids:\n                if other_id == candidate_id or other_id not in reduced:\n                    continue\n                reachable = nx.node_connected_component(reduced, other_id)\n                if not (reachable & circulation_ids):\n                    violations.append(\n                        f\"'{rooms_by_id[candidate_id].id}' actúa como paso obligado hacia \"\n                        f\"'{rooms_by_id[other_id].id}' -- sin ella, esta última queda \"\n                        f\"desconectada de toda circulación\"\n                    )\n\n        return ValidationResult(violations=violations)\n", "housing_generator/infrastructure/algorithms/constraints/ancho_libre_pasillo_validator.py": "from typing import List\nfrom housing_generator.application.ports.constraint_validator_port import ConstraintValidatorPort\nfrom housing_generator.application.dto.validation_result import ValidationResult\nfrom housing_generator.domain.entities.layout import Layout\nfrom housing_generator.domain.enums import RoomType\nfrom housing_generator.infrastructure.geometry.shapely_utils import evaluate_minimum_width\n\n# A.3.2.3: espacios de comunicacion interiores a la vivienda (pasillos).\n# No se modela la distincion \"estrechamiento puntual\" (0.90m) vs \"todo\n# el recorrido\" (1.00m) -- nuestras estancias son siempre rectangulares\n# (particion guillotina), asi que el ancho es uniforme en todo el\n# CORRIDOR; se aplica el minimo general de todo el recorrido (1.00m).\nANCHO_LIBRE_PASILLO_M = 1.00\n\n\nclass AnchoLibrePasilloValidator(ConstraintValidatorPort):\n    \"\"\"A.3.2.3: el ancho libre de cada CORRIDOR debe ser >= 1.00m (no se\n    aplica el minimo mas laxo de estrechamiento puntual, 0.90m, porque\n    nuestras estancias rectangulares no representan una diferencia entre\n    \"un punto\" y \"todo el recorrido\").\"\"\"\n\n    def validate(self, layout: Layout) -> ValidationResult:\n        violations: List[str] = []\n        warnings: List[str] = []\n\n        for room in layout.rooms:\n            if room.room_type != RoomType.CORRIDOR or not room.is_placed:\n                continue\n            v, w = evaluate_minimum_width(\n                room.id, room.boundary.polygon, ANCHO_LIBRE_PASILLO_M,\n                violation_message=f\"ancho libre por debajo del minimo de A.3.2.3 ({ANCHO_LIBRE_PASILLO_M:.2f}m)\",\n                warning_message=\"forma no rectangular, no se puede verificar el ancho libre de pasillo (A.3.2.3)\",\n            )\n            violations.extend(v)\n            warnings.extend(w)\n\n        return ValidationResult(violations=violations, warnings=warnings)\n", "housing_generator/infrastructure/algorithms/constraints/grouping_constraint_validator.py": "from typing import Callable, List, Optional\nimport networkx as nx\nfrom housing_generator.application.ports.constraint_validator_port import ConstraintValidatorPort\nfrom housing_generator.application.ports.adjacency_graph_builder_port import AdjacencyGraphBuilderPort\nfrom housing_generator.application.dto.validation_result import ValidationResult\nfrom housing_generator.domain.entities.layout import Layout\nfrom housing_generator.domain.entities.room import Room\n\n\nclass GroupingConstraintValidator(ConstraintValidatorPort):\n    \"\"\"Comprueba que todas las estancias que cumplen `predicate` esten a\n    distancia (numero de paredes que hay que cruzar) <= `max_distance`\n    entre si, medida sobre el grafo de adyacencia REAL (geometria ya\n    generada, no requisitos declarados).\n\n    Es el mismo mecanismo generico que sirve tanto para el nucleo humedo\n    (predicate=is_wet, max_distance=1, pared compartida) como, mas\n    adelante, para zonificacion dia/noche (predicate=misma zona,\n    max_distance mayor, sin exigir pared comun) -- solo cambian los tres\n    parametros, no la logica de medicion.\n    \"\"\"\n\n    def __init__(\n        self,\n        graph_builder: AdjacencyGraphBuilderPort,\n        predicate: Callable[[Room], bool],\n        max_distance: int,\n        label: str,\n    ):\n        self._graph_builder = graph_builder\n        self._predicate = predicate\n        self._max_distance = max_distance\n        self._label = label\n\n    def validate(self, layout: Layout) -> ValidationResult:\n        graph = self._graph_builder.build(layout)\n        members = [r.id for r in layout.rooms if r.is_placed and self._predicate(r)]\n\n        violations: List[str] = []\n        for i, room_a_id in enumerate(members):\n            for room_b_id in members[i + 1:]:\n                distance = self._distance(graph, room_a_id, room_b_id)\n                if distance is None:\n                    violations.append(\n                        f\"'{room_a_id}' y '{room_b_id}' ({self._label}) no estan conectadas \"\n                        f\"en el grafo de adyacencia real\"\n                    )\n                elif distance > self._max_distance:\n                    violations.append(\n                        f\"'{room_a_id}' y '{room_b_id}' ({self._label}) estan a distancia \"\n                        f\"{distance}, por encima del maximo permitido ({self._max_distance})\"\n                    )\n        return ValidationResult(violations=violations)\n\n    @staticmethod\n    def _distance(graph: nx.Graph, a: str, b: str) -> Optional[int]:\n        try:\n            return nx.shortest_path_length(graph, a, b)\n        except (nx.NetworkXNoPath, nx.NodeNotFound):\n            return None\n", "housing_generator/infrastructure/algorithms/constraints/cocina_integrada_validator.py": "from typing import List, Optional, Tuple\nfrom housing_generator.application.ports.constraint_validator_port import ConstraintValidatorPort\nfrom housing_generator.application.dto.validation_result import ValidationResult\nfrom housing_generator.domain.entities.layout import Layout\nfrom housing_generator.domain.entities.room import Room\nfrom housing_generator.domain.enums import RoomType, SpaceCategory\nfrom housing_generator.infrastructure.algorithms.constraints.estancia_minimum_area_validator import (\n    minimo_estancia,\n)\nfrom housing_generator.infrastructure.algorithms.constraints.servicio_minimum_area_validator import (\n    tabla_servicios_para,\n)\n\n# A.3.2.2 / nhv.lua (validarCocinaIntegrada): cuando la cocina se abre en\n# un unico espacio con la estancia mayor (caso tipico de un estudio), la\n# superficie minima del CONJUNTO es la SUMA de los minimos de cada pieza\n# por separado (Tabla 1 para la estancia mayor + Tabla 2 para la cocina,\n# cada una segun el numero de estancias) -- no un numero fijo propio.\n# Ademas exige una apertura vertical minima de relacion entre ambas.\nAPERTURA_VERTICAL_MIN_M2 = 3.5\n\n\nclass CocinaIntegradaValidator(ConstraintValidatorPort):\n    \"\"\"Valida la cocina integrada en la estancia mayor (RoomType.KITCHEN\n    con `integrated_in_largest_room=True`).\n\n    Fiel al comportamiento de la fuente, con tres casos distintos:\n    - Si NO hay ninguna cocina marcada como integrada: la funcion NO\n      APLICA -- lista vacia, sin avisos. Esto es distinto de \"no\n      verificable\": simplemente no es un caso relevante para este\n      programa.\n    - Si hay cocina integrada pero no hay salon (`RoomType.LIVING_ROOM`)\n      en el programa: AVISO (no se puede determinar la estancia mayor).\n    - Si hay ambos: se comprueba la superficie combinada (violacion si\n      no alcanza el minimo) y la apertura vertical (violacion si es\n      insuficiente; AVISO si no se declaro, nunca aprobacion silenciosa).\n\n    `total_num_estancias_override`: **[RESUELTO]** bug real encontrado en\n    auditoria de logica -- este validador NUNCA recibio el mismo arreglo\n    multi-planta que sus dos primos (`EstanciaMinimumAreaValidator`,\n    `ServicioMinimumAreaValidator`). Sin esto, en un edificio de 2\n    plantas con cocina integrada abajo y dormitorios arriba (el caso\n    normal), `num_estancias` solo contaba las estancias de ESTA planta,\n    aplicando una fila de Tabla 1/2 mas baja de la real -- podia APROBAR\n    SILENCIOSAMENTE una superficie combinada realmente insuficiente para\n    el edificio completo. `None` (por defecto, caso de una sola planta)\n    preserva el comportamiento anterior exacto.\"\"\"\n\n    def __init__(self, total_num_estancias_override: Optional[int] = None):\n        self._total_override = total_num_estancias_override\n\n    def validate(self, layout: Layout) -> ValidationResult:\n        # Refactor por complejidad (radon cc: 16, \"C\" -- el mas alto del\n        # proyecto junto a EstanciaMinimumAreaValidator, mismo tratamiento\n        # aplicado alli): este metodo hacia DOS cosas independientes a la\n        # vez (superficie combinada, apertura vertical). Separado en dos\n        # metodos con responsabilidad unica, sin cambiar el comportamiento.\n        cocina = next(\n            (r for r in layout.rooms if r.room_type == RoomType.KITCHEN and r.integrated_in_largest_room),\n            None,\n        )\n        if cocina is None:\n            return ValidationResult()\n\n        mayor = next((r for r in layout.rooms if r.room_type == RoomType.LIVING_ROOM), None)\n        if mayor is None:\n            return ValidationResult(\n                warnings=[\"Cocina integrada declarada pero no hay salón (LIVING_ROOM) en el \"\n                          \"programa -- no se puede determinar la estancia mayor\"]\n            )\n\n        local_count = sum(1 for r in layout.rooms if r.space_category == SpaceCategory.ESTANCIA)\n        num_estancias = self._total_override if self._total_override is not None else local_count\n\n        area_violations, area_warnings = self._check_combined_area(mayor, cocina, num_estancias)\n        opening_violations, opening_warnings = self._check_vertical_opening(mayor, cocina)\n\n        return ValidationResult(\n            violations=area_violations + opening_violations,\n            warnings=area_warnings + opening_warnings,\n        )\n\n    @staticmethod\n    def _check_combined_area(mayor: Room, cocina: Room, num_estancias: int) -> Tuple[List[str], List[str]]:\n        \"\"\"Superficie minima del CONJUNTO salon+cocina: suma de los\n        minimos de cada pieza por separado (Tabla 1 + Tabla 2).\"\"\"\n        violations: List[str] = []\n        warnings: List[str] = []\n\n        minimo_mayor = minimo_estancia(num_estancias, 1)\n        minimo_cocina = tabla_servicios_para(num_estancias).get(\"cocina\")\n\n        if minimo_mayor is not None and minimo_cocina is not None:\n            minimo_combinado = minimo_mayor + minimo_cocina\n            area_combinada = mayor.dimensions.area_m2 + cocina.dimensions.area_m2\n            if area_combinada < minimo_combinado:\n                violations.append(\n                    f\"'{mayor.id}' + '{cocina.id}': superficie combinada {area_combinada:.1f}m2 \"\n                    f\"por debajo del minimo {minimo_combinado:.1f}m2 \"\n                    f\"({minimo_mayor:.1f}m2 estancia mayor + {minimo_cocina:.1f}m2 cocina, \"\n                    f\"cada una segun su propia tabla)\"\n                )\n        else:\n            warnings.append(\n                f\"No se pudo determinar el minimo combinado de '{mayor.id}' + '{cocina.id}' \"\n                f\"-- revisar el numero de estancias\"\n            )\n        return violations, warnings\n\n    @staticmethod\n    def _check_vertical_opening(mayor: Room, cocina: Room) -> Tuple[List[str], List[str]]:\n        \"\"\"Apertura vertical minima de relacion entre cocina y salon.\"\"\"\n        violations: List[str] = []\n        warnings: List[str] = []\n\n        if cocina.vertical_opening_m2 is None:\n            warnings.append(\n                f\"'{cocina.id}': falta declarar 'vertical_opening_m2' -- no se puede verificar \"\n                f\"la apertura minima de {APERTURA_VERTICAL_MIN_M2:.1f}m2 con '{mayor.id}'\"\n            )\n        elif cocina.vertical_opening_m2 < APERTURA_VERTICAL_MIN_M2:\n            violations.append(\n                f\"'{cocina.id}': apertura vertical de relación con '{mayor.id}' de \"\n                f\"{cocina.vertical_opening_m2:.1f}m2, por debajo del mínimo \"\n                f\"{APERTURA_VERTICAL_MIN_M2:.1f}m2\"\n            )\n        return violations, warnings\n", "housing_generator/infrastructure/algorithms/constraints/day_night_zoning_validator.py": "from typing import List\nfrom housing_generator.application.ports.adjacency_graph_builder_port import AdjacencyGraphBuilderPort\nfrom housing_generator.infrastructure.algorithms.constraints.grouping_constraint_validator import (\n    GroupingConstraintValidator,\n)\nfrom housing_generator.domain.enums import ZoneType, SpaceCategory\n\n# Zonificacion dia/noche: las estancias de una misma zona deben quedar\n# agrupadas en la planta, pero -- a diferencia del nucleo humedo -- NO\n# hace falta que compartan pared entre si, solo que no queden dispersas.\n# Umbral segun `nhv.lua` (evaluarZonificacionDiaNoche): 2 para ambas\n# zonas. Sujeto a confirmacion/ajuste.\nZONA_DIA_MAX_DISTANCE = 2\nZONA_NOCHE_MAX_DISTANCE = 2\n\n# BUG ENCONTRADO EN AUDITORIA: CORRIDOR y ENTRANCE_HALL son\n# SpaceCategory.CIRCULACION pero tienen zone=DAY por defecto (ver\n# DEFAULT_ROOM_ZONE). Sin esta exclusion, un pasillo colocado junto a\n# los dormitorios (su funcion real en un diseno concreto) generaba una\n# VIOLACION FALSA de zonificacion dia, por estar \"lejos\" de living/\n# dining/kitchen -- aunque el pasillo este cumpliendo perfectamente su\n# funcion de circulacion hacia la zona noche. La circulacion, por\n# definicion, sirve a varias zonas a la vez; no debe quedar atrapada en\n# la agrupacion de una sola.\ndef _is_non_circulation_in_zone(zone: ZoneType):\n    return lambda room: room.zone == zone and room.space_category != SpaceCategory.CIRCULACION\n\n\ndef build_day_zone_grouping_validator(\n    graph_builder: AdjacencyGraphBuilderPort,\n    max_distance: int = ZONA_DIA_MAX_DISTANCE,\n) -> GroupingConstraintValidator:\n    return GroupingConstraintValidator(\n        graph_builder=graph_builder,\n        predicate=_is_non_circulation_in_zone(ZoneType.DAY),\n        max_distance=max_distance,\n        label=\"zona dia\",\n    )\n\n\ndef build_night_zone_grouping_validator(\n    graph_builder: AdjacencyGraphBuilderPort,\n    max_distance: int = ZONA_NOCHE_MAX_DISTANCE,\n) -> GroupingConstraintValidator:\n    return GroupingConstraintValidator(\n        graph_builder=graph_builder,\n        predicate=_is_non_circulation_in_zone(ZoneType.NIGHT),\n        max_distance=max_distance,\n        label=\"zona noche\",\n    )\n\n\ndef build_day_night_zoning_validators(\n    graph_builder: AdjacencyGraphBuilderPort,\n) -> List[GroupingConstraintValidator]:\n    \"\"\"Conveniencia: las dos validaciones juntas, en una lista -- lista para\n    cuando se resuelva como se combinan varios validadores en el caso de uso.\"\"\"\n    return [\n        build_day_zone_grouping_validator(graph_builder),\n        build_night_zone_grouping_validator(graph_builder),\n    ]\n\n\n# Zonificacion de servicio: NO existe en nhv.lua (evaluarZonificacionDiaNoche\n# solo cubre dia/noche) -- es una extension propia de este proyecto, no una\n# regla portada de la fuente normativa. Se marca como tal, igual que\n# `nhv.lua` distingue explicitamente sus propias heuristicas de diseno\n# (PASIVO.factorHueco, PESOS_ORIENTACION...) de las reglas normativas.\n# Umbral elegido igual al de dia/noche (2) por consistencia, ajustable.\nZONA_SERVICIO_MAX_DISTANCE = 2\n\n\ndef build_service_zone_grouping_validator(\n    graph_builder: AdjacencyGraphBuilderPort,\n    max_distance: int = ZONA_SERVICIO_MAX_DISTANCE,\n) -> GroupingConstraintValidator:\n    return GroupingConstraintValidator(\n        graph_builder=graph_builder,\n        predicate=_is_non_circulation_in_zone(ZoneType.SERVICE),\n        max_distance=max_distance,\n        label=\"zona servicio\",\n    )\n", "housing_generator/infrastructure/algorithms/constraints/__init__.py": "", "housing_generator/infrastructure/algorithms/constraints/altura_libre_validator.py": "from typing import List\nfrom housing_generator.application.ports.constraint_validator_port import ConstraintValidatorPort\nfrom housing_generator.application.dto.validation_result import ValidationResult\nfrom housing_generator.domain.entities.layout import Layout\nfrom housing_generator.domain.enums import RoomType\n\n# A.3.1.1: altura libre minima entre pavimento y techo terminados.\n# - alturaLibreMin (2.50m): la mayoria de piezas.\n# - alturaLibreReducida (2.20m): DIRECTAMENTE permitida, sin condicion,\n#   en vestibulo/pasillo/ESCALERAS/bano/aseo/lavadero/tendedero/GARAJES\n#   DE VIVIENDAS UNIFAMILIARES (A.3.1.1.b, texto exacto confirmado por\n#   investigacion normativa directa -- ver docs/architecture.md,\n#   hallazgo de la revision \"mas informacion relevante sin aplicar\").\n# - En el RESTO de piezas, 2.20m se admite como MAXIMO en una fraccion\n#   de la superficie util (30%) -- el resto debe llegar a 2.50m. Es una\n#   comprobacion de geometria PARCIAL (que parte de la planta queda bajo\n#   una viga/bajante) que este proyecto NO calcula, igual que la propia\n#   fuente admite no calcular: en vez de asumir cumplimiento o violacion,\n#   se emite un AVISO recordando la excepcion (A.3.1.1.c).\n# Solo cuarto tecnico queda fuera de alcance: no aparece en ninguna\n# lista de la fuente consultada.\n#\n# [RESUELTO -- bug real encontrado en auditoria] Antes, GARAGE estaba en\n# ROOM_TYPES_FUERA_DE_ALCANCE (sin comprobar en absoluto) y STAIRCASE no\n# estaba en ninguna de las dos listas (caia en el caso general de\n# 2.50m/excepcion del 30%, mas estricto de lo que le corresponde) --\n# ambos EXPLICITAMENTE nombrados en A.3.1.1.b, confirmado con el mismo\n# texto normativo citado arriba. El comentario anterior decia \"garaje...\n# no aparece en ninguna lista de la fuente\", repitiendo la misma\n# confusion ya corregida en DEFAULT_MIN_EXTERIOR_SIDES (B.2.6 no es \"la\n# regla propia del garaje unifamiliar\" -- es de garajes COLECTIVOS, no\n# aplica aqui; la reduccion de altura SI aparece, en la seccion A que si\n# aplica a unifamiliar).\nALTURA_LIBRE_MIN_M = 2.50\nALTURA_LIBRE_REDUCIDA_M = 2.20\n\nROOM_TYPES_REDUCCION_DIRECTA = {\n    RoomType.ENTRANCE_HALL,  # vestibulo\n    RoomType.CORRIDOR,       # pasillo\n    RoomType.STAIRCASE,      # escaleras\n    RoomType.BATHROOM,       # bano\n    RoomType.TOILET,         # aseo\n    RoomType.LAUNDRY,        # lavadero\n    RoomType.DRYING_AREA,    # tendedero\n    RoomType.GARAGE,         # garajes de viviendas unifamiliares\n}\nROOM_TYPES_FUERA_DE_ALCANCE = {RoomType.TECHNICAL_ROOM}\n\n\nclass AlturaLibreValidator(ConstraintValidatorPort):\n    \"\"\"Valida `Room.dimensions.ceiling_height_m` contra A.3.1.1.\n\n    - Sin altura declarada (`ceiling_height_m is None`): AVISO, nunca se\n      asume cumplimiento ni se penaliza como violacion.\n    - Piezas de reduccion directa: violacion solo si < 2.20m.\n    - Resto de piezas: violacion si < 2.20m; AVISO (no violacion) si\n      esta entre 2.20m y 2.50m, porque podria estar cubierta por la\n      excepcion del 30% que este validador no puede comprobar; sin\n      aviso si >= 2.50m.\n    \"\"\"\n\n    def validate(self, layout: Layout) -> ValidationResult:\n        violations: List[str] = []\n        warnings: List[str] = []\n\n        for room in layout.rooms:\n            if room.room_type in ROOM_TYPES_FUERA_DE_ALCANCE:\n                continue\n\n            altura = room.dimensions.ceiling_height_m\n            if altura is None:\n                warnings.append(\n                    f\"'{room.id}': altura de techo no declarada, no se puede verificar A.3.1.1\"\n                )\n                continue\n\n            if room.room_type in ROOM_TYPES_REDUCCION_DIRECTA:\n                if altura < ALTURA_LIBRE_REDUCIDA_M:\n                    violations.append(\n                        f\"'{room.id}': altura libre {altura:.2f}m por debajo del minimo \"\n                        f\"reducido de A.3.1.1.b ({ALTURA_LIBRE_REDUCIDA_M:.2f}m)\"\n                    )\n            else:\n                if altura < ALTURA_LIBRE_REDUCIDA_M:\n                    violations.append(\n                        f\"'{room.id}': altura libre {altura:.2f}m por debajo incluso del \"\n                        f\"minimo reducido de A.3.1.1 ({ALTURA_LIBRE_REDUCIDA_M:.2f}m)\"\n                    )\n                elif altura < ALTURA_LIBRE_MIN_M:\n                    warnings.append(\n                        f\"'{room.id}': altura libre {altura:.2f}m por debajo de \"\n                        f\"{ALTURA_LIBRE_MIN_M:.2f}m -- podria cumplir via la excepcion del \"\n                        f\"30% de superficie (A.3.1.1.c), no verificable sin geometria parcial\"\n                    )\n\n        return ValidationResult(violations=violations, warnings=warnings)\n", "housing_generator/infrastructure/algorithms/constraints/nucleo_humedo_vertical_validator.py": "from typing import List\nfrom shapely.geometry import Polygon\nfrom shapely.ops import unary_union\nfrom housing_generator.application.ports.constraint_validator_port import ConstraintValidatorPort\nfrom housing_generator.application.dto.validation_result import ValidationResult\nfrom housing_generator.domain.entities.layout import Layout\n\n# docs/niveles_plantas.md, \"Relacion vertical: continuidad de\n# instalaciones (bajantes)\" -- documentado desde hace tiempo, nunca\n# implementable por falta de generacion multi-planta. Regla: cualquier\n# estancia humeda (is_wet) de esta planta debe solapar en (x,y) con\n# ALGUNA humeda de la planta inmediatamente inferior -- \"cualquier tipo\n# humedo coincide, no especifico por tipo\" (ya confirmado en ese\n# documento). A diferencia de la escalera (que exige near-alineacion\n# exacta por continuidad estructural), aqui basta con solape real\n# (interseccion de area > 0): las bajantes necesitan poder discurrir\n# verticalmente por la zona humeda, no que las piezas coincidan pieza\n# a pieza.\n\n\nclass NucleoHumedoVerticalValidator(ConstraintValidatorPort):\n    \"\"\"Cada estancia humeda de esta planta debe solapar en planta con\n    alguna humeda de la planta inmediatamente inferior (continuidad de\n    bajantes). `reference_wet_boundaries=[]` (planta de abajo sin\n    humedas, o no hay planta de abajo) significa que este validador no\n    aplica -- no se puede comprobar continuidad contra una planta que no\n    tiene ninguna humeda con la que solapar.\"\"\"\n\n    def __init__(self, reference_wet_boundaries: List[Polygon]):\n        self._reference_union = unary_union(reference_wet_boundaries) if reference_wet_boundaries else None\n\n    def validate(self, layout: Layout) -> ValidationResult:\n        if self._reference_union is None:\n            return ValidationResult()\n\n        wet_rooms = [r for r in layout.rooms if r.is_wet and r.is_placed]\n        violations: List[str] = []\n        for room in wet_rooms:\n            overlap = room.boundary.polygon.intersection(self._reference_union).area\n            if overlap <= 0:\n                violations.append(\n                    f\"'{room.id}': sin solape en planta con ninguna estancia humeda de la \"\n                    f\"planta inferior -- continuidad de bajantes rota\"\n                )\n        return ValidationResult(violations=violations)\n", "housing_generator/infrastructure/algorithms/constraints/estancia_minimum_area_validator.py": "from typing import List, Dict, Optional, Tuple\nfrom housing_generator.application.ports.constraint_validator_port import ConstraintValidatorPort\nfrom housing_generator.application.dto.validation_result import ValidationResult\nfrom housing_generator.domain.entities.layout import Layout\nfrom housing_generator.domain.entities.room import Room\nfrom housing_generator.domain.enums import SpaceCategory, RoomType\nfrom housing_generator.infrastructure.geometry.shapely_utils import can_inscribe_square\n\n# Tabla 1 (A.3.2.1 en nhv.lua / Decreto 29/2010): superficie util minima\n# POR ESTANCIA segun el puesto que ocupa por tamano (E1 = la mayor, E2 =\n# la segunda...), NO una superficie total. Portado literalmente de la\n# fuente normativa -- estos numeros no son heuristica de este proyecto.\nTABLA_1: Dict[int, List[float]] = {\n    1: [25],\n    2: [16, 12],\n    3: [18, 12, 8],\n    4: [20, 12, 8, 8],\n    5: [22, 12, 8, 8, 6],\n}\nTABLA_1_MAS_DE_CINCO: List[float] = [25, 12, 8, 8, 8]  # E1..E5 fijos si hay >5 estancias\nMINIMO_ESTANCIA_ADICIONAL = 6.0  # E6, E7... cuando hay mas de 5\n\n# A.3.2.1.a: lado del cuadrado inscribible exigido a la estancia mayor\nCUADRADO_INSCRIBIBLE_ESTANCIA_MAYOR_LADO_M = 3.30\n\n\ndef minimo_estancia(num_estancias: int, indice: int) -> Optional[float]:\n    \"\"\"Minimo de superficie util para la estancia que ocupa el puesto\n    `indice` (1 = la mayor) en una vivienda con `num_estancias` estancias.\"\"\"\n    if num_estancias <= 5:\n        fila = TABLA_1.get(num_estancias)\n        if fila is None or indice > len(fila):\n            return None\n        return fila[indice - 1]\n    if indice <= 5:\n        return TABLA_1_MAS_DE_CINCO[indice - 1]\n    return MINIMO_ESTANCIA_ADICIONAL\n\n\nclass EstanciaMinimumAreaValidator(ConstraintValidatorPort):\n    \"\"\"Tabla 1: superficie minima por puesto de tamano entre las estancias\n    (space_category == ESTANCIA). Ni cocina, ni bano/aseo/lavadero, ni\n    circulacion cuentan aqui -- solo estar/comedor/dormitorios/despacho.\n\n    La \"estancia mayor\" para el cuadrado inscribible (A.3.2.1.a) es\n    SIEMPRE el salon (RoomType.LIVING_ROOM) -- confirmado como regla de\n    proyecto, no una derivacion automatica por area. El ranking de\n    Tabla 1 (puesto 1..N) sigue siendo por tamano real, sin relacion con\n    cual sea la estancia mayor; son dos conceptos independientes.\n    - Si no hay salon declarado entre las estancias: se usa la de mayor\n      area como alternativa, pero se marca como AVISO (no se asume en\n      silencio que la sustitucion es equivalente).\n    - Si la estancia mayor esta colocada (`boundary` real) y es\n      rectangular, se verifica el cuadrado inscribible de forma exacta.\n    - Si esta colocada pero NO es rectangular: AVISO, nunca violacion.\n    - Si no esta colocada todavia: no se comprueba aqui.\n\n    `total_num_estancias_override`: para vivienda MULTI-PLANTA (ver\n    GenerateBuildingUseCase) -- este validador se aplica UNA planta a la\n    vez, pero Tabla 1 depende del numero de estancias del EDIFICIO\n    COMPLETO, no solo de las de esta planta (bug real encontrado al\n    construir el primer edificio de 2 plantas de prueba: una planta con\n    1 sola estancia aplicaba la fila de \"vivienda de 1 estancia\" (25m2)\n    en vez de la fila real del edificio). Si se declara, sustituye\n    `len(ordenadas)` para elegir la FILA de Tabla 1 correcta.\n\n    `global_rank_override`: **[RESUELTO]** dict room_id -> puesto GLOBAL\n    (1=mayor del EDIFICIO completo, no solo de esta planta). Corrige la\n    limitacion senalada en el incremento anterior (el ranking quedaba\n    atado solo a las estancias de la planta local, podia exigir un\n    minimo mas estricto del que corresponderia). `GenerateBuildingUseCase`\n    lo precalcula una vez, antes de generar ninguna planta, porque las\n    areas son DECLARADAS (no dependen de la geometria ya colocada).\n    \"\"\"\n\n    def __init__(\n        self,\n        total_num_estancias_override: Optional[int] = None,\n        global_rank_override: Optional[Dict[str, int]] = None,\n    ):\n        self._total_override = total_num_estancias_override\n        self._global_rank = global_rank_override\n\n    def validate(self, layout: Layout) -> ValidationResult:\n        # Refactor por complejidad (radon cc: 16, \"C\" -- el mas alto del\n        # proyecto junto a CocinaIntegradaValidator): este metodo hacia\n        # DOS cosas independientes a la vez (ranking de Tabla 1 por\n        # puesto, y cuadrado inscribible de la estancia mayor). Separado\n        # en dos metodos con responsabilidad unica, sin cambiar el\n        # comportamiento -- mismas violaciones/avisos, mismo orden.\n        estancias = [r for r in layout.rooms if r.space_category == SpaceCategory.ESTANCIA]\n        if not estancias:\n            return ValidationResult()\n\n        ordenadas = sorted(estancias, key=lambda r: r.dimensions.area_m2, reverse=True)\n        num_estancias = self._total_override if self._total_override is not None else len(ordenadas)\n\n        violations = self._check_rank_minimums(ordenadas, num_estancias)\n        cuadrado_violations, warnings = self._check_estancia_mayor_cuadrado(estancias, ordenadas)\n        violations.extend(cuadrado_violations)\n\n        return ValidationResult(violations=violations, warnings=warnings)\n\n    def _check_rank_minimums(self, ordenadas: List[Room], num_estancias: int) -> List[str]:\n        \"\"\"Tabla 1 propiamente dicha: superficie minima por puesto de\n        tamano (E1=mayor, E2=segunda...).\"\"\"\n        violations: List[str] = []\n        for local_i, room in enumerate(ordenadas, start=1):\n            puesto = self._global_rank.get(room.id, local_i) if self._global_rank else local_i\n            minimo = minimo_estancia(num_estancias, puesto)\n            if minimo is not None and room.dimensions.area_m2 < minimo:\n                violations.append(\n                    f\"'{room.id}': {room.dimensions.area_m2:.1f}m2, por debajo del minimo de \"\n                    f\"Tabla 1 para el puesto {puesto} de {num_estancias} estancias ({minimo:.1f}m2)\"\n                )\n        return violations\n\n    def _check_estancia_mayor_cuadrado(\n        self, estancias: List[Room], ordenadas: List[Room],\n    ) -> Tuple[List[str], List[str]]:\n        \"\"\"A.3.2.1.a: cuadrado inscribible de 3.30m de lado en la\n        estancia mayor (siempre el salon, RoomType.LIVING_ROOM).\"\"\"\n        violations: List[str] = []\n        warnings: List[str] = []\n\n        mayor = next((r for r in estancias if r.room_type == RoomType.LIVING_ROOM), None)\n        if mayor is None:\n            if self._total_override is not None:\n                # BUG REAL encontrado en auditoria de logica: en\n                # multi-planta, \"no hay living_room EN ESTA PLANTA\" es\n                # el caso NORMAL para plantas superiores (dormitorios),\n                # no una anomalia -- el salon esta legitimamente en OTRA\n                # planta. Sustituir por la mayor estancia LOCAL y\n                # comprobarle el cuadrado inscribible de 3.30m (regla\n                # que solo aplica al salon) generaba avisos enganosos y,\n                # peor, podia generar una VIOLACION FALSA si esa\n                # estancia local no cumplia un requisito que nunca le\n                # correspondio. La planta que SI tiene el salon real ya\n                # lo comprueba correctamente por su cuenta (mas abajo,\n                # sin pasar por esta rama) -- no hace falta sustituto.\n                return violations, warnings\n            mayor = ordenadas[0]\n            warnings.append(\n                f\"No hay 'living_room' declarado entre las estancias; se usa '{mayor.id}' \"\n                f\"(la de mayor area) como sustituto de la estancia mayor para el cuadrado \"\n                f\"inscribible -- confirmar si esto es correcto para este programa\"\n            )\n\n        if mayor.is_placed:\n            cabe = can_inscribe_square(mayor.boundary.polygon, CUADRADO_INSCRIBIBLE_ESTANCIA_MAYOR_LADO_M)\n            if cabe is False:\n                violations.append(\n                    f\"'{mayor.id}' (estancia mayor): no cabe el cuadrado inscribible de \"\n                    f\"{CUADRADO_INSCRIBIBLE_ESTANCIA_MAYOR_LADO_M:.2f}m de lado\"\n                )\n            elif cabe is None:\n                warnings.append(\n                    f\"'{mayor.id}' (estancia mayor): forma no rectangular, no se puede \"\n                    f\"verificar el cuadrado inscribible de {CUADRADO_INSCRIBIBLE_ESTANCIA_MAYOR_LADO_M:.2f}m \"\n                    f\"con la geometria computacional implementada actualmente\"\n                )\n\n        return violations, warnings\n", "housing_generator/infrastructure/algorithms/constraints/composite_constraint_validator.py": "from typing import List\nfrom housing_generator.application.ports.constraint_validator_port import ConstraintValidatorPort\nfrom housing_generator.application.dto.validation_result import ValidationResult\nfrom housing_generator.domain.entities.layout import Layout\n\n\nclass CompositeConstraintValidator(ConstraintValidatorPort):\n    \"\"\"Ejecuta varios ConstraintValidatorPort sobre el mismo Layout y\n    fusiona sus resultados (violaciones + avisos de todos, unidos).\n\n    Permite que GenerateLayoutUseCase siga aceptando UN solo\n    ConstraintValidatorPort mientras el sistema acumula validadores\n    independientes (nucleo humedo, zonificacion, Tabla 1, Tabla 2...)\n    sin que ninguno tenga que saber de los demas.\n    \"\"\"\n\n    def __init__(self, validators: List[ConstraintValidatorPort]):\n        self._validators = validators\n\n    def validate(self, layout: Layout) -> ValidationResult:\n        return ValidationResult.merge([v.validate(layout) for v in self._validators])\n", "housing_generator/infrastructure/algorithms/constraints/vivienda_minima_validator.py": "from typing import List\nfrom housing_generator.application.ports.constraint_validator_port import ConstraintValidatorPort\nfrom housing_generator.application.dto.validation_result import ValidationResult\nfrom housing_generator.domain.entities.layout import Layout\nfrom housing_generator.domain.enums import RoomType\n\n# \"Programa mínimo\": texto EXACTO del Decreto 29/2010 de Galicia,\n# apartado I.A.2.3 (confirmado por investigacion independiente, cita\n# textual): \"La vivienda constará, como mínimo, de una estancia más una\n# cocina, un cuarto de baño, un lavadero, un tendedero y un espacio de\n# almacenamiento general.\" nhv.lua no modela este apartado en absoluto.\n#\n# CORRECCION: una primera version de este validador solo exigia\n# salon+cocina+bano, basada en el estandar generico CTE/Orden de 1944\n# (valido para otras comunidades) en vez de buscar el texto especifico\n# de Galicia primero -- el usuario detecto que algo no cuadraba, y al\n# revisar la fuente exacta se confirmo que faltaban tres piezas enteras\n# (lavadero, tendedero, almacenamiento general).\n#\n# Mapeo de \"estancia\" -> RoomType.LIVING_ROOM: el propio decreto exige\n# en otro apartado (A.3.2.1.a) que exista \"al menos una estancia mayor\"\n# en toda vivienda; este proyecto ya adopto como convencion que la\n# estancia mayor es siempre el salon (confirmado explicitamente por el\n# usuario en una sesion anterior), asi que \"una estancia\" en el programa\n# minimo se interpreta como ese mismo salon, no como categoria generica.\n\n\nclass ViviendaMinimaValidator(ConstraintValidatorPort):\n    \"\"\"Comprueba que el Program contenga las seis piezas del programa\n    mínimo legal (Decreto 29/2010, I.A.2.3): salón, cocina, baño\n    completo, lavadero, tendedero y almacenamiento general. Sin este\n    validador, un `Program` con, por ejemplo, solo un garaje, pasaría el\n    resto de los validadores del composite sin ningún aviso.\"\"\"\n\n    _REQUIRED = [\n        (RoomType.LIVING_ROOM, \"un salón (LIVING_ROOM) -- una estancia de estar-comedor\"),\n        (RoomType.KITCHEN, \"una cocina (KITCHEN)\"),\n        (RoomType.BATHROOM, \"un baño completo (BATHROOM) -- un aseo (TOILET) no sustituye este requisito\"),\n        (RoomType.LAUNDRY, \"un lavadero (LAUNDRY)\"),\n        (RoomType.DRYING_AREA, \"un tendedero (DRYING_AREA)\"),\n        (RoomType.STORAGE, \"un espacio de almacenamiento general (STORAGE)\"),\n    ]\n\n    def validate(self, layout: Layout) -> ValidationResult:\n        types_present = {r.room_type for r in layout.rooms}\n        violations: List[str] = [\n            f\"Programa mínimo incompleto: falta {descripcion}\"\n            for room_type, descripcion in self._REQUIRED\n            if room_type not in types_present\n        ]\n        return ValidationResult(violations=violations)\n", "housing_generator/infrastructure/algorithms/constraints/ancho_libre_estancia_validator.py": "from typing import List\nfrom housing_generator.application.ports.constraint_validator_port import ConstraintValidatorPort\nfrom housing_generator.application.dto.validation_result import ValidationResult\nfrom housing_generator.domain.entities.layout import Layout\nfrom housing_generator.domain.enums import RoomType\nfrom housing_generator.infrastructure.geometry.shapely_utils import meets_minimum_width\n\n# A.3.2.1: ancho libre minimo entre paramentos enfrentados. Declarado en\n# nhv.lua (NHV.anchoLibreMin) pero nunca conectado a ningun validador en\n# la fuente; los valores en si son reales (Anexo I, Decreto de Galicia),\n# confirmados de forma independiente. Solo cubre estas 5 categorias --\n# comedor, despacho, aseo, lavadero, tendedero, trastero, almacenamiento\n# no tienen ancho libre asignado en ningun sitio de la fuente.\nANCHO_LIBRE_ESTANCIA_MAYOR_M = 2.70\nANCHO_LIBRE_DORMITORIO_DOBLE_M = 2.60   # habitacion >= 12m2\nANCHO_LIBRE_DORMITORIO_INDIVIDUAL_M = 2.00  # habitacion < 12m2\nANCHO_LIBRE_COCINA_M = 1.80\nANCHO_LIBRE_BANO_M = 1.60\nDORMITORIO_DOBLE_AREA_UMBRAL_M2 = 12.0\n\n_DORMITORIO_TYPES = {RoomType.BEDROOM, RoomType.MASTER_BEDROOM}\n\n\nclass AnchoLibreEstanciaValidator(ConstraintValidatorPort):\n    \"\"\"A.3.2.1: comprueba el ancho libre minimo (lado mas corto del\n    rectangulo) para estancia mayor, dormitorios, cocina y bano.\n\n    La \"estancia mayor\" aqui es estrictamente `RoomType.LIVING_ROOM` --\n    a diferencia de `EstanciaMinimumAreaValidator`, este validador NO\n    hace fallback a la estancia de mayor area si no hay salon declarado\n    (para no duplicar ese aviso, que ya emite aquel validador sobre el\n    mismo tema): si no hay salon, esta comprobacion concreta simplemente\n    no se ejecuta.\n    \"\"\"\n\n    def validate(self, layout: Layout) -> ValidationResult:\n        violations: List[str] = []\n        warnings: List[str] = []\n\n        placed_rooms = [r for r in layout.rooms if r.is_placed]\n\n        mayor = next((r for r in placed_rooms if r.room_type == RoomType.LIVING_ROOM), None)\n        if mayor is not None:\n            self._check(mayor, ANCHO_LIBRE_ESTANCIA_MAYOR_M, \"estancia mayor (A.3.2.1.a)\", violations, warnings)\n\n        for room in placed_rooms:\n            if room.room_type in _DORMITORIO_TYPES:\n                if room.dimensions.area_m2 >= DORMITORIO_DOBLE_AREA_UMBRAL_M2:\n                    minimo, etiqueta = ANCHO_LIBRE_DORMITORIO_DOBLE_M, \"dormitorio doble (A.3.2.1.e/f)\"\n                else:\n                    minimo, etiqueta = ANCHO_LIBRE_DORMITORIO_INDIVIDUAL_M, \"dormitorio individual (A.3.2.1.g/h)\"\n                self._check(room, minimo, etiqueta, violations, warnings)\n            elif room.room_type == RoomType.KITCHEN:\n                self._check(room, ANCHO_LIBRE_COCINA_M, \"cocina (A.3.2.1)\", violations, warnings)\n            elif room.room_type == RoomType.BATHROOM:\n                self._check(room, ANCHO_LIBRE_BANO_M, \"bano (A.3.2.1)\", violations, warnings)\n\n        return ValidationResult(violations=violations, warnings=warnings)\n\n    @staticmethod\n    def _check(room, minimo: float, etiqueta: str, violations: List[str], warnings: List[str]) -> None:\n        cumple = meets_minimum_width(room.boundary.polygon, minimo)\n        if cumple is False:\n            violations.append(\n                f\"'{room.id}' ({etiqueta}): ancho libre por debajo del minimo de {minimo:.2f}m\"\n            )\n        elif cumple is None:\n            warnings.append(\n                f\"'{room.id}' ({etiqueta}): forma no rectangular, no se puede verificar \"\n                f\"el ancho libre de {minimo:.2f}m\"\n            )\n", "housing_generator/infrastructure/algorithms/constraints/bano_acceso_validator.py": "from typing import List\nfrom housing_generator.application.ports.constraint_validator_port import ConstraintValidatorPort\nfrom housing_generator.application.ports.adjacency_graph_builder_port import AdjacencyGraphBuilderPort\nfrom housing_generator.application.dto.validation_result import ValidationResult\nfrom housing_generator.domain.entities.layout import Layout\nfrom housing_generator.domain.enums import RoomType, SpaceCategory\n\n# Regla \"Condicional\" del catalogo de relaciones espaciales\n# (BEDROOM/MASTER_BEDROOM x BATHROOM, ver relaciones_espaciales.md):\n# \"1 bano -> acceso solo via pasillo; >=2 banos -> uno puede ser en-suite\".\n#\n# NO es un valor estatico de tabla (TipoA, TipoB) -- depende de cuantos\n# RoomType.BATHROOM tenga el Program real. Formulacion equivalente y mas\n# simple que no necesita ramificar por conteo: al menos UN bano debe\n# tener acceso directo (pared compartida) a circulacion general\n# (CORRIDOR o ENTRANCE_HALL). Con 1 solo bano, esa exigencia recae\n# necesariamente sobre el (equivale a \"acceso solo via pasillo\"); con 2+,\n# basta con que UNO la cumpla, los demas pueden ser en-suite de un\n# dormitorio sin acceso propio a circulacion.\n\n\nclass BanoAccesoGeneralValidator(ConstraintValidatorPort):\n    \"\"\"Al menos un RoomType.BATHROOM debe tener adyacencia real (pared\n    compartida) con una estancia de circulacion (CORRIDOR o\n    ENTRANCE_HALL) -- ningun bano puede quedar \"capturado\" exclusivamente\n    dentro de un dormitorio si es el unico (o el unico con acceso general)\n    de la vivienda.\n\n    Si no hay ningun BATHROOM colocado, no aplica (lista vacia, sin\n    avisos) -- ViviendaMinimaValidator ya exige que exista al menos uno;\n    este validador no duplica esa exigencia, solo comprueba el acceso.\n    \"\"\"\n\n    def __init__(self, graph_builder: AdjacencyGraphBuilderPort):\n        self._graph_builder = graph_builder\n\n    def validate(self, layout: Layout) -> ValidationResult:\n        bathrooms = [r for r in layout.rooms if r.is_placed and r.room_type == RoomType.BATHROOM]\n        if not bathrooms:\n            return ValidationResult()\n\n        graph = self._graph_builder.build(layout)\n        circulation_ids = {\n            r.id for r in layout.rooms\n            if r.is_placed and r.space_category == SpaceCategory.CIRCULACION\n        }\n\n        for bath in bathrooms:\n            if bath.id not in graph:\n                continue\n            neighbors = set(graph.neighbors(bath.id))\n            if neighbors & circulation_ids:\n                return ValidationResult()  # al menos uno tiene acceso general -- regla satisfecha\n\n        violations: List[str] = [\n            f\"Ningún baño tiene acceso directo desde circulación general (CORRIDOR/ENTRANCE_HALL) \"\n            f\"-- con {len(bathrooms)} baño(s) en el programa, al menos uno no puede quedar \"\n            f\"capturado exclusivamente dentro de un dormitorio\"\n        ]\n        return ValidationResult(violations=violations)\n", "housing_generator/infrastructure/algorithms/constraints/exterior_contact_validator.py": "from typing import List\nfrom housing_generator.application.ports.constraint_validator_port import ConstraintValidatorPort\nfrom housing_generator.application.dto.validation_result import ValidationResult\nfrom housing_generator.domain.entities.layout import Layout\nfrom housing_generator.infrastructure.geometry.shapely_utils import count_exterior_sides\n\n# Umbral de contacto con el exterior (0.3m) -- distinto y mayor que el\n# umbral de adyacencia interior entre estancias (0.1m), confirmado por\n# el usuario en la sesion de nucleo humedo/grafo de adyacencia.\nEXTERIOR_MIN_CONTACT_M = 0.3\n\n\nclass ExteriorContactValidator(ConstraintValidatorPort):\n    \"\"\"Comprueba que cada estancia tenga al menos\n    `room.min_exterior_sides` lados con contacto real al limite del\n    solar (ver DEFAULT_MIN_EXTERIOR_SIDES en enums.py para el porque de\n    cada valor por tipo).\n\n    Misma logica de tres estados que el resto de validadores\n    geometricos: violacion si no llega al minimo, aviso si la forma no\n    es rectangular (no verificable), nada si la estancia no esta\n    colocada todavia.\n    \"\"\"\n\n    def validate(self, layout: Layout) -> ValidationResult:\n        violations: List[str] = []\n        warnings: List[str] = []\n\n        # borde del AREA EDIFICABLE, no de la parcela legal completa --\n        # con retranqueo declarado (vivienda aislada), la construccion\n        # nunca llega a tocar la linea de parcela real, asi que\n        # comprobar contra ella nunca daria contacto exterior valido.\n        # El borde del area edificable es donde de verdad termina la\n        # construccion y empieza el jardin/exterior. Sin retranqueo,\n        # ambas coinciden (mismo comportamiento que antes).\n        lot_polygon = layout.lot.buildable_area.polygon\n\n        # vivienda pareada/adosada (retomado de docs/CONTINUIDAD.md):\n        # los lados de medianera SI forman parte del area edificable\n        # (la construccion llega hasta el linde ahi), pero una pared de\n        # medianera no tiene luz ni ventilacion propia -- no cuenta como\n        # contacto exterior real aunque geometricamente toque el borde.\n        excluded_segments = layout.lot.medianera_boundary_segments()\n\n        for room in layout.rooms:\n            if not room.is_placed or room.min_exterior_sides <= 0:\n                continue\n\n            lados = count_exterior_sides(\n                room.boundary.polygon, lot_polygon, EXTERIOR_MIN_CONTACT_M,\n                excluded_segments=excluded_segments,\n            )\n\n            if lados is None:\n                warnings.append(\n                    f\"'{room.id}': forma no rectangular, no se puede verificar el \"\n                    f\"contacto exterior\"\n                )\n            elif lados < room.min_exterior_sides:\n                violations.append(\n                    f\"'{room.id}': {lados} lado(s) con contacto exterior, \"\n                    f\"por debajo del minimo exigido ({room.min_exterior_sides})\"\n                )\n\n        return ValidationResult(violations=violations, warnings=warnings)\n", "housing_generator/infrastructure/algorithms/constraints/wet_core_validator.py": "from housing_generator.application.ports.adjacency_graph_builder_port import AdjacencyGraphBuilderPort\nfrom housing_generator.infrastructure.algorithms.constraints.grouping_constraint_validator import (\n    GroupingConstraintValidator,\n)\n\n# Nucleo humedo: todas las piezas humedas (cocina, bano, lavadero...)\n# deben compartir pared entre si (distancia 1 = pared compartida,\n# confirmado por `nhv.lua`: bajantes cortos, ahorro real en fontaneria).\nNUCLEO_HUMEDO_MAX_DISTANCE = 1\n\n\ndef build_wet_core_validator(graph_builder: AdjacencyGraphBuilderPort) -> GroupingConstraintValidator:\n    \"\"\"Fabrica el validador de nucleo humedo: primer caso concreto del\n    mecanismo generico GroupingConstraintValidator.\"\"\"\n    return GroupingConstraintValidator(\n        graph_builder=graph_builder,\n        predicate=lambda room: room.is_wet,\n        max_distance=NUCLEO_HUMEDO_MAX_DISTANCE,\n        label=\"nucleo humedo\",\n    )\n", "housing_generator/infrastructure/algorithms/constraints/ancho_libre_practico_validator.py": "from typing import List, Set\nfrom housing_generator.application.ports.constraint_validator_port import ConstraintValidatorPort\nfrom housing_generator.application.dto.validation_result import ValidationResult\nfrom housing_generator.domain.entities.layout import Layout\nfrom housing_generator.domain.enums import RoomType\nfrom housing_generator.infrastructure.geometry.shapely_utils import evaluate_minimum_width\n\n# NO NORMATIVO -- criterio de ingenieria practica, confirmado\n# explicitamente con el usuario, no un valor del Decreto 29/2010.\n#\n# Hallazgo real: AnchoLibreEstanciaValidator (A.3.2.1) solo cubre 5\n# categorias porque el propio decreto no especifica ancho libre minimo\n# para el resto de tipos -- confirmado e investigado en su momento, no\n# un descuido. Pero eso significaba que el generador podia producir\n# formas NORMATIVAMENTE CONFORMES y PRACTICAMENTE INSERVIBLES: un caso\n# real (captura de pantalla del usuario) mostro un \"Almacen\" de 3m2\n# generado como 2.49m x 0.49m -- 49 CENTIMETROS de fondo, cumple el\n# area exigida pero es inutilizable en la practica (no cabe ni una\n# balda). El decreto no exige un minimo ahi porque asume, con razon,\n# que ningun arquitecto real dibujaria eso -- pero un generador\n# automatico sin este limite si puede, y sin darse cuenta.\n#\n# Cubre los tipos que NO tienen ningun otro ancho libre comprobado en\n# ningun validador del proyecto (ver docs/architecture.md para el\n# listado exacto verificado): comedor, despacho, aseo, lavadero,\n# tendedero, almacenamiento, recibidor, garaje, cuarto tecnico.\n# Trastero (STORAGE_ROOM) ya tiene su propio minimo normativo (B.2.5,\n# TrasteroMinimumAreaValidator, 1.60m) -- no se duplica aqui.\nANCHO_LIBRE_PRACTICO_M = 1.20\n\nTIPOS_SIN_ANCHO_NORMATIVO: Set[RoomType] = {\n    RoomType.DINING_ROOM,\n    RoomType.STUDY,\n    RoomType.TOILET,\n    RoomType.LAUNDRY,\n    RoomType.DRYING_AREA,\n    RoomType.STORAGE,\n    RoomType.ENTRANCE_HALL,\n    RoomType.GARAGE,\n    RoomType.TECHNICAL_ROOM,\n}\n\n\nclass AnchoLibrePracticoValidator(ConstraintValidatorPort):\n    \"\"\"Ancho libre mínimo NO NORMATIVO (1.20m, criterio de ingeniería\n    confirmado explícitamente, no del Decreto 29/2010) para los tipos\n    de estancia que el decreto deja sin ancho libre especificado --\n    evita formas técnicamente conformes en área pero inservibles en la\n    práctica (p.ej. un almacén de 49cm de fondo).\"\"\"\n\n    def validate(self, layout: Layout) -> ValidationResult:\n        violations: List[str] = []\n        warnings: List[str] = []\n\n        for room in layout.rooms:\n            if room.room_type not in TIPOS_SIN_ANCHO_NORMATIVO or not room.is_placed:\n                continue\n            v, w = evaluate_minimum_width(\n                room.id, room.boundary.polygon, ANCHO_LIBRE_PRACTICO_M,\n                violation_message=(\n                    f\"ancho libre por debajo del minimo practico de ingenieria \"\n                    f\"({ANCHO_LIBRE_PRACTICO_M:.2f}m, NO normativo -- el Decreto 29/2010 \"\n                    f\"no especifica ancho libre para este tipo, pero una estancia mas \"\n                    f\"estrecha que esto no es utilizable en la practica)\"\n                ),\n                warning_message=\"forma no rectangular, no se puede verificar el ancho libre práctico\",\n            )\n            violations.extend(v)\n            warnings.extend(w)\n\n        return ValidationResult(violations=violations, warnings=warnings)\n", "housing_generator/infrastructure/algorithms/constraints/espacio_acceso_validator.py": "from typing import List\nfrom housing_generator.application.ports.constraint_validator_port import ConstraintValidatorPort\nfrom housing_generator.application.dto.validation_result import ValidationResult\nfrom housing_generator.domain.entities.layout import Layout\nfrom housing_generator.domain.enums import RoomType\nfrom housing_generator.infrastructure.geometry.shapely_utils import can_inscribe_square\n\n# A.2 (numeracion exacta incierta tras la renumeracion del Decreto\n# 128/2023 -- el fragmento aparecio junto a A.4 en las fuentes\n# consultadas, probablemente perteneciente a A.3.3 \"Espacios de\n# comunicacion\" en la version vigente): \"El espacio de acceso interior\n# de la vivienda debera admitir la inscripcion de un cuadrado de 1,50 m\n# de lado, libre de obstaculos, en contacto con la puerta de entrada y\n# cuya superficie util podra estar incluida en la superficie util\n# minima de la estancia mayor en caso de que el acceso a la vivienda se\n# realice directamente a traves de ella.\"\nESPACIO_ACCESO_CUADRADO_M = 1.50\n\n# \"En contacto con la puerta de entrada\" NO se comprueba aqui -- este\n# proyecto no modela puertas/accesos en absoluto (mismo hueco de modelo\n# ya identificado en relaciones_espaciales.md: \"acceso/puertas\"). Se\n# documenta como alcance pendiente, no como aviso repetido en cada\n# validacion (a diferencia de datos que faltan caso a caso, esto falta\n# siempre, de forma sistematica, hasta que se aborde el modelo de\n# puertas como pieza propia).\n\n\nclass EspacioAccesoValidator(ConstraintValidatorPort):\n    \"\"\"Cuadrado inscribible de 1.50m en el recibidor (RoomType.ENTRANCE_HALL).\n\n    Si no hay ENTRANCE_HALL en el programa, el requisito NO APLICA (lista\n    vacia, sin avisos) -- la propia norma exime este caso cuando el\n    acceso a la vivienda se realiza directamente a traves de la estancia\n    mayor, sin recibidor propio; ese caso ya queda cubierto por el\n    minimo de la estancia mayor (Tabla 1), no por este validador.\n    \"\"\"\n\n    def validate(self, layout: Layout) -> ValidationResult:\n        violations: List[str] = []\n        warnings: List[str] = []\n\n        for room in layout.rooms:\n            if room.room_type != RoomType.ENTRANCE_HALL:\n                continue\n            if not room.is_placed:\n                continue\n\n            cumple = can_inscribe_square(room.boundary.polygon, ESPACIO_ACCESO_CUADRADO_M)\n            if cumple is False:\n                violations.append(\n                    f\"'{room.id}': no admite el cuadrado de {ESPACIO_ACCESO_CUADRADO_M:.2f}m \"\n                    f\"de lado exigido en el espacio de acceso interior\"\n                )\n            elif cumple is None:\n                warnings.append(\n                    f\"'{room.id}': forma no rectangular, no se puede verificar el cuadrado \"\n                    f\"de acceso interior de {ESPACIO_ACCESO_CUADRADO_M:.2f}m\"\n                )\n\n        return ValidationResult(violations=violations, warnings=warnings)\n", "housing_generator/infrastructure/algorithms/constraints/escalera_ancho_libre_validator.py": "from typing import List\nfrom housing_generator.application.ports.constraint_validator_port import ConstraintValidatorPort\nfrom housing_generator.application.dto.validation_result import ValidationResult\nfrom housing_generator.domain.entities.layout import Layout\nfrom housing_generator.domain.enums import RoomType\nfrom housing_generator.infrastructure.geometry.shapely_utils import evaluate_minimum_width\n\n# CTE DB-SUA 1, escalera de USO RESTRINGIDO (interior de vivienda\n# unifamiliar -- confirmado por investigacion independiente en\n# docs/niveles_plantas.md: \"la escalera interior de un alojamiento...\n# se considera de uso restringido cualquiera que sea el numero de\n# usuarios\"). Ancho minimo 0.80m -- NO el de uso general (1.00-1.20m,\n# zonas comunes de edificio), que no aplica a este caso.\nESCALERA_ANCHO_LIBRE_MIN_M = 0.80\n\n\nclass EscaleraAnchoLibreValidator(ConstraintValidatorPort):\n    \"\"\"Ancho libre minimo de RoomType.STAIRCASE (0.80m, uso restringido\n    CTE DB-SUA 1). No comprueba huella/contrahuella de peldanos\n    (geometria de escalon, fuera de alcance -- ver niveles_plantas.md)\n    ni alineacion entre plantas (ver EscaleraAlineacionValidator, aparte).\"\"\"\n\n    def validate(self, layout: Layout) -> ValidationResult:\n        violations: List[str] = []\n        warnings: List[str] = []\n        for room in layout.rooms:\n            if room.room_type != RoomType.STAIRCASE or not room.is_placed:\n                continue\n            v, w = evaluate_minimum_width(\n                room.id, room.boundary.polygon, ESCALERA_ANCHO_LIBRE_MIN_M,\n                violation_message=(\n                    f\"ancho libre por debajo del minimo de escalera de uso \"\n                    f\"restringido ({ESCALERA_ANCHO_LIBRE_MIN_M:.2f}m, CTE DB-SUA 1)\"\n                ),\n                warning_message=\"forma no rectangular, no se puede verificar el ancho libre de escalera\",\n            )\n            violations.extend(v)\n            warnings.extend(w)\n        return ValidationResult(violations=violations, warnings=warnings)\n", "housing_generator/infrastructure/algorithms/constraints/trastero_minimum_area_validator.py": "from typing import List\nfrom housing_generator.application.ports.constraint_validator_port import ConstraintValidatorPort\nfrom housing_generator.application.dto.validation_result import ValidationResult\nfrom housing_generator.domain.entities.layout import Layout\nfrom housing_generator.domain.enums import RoomType\nfrom housing_generator.infrastructure.geometry.shapely_utils import evaluate_minimum_width\n\n# B.2.5 (trastero): superficie minima FIJA, no escala con el numero de\n# estancias -- a diferencia de \"almacenamiento\" (Tabla 2). Confirmado en\n# nhv.lua (NHV.trastero.area = 4.00), con la propia fuente admitiendo que\n# esta regla nunca estuvo realmente implementada pese a estar declarada.\nTRASTERO_AREA_MIN_M2 = 4.00\nTRASTERO_ANCHO_LIBRE_MIN_M = 1.60\n\n# Ancho de puerta (0.80m) sigue pendiente -- requiere modelar puertas/\n# accesos, que este proyecto no modela todavia (mismo hueco identificado\n# en relaciones_espaciales.md: \"acceso/puertas\").\n\n\nclass TrasteroMinimumAreaValidator(ConstraintValidatorPort):\n    \"\"\"B.2.5: superficie minima fija Y ancho libre minimo para trasteros\n    (RoomType.STORAGE_ROOM). Distinto de ServicioMinimumAreaValidator\n    (Tabla 2), que cubre \"almacenamiento\" (RoomType.STORAGE) con un\n    minimo que SI escala con el numero de estancias.\n\n    El ancho de puerta (0.80m, tambien en B.2.5) NO se comprueba aqui --\n    requiere modelar puertas/accesos, pendiente en todo el proyecto.\n    \"\"\"\n\n    def validate(self, layout: Layout) -> ValidationResult:\n        violations: List[str] = []\n        warnings: List[str] = []\n        for room in layout.rooms:\n            if room.room_type != RoomType.STORAGE_ROOM:\n                continue\n            if room.dimensions.area_m2 < TRASTERO_AREA_MIN_M2:\n                violations.append(\n                    f\"'{room.id}': {room.dimensions.area_m2:.1f}m2, por debajo del minimo \"\n                    f\"fijo de B.2.5 para trasteros ({TRASTERO_AREA_MIN_M2:.1f}m2)\"\n                )\n            if room.is_placed:\n                v, w = evaluate_minimum_width(\n                    room.id, room.boundary.polygon, TRASTERO_ANCHO_LIBRE_MIN_M,\n                    violation_message=(\n                        f\"ancho libre por debajo del minimo de B.2.5 ({TRASTERO_ANCHO_LIBRE_MIN_M:.2f}m)\"\n                    ),\n                    warning_message=\"forma no rectangular, no se puede verificar el ancho libre de trastero (B.2.5)\",\n                )\n                violations.extend(v)\n                warnings.extend(w)\n        return ValidationResult(violations=violations, warnings=warnings)\n", "housing_generator/infrastructure/algorithms/constraints/adjacency_validator.py": "from typing import List, Optional\nfrom housing_generator.application.ports.constraint_validator_port import ConstraintValidatorPort\nfrom housing_generator.application.dto.validation_result import ValidationResult\nfrom housing_generator.domain.entities.layout import Layout\nfrom housing_generator.domain.enums import AdjacencyStrength\n\n# MUST_BE_NEAR: longitud minima de borde compartido para considerar que\n# dos estancias estan \"unidas por un lado\" (no solo tocandose en una\n# esquina) -- lo bastante para que quepa una puerta. Confirmado por el\n# usuario como umbral mas exigente que el de adyacencia generica (0.1m).\nMUST_BE_NEAR_MIN_SHARED_LENGTH_M = 1.0\n\n\nclass AdjacencyConstraintValidator(ConstraintValidatorPort):\n    \"\"\"Comprueba restricciones duras:\n    - toda estancia debe estar colocada\n    - el limite del solar debe contener cada estancia\n    - las estancias marcadas MUST_BE_AWAY no deben tocarse\n    - las estancias marcadas MUST_BE_NEAR deben compartir un borde de al\n      menos MUST_BE_NEAR_MIN_SHARED_LENGTH_M (no basta con tocarse en un\n      punto o un tramo muy corto)\n    \"\"\"\n\n    def __init__(self, adjacency_requirements: Optional[list] = None, touch_tolerance_m: float = 0.05):\n        self._requirements = adjacency_requirements or []\n        self._tolerance = touch_tolerance_m\n\n    def validate(self, layout: Layout) -> ValidationResult:\n        violations: List[str] = []\n\n        for room in layout.rooms:\n            if not room.is_placed:\n                violations.append(f\"La estancia '{room.id}' no fue colocada\")\n                continue\n            if not layout.lot.boundary.polygon.buffer(self._tolerance).contains(room.boundary.polygon):\n                violations.append(f\"La estancia '{room.id}' queda fuera del limite del solar\")\n\n        rooms_by_id = {r.id: r for r in layout.rooms if r.is_placed}\n        for req in self._requirements:\n            room_a = rooms_by_id.get(req.room_a_id)\n            room_b = rooms_by_id.get(req.room_b_id)\n            if not room_a or not room_b:\n                continue\n\n            if req.strength == AdjacencyStrength.MUST_BE_AWAY:\n                if room_a.boundary.polygon.distance(room_b.boundary.polygon) < self._tolerance:\n                    violations.append(\n                        f\"Las estancias '{req.room_a_id}' y '{req.room_b_id}' deben estar \"\n                        f\"separadas pero son adyacentes\"\n                    )\n\n            elif req.strength == AdjacencyStrength.MUST_BE_NEAR:\n                shared_length = room_a.boundary.polygon.boundary.intersection(\n                    room_b.boundary.polygon.boundary\n                ).length\n                if shared_length < MUST_BE_NEAR_MIN_SHARED_LENGTH_M:\n                    violations.append(\n                        f\"Las estancias '{req.room_a_id}' y '{req.room_b_id}' deben compartir \"\n                        f\"al menos {MUST_BE_NEAR_MIN_SHARED_LENGTH_M:.2f}m de borde, pero \"\n                        f\"comparten {shared_length:.2f}m\"\n                    )\n\n        return ValidationResult(violations=violations)\n", "housing_generator/infrastructure/algorithms/constraints/escalera_alineacion_validator.py": "from typing import List, Optional\nfrom shapely.geometry import Polygon\nfrom housing_generator.application.ports.constraint_validator_port import ConstraintValidatorPort\nfrom housing_generator.application.dto.validation_result import ValidationResult\nfrom housing_generator.domain.entities.layout import Layout\nfrom housing_generator.domain.enums import RoomType\n\n# Confirmado por investigacion externa (Infinigen Indoors, 2024, apendice\n# D.5 \"Adding staircases\"): \"we compute the intersection of the space\n# assigned as staircase rooms on consecutive floors... rejected when the\n# consecutive staircase [does not] intersect [sufficiently]\". Aqui se\n# adapta a nuestra arquitectura (arbol de particion por planta, generado\n# de forma independiente, no busqueda conjunta): en vez de un \"hueco\"\n# compartido durante la busqueda, la planta de ABAJO se genera primero y\n# su escalera ya resuelta se pasa como referencia FIJA a este validador\n# al generar la planta de ARRIBA -- la alineacion se convierte asi en\n# una restriccion dura mas dentro del mismo mecanismo de recocido\n# simulado ya existente, sin necesitar un tipo de movimiento nuevo.\nESCALERA_ALINEACION_MIN_OVERLAP_RATIO = 0.90\n\n\nclass EscaleraAlineacionValidator(ConstraintValidatorPort):\n    \"\"\"Exige que la huella de RoomType.STAIRCASE en esta planta se solape\n    sustancialmente (>=90% del area de la mas pequena de las dos) con la\n    huella YA RESUELTA de la escalera en la planta de abajo.\n\n    `floor_below_exists=False`: no hay ninguna planta inferior en el\n    edificio (esta es la planta mas baja) -- no aplica en absoluto, no\n    hay nada con lo que alinear.\n\n    `floor_below_exists=True, reference_boundary=None`: SI hay planta\n    inferior, pero esa planta NO declara ninguna escalera -- si ESTA\n    planta si tiene una, es una escalera que no arranca de ningun sitio\n    (violacion). Bug real encontrado en auditoria: antes, este caso se\n    trataba igual que \"no hay planta inferior\" (mismo `None`), dejando\n    pasar sin deteccion una escalera que no conecta con la planta de\n    abajo. Confirmado con test que reproduce el caso exacto antes de\n    corregirlo.\"\"\"\n\n    def __init__(self, reference_boundary: Optional[Polygon], floor_below_exists: bool = True):\n        self._reference = reference_boundary\n        self._floor_below_exists = floor_below_exists\n\n    def validate(self, layout: Layout) -> ValidationResult:\n        staircases = [r for r in layout.rooms if r.room_type == RoomType.STAIRCASE and r.is_placed]\n\n        if not self._floor_below_exists:\n            return ValidationResult()  # planta mas baja del edificio -- nada que alinear\n\n        if self._reference is None:\n            if staircases:\n                return ValidationResult(violations=[\n                    \"Esta planta declara escalera, pero la planta inferior no tiene ninguna \"\n                    \"-- la escalera no arranca de ningun sitio\"\n                ])\n            return ValidationResult()  # ninguna de las dos plantas tiene escalera -- correcto\n\n        if not staircases:\n            return ValidationResult(violations=[\n                \"La planta inferior tiene escalera pero esta planta no declara ninguna \"\n                \"RoomType.STAIRCASE -- la escalera no puede quedar sin continuidad\"\n            ])\n\n        violations: List[str] = []\n        for stair in staircases:\n            intersection_area = stair.boundary.polygon.intersection(self._reference).area\n            smaller_area = min(stair.boundary.polygon.area, self._reference.area)\n            ratio = intersection_area / smaller_area if smaller_area > 0 else 0.0\n            if ratio < ESCALERA_ALINEACION_MIN_OVERLAP_RATIO:\n                violations.append(\n                    f\"'{stair.id}': solapamiento con la escalera de la planta inferior de \"\n                    f\"{ratio:.0%}, por debajo del minimo exigido \"\n                    f\"({ESCALERA_ALINEACION_MIN_OVERLAP_RATIO:.0%})\"\n                )\n        return ValidationResult(violations=violations)\n", "housing_generator/infrastructure/algorithms/constraints/dormitorio_armario_validator.py": "from typing import List\nfrom housing_generator.application.ports.constraint_validator_port import ConstraintValidatorPort\nfrom housing_generator.application.dto.validation_result import ValidationResult\nfrom housing_generator.domain.entities.layout import Layout\nfrom housing_generator.domain.enums import RoomType\nfrom housing_generator.infrastructure.geometry.shapely_utils import can_fit_rectangle\n\n# Espacio de armario empotrado por dormitorio -- CONFIRMADO por\n# investigacion (condiciones minimas de habitabilidad, varias fuentes\n# independientes), NO presente en nhv.lua. El espacio cuenta DENTRO de\n# la superficie del propio dormitorio (no es un Room aparte):\n#   - profundidad minima: 0.60 m\n#   - altura minima: 2.20 m -- NO se duplica aqui: la altura general del\n#     dormitorio ya la cubre `AlturaLibreValidator` sobre la misma\n#     habitacion (el armario esta dentro de ella, no es un volumen aparte\n#     con su propia altura independiente).\n#   - largo minimo: 1.00 m si la habitacion es de mas de 6m2,\n#                   1.50 m si la habitacion es de mas de 8m2\n# El umbral exacto para habitaciones de <=6m2 no aparece en las fuentes\n# consultadas; se usa 1.00 m como valor conservador por defecto, marcado\n# como asuncion, no como cifra normativa confirmada.\nARMARIO_PROFUNDIDAD_MIN_M = 0.60\nARMARIO_LARGO_MIN_PEQUENO_M = 1.00\nARMARIO_LARGO_MIN_GRANDE_M = 1.50\nARMARIO_AREA_UMBRAL_GRANDE_M2 = 8.0\n\n\ndef armario_largo_minimo(area_m2: float) -> float:\n    if area_m2 > ARMARIO_AREA_UMBRAL_GRANDE_M2:\n        return ARMARIO_LARGO_MIN_GRANDE_M\n    return ARMARIO_LARGO_MIN_PEQUENO_M  # incluye <=6m2 como asuncion conservadora\n\n\nclass DormitorioArmarioValidator(ConstraintValidatorPort):\n    \"\"\"Exige que cada dormitorio (BEDROOM, MASTER_BEDROOM) admita, dentro\n    de su propia forma, un hueco de armario empotrado de\n    `armario_largo_minimo(area) x ARMARIO_PROFUNDIDAD_MIN_M`.\n\n    NO reserva ni resta esa superficie del dormitorio -- solo comprueba\n    que la geometria de la habitacion sea capaz de alojarlo, igual que\n    el cuadrado inscribible del salon. Misma logica de tres estados:\n    violacion si no cabe, aviso si no se puede verificar (forma no\n    rectangular), nada si no esta colocado todavia.\n\n    La altura minima (2.20m) no se comprueba EN ESTE validador -- la\n    cubre `AlturaLibreValidator` sobre la misma habitacion.\n    \"\"\"\n\n    ROOM_TYPES = {RoomType.BEDROOM, RoomType.MASTER_BEDROOM}\n\n    def validate(self, layout: Layout) -> ValidationResult:\n        violations: List[str] = []\n        warnings: List[str] = []\n\n        for room in layout.rooms:\n            if room.room_type not in self.ROOM_TYPES or not room.is_placed:\n                continue\n\n            largo = armario_largo_minimo(room.dimensions.area_m2)\n            cabe = can_fit_rectangle(room.boundary.polygon, largo, ARMARIO_PROFUNDIDAD_MIN_M)\n\n            if cabe is False:\n                violations.append(\n                    f\"'{room.id}': no admite el hueco de armario empotrado minimo \"\n                    f\"({largo:.2f}m x {ARMARIO_PROFUNDIDAD_MIN_M:.2f}m) dentro de su \"\n                    f\"propia forma\"\n                )\n            elif cabe is None:\n                warnings.append(\n                    f\"'{room.id}': forma no rectangular, no se puede verificar el \"\n                    f\"hueco de armario empotrado\"\n                )\n\n        return ValidationResult(violations=violations, warnings=warnings)\n", "housing_generator/infrastructure/algorithms/constraints/vivienda_accesible_validator.py": "from typing import List\nfrom housing_generator.application.ports.constraint_validator_port import ConstraintValidatorPort\nfrom housing_generator.application.dto.validation_result import ValidationResult\nfrom housing_generator.domain.entities.layout import Layout\nfrom housing_generator.domain.enums import RoomType\nfrom housing_generator.infrastructure.geometry.shapely_utils import can_inscribe_square, evaluate_minimum_width\n\n# Retomado de un modulo Lua de un proyecto anterior del usuario\n# (accesibilidad.lua), que investigo a fondo DB-SUA (Anejo A, CTE\n# estatal) cruzado con el Codigo de Accesibilidad de Galicia (Decreto\n# 35/2000, actualizado por el Decreto 74/2013) y la Base 5.4 gallega\n# (vivienda adaptada para usuarios de silla de ruedas). OPT-IN: la\n# gran mayoria de viviendas NO estan obligadas a cumplir estas\n# condiciones -- DB-SUA 9.1, texto literal citado en la fuente Lua:\n# \"Dentro de los limites de las viviendas... las condiciones de\n# accesibilidad unicamente son exigibles en aquellas que deban ser\n# accesibles\" (una designacion especifica, no cualquier vivienda).\n#\n# ALCANCE: de todo lo que cubre la fuente Lua (que tambien verifica\n# mobiliario -- altura de encimera, aproximacion lateral a la cama,\n# hueco bajo fregadero, barras de apoyo...), aqui solo se modela lo\n# GEOMETRICAMENTE VERIFICABLE con nuestro `Room` (un rectangulo con\n# area, sin mobiliario ni fixtures) -- circulo de giro y ancho de\n# pasillo. El resto exigiria modelar mobiliario como piezas propias\n# dentro de cada estancia, un salto de complejidad que este proyecto\n# no da por los mismos motivos que ya documentamos para C.10 (luz\n# directa) o el parametro D de patios: fingir una comprobacion sin\n# los datos reales seria peor que no darla.\nCIRCULO_GIRO_ACCESIBLE_M = 1.50  # DB-SUA Anejo A / Base 5.4 -- mismo valor en estancias y bano\nPASILLO_ACCESIBLE_ANCHO_M = 1.20  # Base 5.4 -- mas exigente que el generico 1.00m (A.3.2.3)\n\n# Tipos de estancia sobre los que tiene sentido exigir el circulo de\n# giro en una vivienda accesible -- las mismas piezas que la fuente Lua\n# comprueba con `acc.circuloGiro` (estancia mayor, dormitorios, cocina,\n# bano) mas RoomType.DINING_ROOM (misma zona de estar, mismo criterio).\n# No incluye estancias de servicio pequenas (lavadero, tendedero,\n# almacenamiento) -- la fuente Lua tampoco las exige.\nTIPOS_CON_CIRCULO_GIRO = {\n    RoomType.LIVING_ROOM, RoomType.DINING_ROOM, RoomType.BEDROOM,\n    RoomType.MASTER_BEDROOM, RoomType.KITCHEN, RoomType.BATHROOM,\n}\n\n\nclass ViviendaAccesibleValidator(ConstraintValidatorPort):\n    \"\"\"Vivienda declarada accesible para usuarios de silla de ruedas\n    (DB-SUA Anejo A + Base 5.4 Galicia) -- SOLO activo si se construye\n    con `activo=True`. Exige circulo de giro Ø1.50m inscribible en\n    estancias habitables + baño, y pasillo ≥1.20m (mas exigente que el\n    minimo general de `AnchoLibrePasilloValidator`, 1.00m -- ambos\n    validadores conviven, este añade una exigencia adicional, no\n    sustituye al general).\"\"\"\n\n    def __init__(self, activo: bool = False):\n        self.activo = activo\n\n    def validate(self, layout: Layout) -> ValidationResult:\n        violations: List[str] = []\n        warnings: List[str] = []\n\n        if not self.activo:\n            return ValidationResult(violations=violations, warnings=warnings)\n\n        for room in layout.rooms:\n            if not room.is_placed:\n                continue\n\n            if room.room_type in TIPOS_CON_CIRCULO_GIRO:\n                cumple = can_inscribe_square(room.boundary.polygon, CIRCULO_GIRO_ACCESIBLE_M)\n                if cumple is False:\n                    violations.append(\n                        f\"'{room.id}': vivienda accesible, no admite el circulo de giro \"\n                        f\"de Ø{CIRCULO_GIRO_ACCESIBLE_M:.2f}m exigido (DB-SUA/Base 5.4)\"\n                    )\n                elif cumple is None:\n                    warnings.append(\n                        f\"'{room.id}': forma no rectangular, no se puede verificar el \"\n                        f\"circulo de giro de vivienda accesible\"\n                    )\n\n            if room.room_type == RoomType.CORRIDOR:\n                v, w = evaluate_minimum_width(\n                    room.id, room.boundary.polygon, PASILLO_ACCESIBLE_ANCHO_M,\n                    violation_message=(\n                        f\"ancho libre por debajo del minimo de vivienda accesible \"\n                        f\"({PASILLO_ACCESIBLE_ANCHO_M:.2f}m, Base 5.4 -- mas exigente que \"\n                        f\"el general de A.3.2.3)\"\n                    ),\n                    warning_message=\"forma no rectangular, no se puede verificar el ancho de pasillo accesible\",\n                )\n                violations.extend(v)\n                warnings.extend(w)\n\n        return ValidationResult(violations=violations, warnings=warnings)\n", "housing_generator/infrastructure/algorithms/layout_generation/simulated_annealing_generator.py": "import copy\nimport math\nimport random\nfrom typing import Dict, List, Optional\n\nfrom housing_generator.application.ports.layout_generator_port import LayoutGeneratorPort\nfrom housing_generator.application.ports.constraint_validator_port import ConstraintValidatorPort\nfrom housing_generator.domain.entities.program import Program\nfrom housing_generator.domain.entities.lot import Lot\nfrom housing_generator.domain.entities.zone import Zone\nfrom housing_generator.domain.entities.layout import Layout\nfrom housing_generator.domain.value_objects.boundary import Boundary\nfrom housing_generator.infrastructure.algorithms.layout_generation.partition_tree import (\n    PartitionNode,\n    build_random_tree,\n    place_tree,\n    random_neighbor,\n)\nfrom housing_generator.infrastructure.algorithms.layout_generation.soft_constraint_scorer import (\n    SoftConstraintScorer,\n)\n\n\nclass SimulatedAnnealingLayoutGenerator(LayoutGeneratorPort):\n    \"\"\"Genera el layout construyendo un arbol de particion recursivo sobre\n    TODAS las estancias del programa a la vez (sin fase previa de reparto\n    por macro-zona geometrica) y buscando la mejor topologia mediante\n    recocido simulado.\n\n    La funcion objetivo combina violaciones DURAS (siempre dominantes)\n    con una penalizacion BLANDA opcional (Preferencia cerca/alejar) --\n    ver `_score`. Comparacion LEXICOGRAFICA real (tupla `(duro, blando)`),\n    no suma ponderada: una primera version sumaba `duro*peso_grande +\n    blando`, que garantiza el orden final correcto pero rompe la\n    dinamica de aceptacion del recocido (`exp(-delta/temperatura)`\n    reacciona a la magnitud absoluta del delta, no solo al orden\n    relativo -- confirmado que rompia tests que no tocaban nada de las\n    restricciones blandas). Con la tupla, cuando lo duro cambia entre\n    candidato y actual, la aceptacion se decide SOLO por ese delta (a su\n    escala natural, igual que antes de anadir nada blando); lo blando\n    solo entra en juego cuando lo duro empata.\n\n    DIFERENCIA DE ARQUITECTURA respecto a GraphBasedLayoutGenerator: este\n    generador recibe el ConstraintValidatorPort como dependencia PROPIA\n    (no solo GenerateLayoutUseCase), porque necesita invocarlo miles de\n    veces durante la busqueda interna. Generacion y validacion quedan\n    acopladas dentro de esta clase concreta -- ambas siguen siendo\n    intercambiables por separado en el resto del sistema (siguen siendo\n    ports), pero esta implementacion en particular necesita las dos.\n\n    `zones` (el parametro del puerto `LayoutGeneratorPort`) se ignora\n    deliberadamente: este generador no reparte geometria por macro-zona,\n    construye su propia agrupacion interna a partir de `room.zone` solo\n    para poblar `Layout.zones` (compatibilidad con el resto del sistema),\n    no para particionar el solar.\n    \"\"\"\n\n    def __init__(\n        self,\n        constraint_validator: ConstraintValidatorPort,\n        max_iterations: int = 2000,\n        initial_temperature: float = 10.0,\n        cooling_rate: float = 0.995,\n        seed: Optional[int] = None,\n        soft_constraint_scorer: Optional[SoftConstraintScorer] = None,\n    ):\n        self._constraint_validator = constraint_validator\n        self._max_iterations = max_iterations\n        self._initial_temperature = initial_temperature\n        self._cooling_rate = cooling_rate\n        self._seed = seed\n        self._soft_scorer = soft_constraint_scorer\n\n    def generate(self, program: Program, lot: Lot, zones: List[Zone]) -> Layout:\n        # BUG REAL encontrado en auditoria: antes, `self._rng` se creaba\n        # UNA sola vez en __init__ y esta misma instancia se reutilizaba\n        # entre llamadas -- `seed` solo garantizaba un resultado\n        # reproducible en la PRIMERA llamada a generate(); cualquier\n        # llamada posterior sobre el MISMO generador continuaba desde\n        # donde quedo la secuencia aleatoria anterior, no desde la\n        # semilla, rompiendo el determinismo que el resto del proyecto\n        # da por hecho (confirmado: llamar generate() dos veces seguidas\n        # con seed=1 daba resultados distintos la segunda vez). Reiniciar\n        # aqui, en cada llamada, hace que la semilla sea reproducible\n        # SIEMPRE, no solo la primera vez.\n        self._rng = random.Random(self._seed)\n\n        room_ids = [r.id for r in program.rooms]\n        areas = {r.id: r.dimensions.area_m2 for r in program.rooms}\n\n        current_tree = build_random_tree(room_ids, self._rng)\n        current_layout = self._materialize(current_tree, program, lot, areas)\n        current_hard, current_soft = self._score(current_layout)\n\n        best_layout = current_layout\n        best_hard, best_soft = current_hard, current_soft\n\n        temperature = self._initial_temperature\n        for _ in range(self._max_iterations):\n            if best_hard == 0 and best_soft == 0:\n                break\n\n            candidate_tree = random_neighbor(current_tree, self._rng, areas)\n            candidate_layout = self._materialize(candidate_tree, program, lot, areas)\n            candidate_hard, candidate_soft = self._score(candidate_layout)\n\n            # BUG REAL encontrado al conectar las restricciones blandas:\n            # una primera version combinaba duro+blando en un UNICO\n            # numero (hard*1000 + soft) para la aceptacion del recocido.\n            # Esto garantiza el orden final correcto, pero ROMPE la\n            # dinamica de aceptacion: exp(-delta/temperatura) reacciona a\n            # la MAGNITUD absoluta del delta, no solo al orden relativo\n            # -- multiplicar por 1000 hacia practicamente imposible\n            # aceptar CUALQUIER movimiento que empeorase lo duro, incluso\n            # al principio con temperatura alta, cambiando el\n            # comportamiento ya afinado de todo el proyecto (confirmado:\n            # rompio un test de multi-planta que no tocaba nada de esto).\n            # Corregido con comparacion LEXICOGRAFICA real: si lo duro\n            # cambia, la aceptacion se decide SOLO por el delta duro (a\n            # su escala natural, pequeña, igual que antes de tocar nada\n            # de esto); solo se mira lo blando cuando lo duro empata.\n            if candidate_hard != current_hard:\n                delta = candidate_hard - current_hard\n            else:\n                delta = candidate_soft - current_soft\n\n            accepted = delta <= 0 or self._rng.random() < math.exp(-delta / max(temperature, 1e-9))\n            if accepted:\n                current_tree, current_layout = candidate_tree, candidate_layout\n                current_hard, current_soft = candidate_hard, candidate_soft\n                if (current_hard, current_soft) < (best_hard, best_soft):\n                    best_layout = current_layout\n                    best_hard, best_soft = current_hard, current_soft\n\n            temperature *= self._cooling_rate\n\n        best_layout.metadata[\"annealing_score\"] = best_hard  # compatibilidad: violaciones duras del mejor layout\n        best_layout.metadata[\"hard_violations\"] = best_hard\n        best_layout.metadata[\"soft_penalty\"] = best_soft\n        return best_layout\n\n    def _score(self, layout: Layout) -> tuple:\n        hard_violations = len(self._constraint_validator.validate(layout).violations)\n        soft_penalty = self._soft_scorer.score(layout) if self._soft_scorer else 0.0\n        return (hard_violations, soft_penalty)\n\n    def _materialize(\n        self,\n        tree: PartitionNode,\n        program: Program,\n        lot: Lot,\n        areas: Dict[str, float],\n    ) -> Layout:\n        # area edificable: la parcela completa si no hay retranqueo\n        # declarado, o la parcela reducida por el retranqueo si lo hay\n        # (vivienda unifamiliar aislada -- ver Lot.buildable_area).\n        placements = place_tree(tree, lot.buildable_area.polygon, areas)\n\n        placed_rooms = []\n        for room in program.rooms:\n            placed_room = copy.copy(room)  # copia superficial: no muta el Room del Program original\n            placed_room.boundary = Boundary(polygon=placements[room.id])\n            placed_rooms.append(placed_room)\n\n        zones_map: Dict = {}\n        for room in placed_rooms:\n            zones_map.setdefault(room.zone, []).append(room.id)\n        built_zones = [Zone(zone_type=zone_type, room_ids=ids) for zone_type, ids in zones_map.items()]\n\n        return Layout(lot=lot, rooms=placed_rooms, zones=built_zones)\n", "housing_generator/infrastructure/algorithms/layout_generation/soft_constraint_scorer.py": "from typing import List\nimport networkx as nx\nfrom housing_generator.application.ports.adjacency_graph_builder_port import AdjacencyGraphBuilderPort\nfrom housing_generator.domain.entities.layout import Layout\nfrom housing_generator.domain.enums import AdjacencyStrength\nfrom housing_generator.domain.value_objects.adjacency import AdjacencyRequirement\n\n# Diseno ya decidido en relaciones_espaciales.md, sin conectar hasta\n# ahora -- primer punto retomado de docs/CONTINUIDAD.md. Investigacion\n# externa confirmada (curriculum-based course timetabling, arxiv\n# 1409.7186): la tecnica estandar para combinar restricciones duras y\n# blandas en una funcion de coste de recocido simulado es una SUMA\n# PONDERADA, con un peso grande para lo duro (parametro del algoritmo,\n# no derivado de una formula) y pesos pequenos especificos por tipo de\n# restriccion blanda -- exactamente el patron aplicado aqui, no una\n# tecnica inventada sin precedente.\n#\n# Metrica: saltos en el grafo de adyacencia REAL (misma fuente que\n# nucleo humedo/zonificacion/topologia de pasillo -- GeometryAdjacencyGraphBuilder,\n# con su cache ya corregida), NO el grafo de puertas disperso ni\n# contacto geometrico directo -- decision ya tomada y documentada.\nTARGET_CERCA_SALTOS = 2\nTARGET_ALEJAR_SALTOS = 3\nPESO_CERCA_NO_SATISFECHO = 1.0\nPESO_ALEJAR_NO_SATISFECHO = 1.0\n\n\nclass SoftConstraintScorer:\n    \"\"\"Calcula la penalizacion blanda (SHOULD_BE_NEAR/SHOULD_BE_AWAY,\n    \"Preferencia cerca/alejar\" del catalogo) de un Layout, para sumarla\n    a las violaciones duras en la funcion objetivo del recocido\n    simulado. Nunca genera una ValidationResult ni bloquea nada -- es\n    puramente un numero a minimizar, subordinado siempre a las\n    restricciones duras (ver SimulatedAnnealingLayoutGenerator._score).\n\n    Si `adjacency_requirements` no contiene ningun SHOULD_BE_NEAR/\n    SHOULD_BE_AWAY, `score()` siempre devuelve 0 -- inerte por\n    completo, no cambia el comportamiento de programas que solo\n    declaran restricciones duras (compatibilidad hacia atras real, no\n    solo de interfaz).\"\"\"\n\n    def __init__(\n        self,\n        adjacency_requirements: List[AdjacencyRequirement],\n        graph_builder: AdjacencyGraphBuilderPort,\n    ):\n        self._soft_requirements = [\n            req for req in adjacency_requirements\n            if req.strength in (AdjacencyStrength.SHOULD_BE_NEAR, AdjacencyStrength.SHOULD_BE_AWAY)\n        ]\n        self._graph_builder = graph_builder\n\n    def score(self, layout: Layout) -> float:\n        if not self._soft_requirements:\n            return 0.0\n\n        graph = self._graph_builder.build(layout)\n        penalty = 0.0\n\n        for req in self._soft_requirements:\n            if req.room_a_id not in graph or req.room_b_id not in graph:\n                # Solo dispara si la estancia NO esta colocada (is_placed\n                # excluida por GeometryAdjacencyGraphBuilder.build()) --\n                # una estancia colocada pero totalmente AISLADA (sin\n                # ninguna pared compartida) SI aparece como nodo en el\n                # grafo (add_node se llama para toda estancia colocada,\n                # tenga o no aristas), asi que ese caso NO entra aqui:\n                # se resuelve mas abajo via distance=inf (nx.has_path\n                # devuelve False si no hay ninguna arista), con el mismo\n                # resultado final. Comentario corregido en auditoria --\n                # el anterior atribuia el caso \"aislada\" a esta rama por\n                # error, aunque el resultado numerico ya era correcto.\n                if req.strength == AdjacencyStrength.SHOULD_BE_NEAR:\n                    penalty += PESO_CERCA_NO_SATISFECHO\n                continue\n\n            if nx.has_path(graph, req.room_a_id, req.room_b_id):\n                distance = nx.shortest_path_length(graph, req.room_a_id, req.room_b_id)\n            else:\n                distance = float(\"inf\")\n\n            if req.strength == AdjacencyStrength.SHOULD_BE_NEAR:\n                if distance > TARGET_CERCA_SALTOS:\n                    penalty += PESO_CERCA_NO_SATISFECHO\n            else:  # SHOULD_BE_AWAY\n                if distance < TARGET_ALEJAR_SALTOS:\n                    penalty += PESO_ALEJAR_NO_SATISFECHO\n\n        return penalty\n", "housing_generator/infrastructure/algorithms/layout_generation/partition_tree.py": "\"\"\"Arbol de particion recursivo (slicing tree) para distribuir TODAS las\nestancias de un programa en un solar de una sola vez, sin una fase previa\nde reparto por macro-zona geometrica.\n\nCada hoja del arbol contiene una estancia; cada nodo interno divide su\nrectangulo en dos, en horizontal o vertical, con una proporcion\ndeterminada por el area total de estancias de cada subarbol. Es la\nrepresentacion clasica de \"slicing floorplan\" usada en floorplanning\n(particion guillotina): cualquier arbol binario con una direccion de\ncorte por nodo interno se traduce en una planta rectangular valida sin\nsolapes ni huecos.\n\"\"\"\nimport copy\nimport random\nfrom dataclasses import dataclass\nfrom typing import Dict, List, Optional\nfrom shapely.geometry import Polygon, box\n\n\n@dataclass\nclass PartitionNode:\n    \"\"\"Nodo del arbol. Una hoja tiene `room_id`; un nodo interno tiene\n    `direction` y dos subarboles `first`/`second`.\n\n    `direction`: **[RESUELTO, retomado tras un caso real]** `None` (por\n    defecto) significa \"automatica -- cortar siempre por el lado MAS\n    LARGO del rectangulo, en el momento de colocar\" (investigacion\n    externa: Marson & Musse 2010, tecnica de squarified treemap para\n    generar plantas con estancias de proporcion cercana a 1:1). Un\n    valor explicito (\"h\"/\"v\") FUERZA esa direccion, anulando el\n    automatismo -- usado por el movimiento `flip_direction` como via de\n    escape para que el recocido pueda explorar topologias distintas a\n    la \"natural\" cuando haga falta.\n\n    Encontrado con un caso real: con la direccion puramente aleatoria\n    de antes, estancias pequeñas emparejadas por azar con una estancia\n    grande podian acabar como tiras finas (ancho libre insuficiente),\n    y anadir una restriccion de ancho minimo practico\n    (AnchoLibrePracticoValidator) volvio esto una dificultad de\n    busqueda mucho mayor -- confirmado que quitando el validador la\n    misma semilla convergia en 22s, con el activo fallaba incluso con\n    30000 iteraciones. Cortar por el lado mas largo por defecto reduce\n    la aparicion de tiras finas desde el propio punto de partida, en\n    vez de depender de que el recocido las evite por pura suerte.\n\n    `ratio_override`: proporcion del corte FORZADA manualmente (0-1,\n    fraccion de `first`), en vez de derivarla siempre del area declarada\n    de las estancias. Inspirado en Merrell/Schkufza/Koltun 2010\n    (\"Sliding a wall\" como proposal move independiente de \"swapping\n    rooms\") -- investigacion externa confirmada, no una idea propia\n    inventada sin referencia. Sin esto, la proporcion de cada corte\n    quedaba SIEMPRE atada al area declarada de cada estancia, sin ningun\n    grado de libertad independiente para ajustar forma/ancho libre sin\n    cambiar topologia. `None` (por defecto) preserva el comportamiento\n    anterior exacto -- calculo derivado del area.\"\"\"\n    room_id: Optional[str] = None\n    direction: Optional[str] = None\n    first: Optional[\"PartitionNode\"] = None\n    second: Optional[\"PartitionNode\"] = None\n    ratio_override: Optional[float] = None\n\n    @property\n    def is_leaf(self) -> bool:\n        return self.room_id is not None\n\n    def leaves(self) -> List[\"PartitionNode\"]:\n        if self.is_leaf:\n            return [self]\n        # invariante mantenida por construccion (build_random_tree,\n        # random_neighbor): un nodo NO-hoja siempre tiene first/second.\n        # mypy no puede demostrarlo solo (Python no tiene \"tipos suma\"\n        # nativos para esto) -- el assert documenta la invariante Y le\n        # da a mypy la informacion de estrechamiento de tipo que necesita.\n        assert self.first is not None and self.second is not None, \\\n            \"Nodo interno sin first/second -- invariante del arbol violada\"\n        return self.first.leaves() + self.second.leaves()\n\n    def internal_nodes(self) -> List[\"PartitionNode\"]:\n        if self.is_leaf:\n            return []\n        assert self.first is not None and self.second is not None, \\\n            \"Nodo interno sin first/second -- invariante del arbol violada\"\n        return [self] + self.first.internal_nodes() + self.second.internal_nodes()\n\n\ndef build_random_tree(room_ids: List[str], rng: random.Random) -> PartitionNode:\n    \"\"\"Construye un arbol de topologia aleatoria que contiene cada\n    room_id exactamente una vez (punto de partida para la busqueda).\n\n    `direction=None` (automatica, corta por el lado mas largo -- ver\n    docstring de PartitionNode) es el punto de partida por defecto,\n    no un valor h/v elegido al azar como antes -- el azar de direccion\n    ahora es responsabilidad exclusiva del movimiento `flip_direction`\n    durante la busqueda, no de la construccion inicial.\"\"\"\n    if len(room_ids) == 1:\n        return PartitionNode(room_id=room_ids[0])\n\n    shuffled = list(room_ids)\n    rng.shuffle(shuffled)\n    split = rng.randint(1, len(shuffled) - 1)\n    first = build_random_tree(shuffled[:split], rng)\n    second = build_random_tree(shuffled[split:], rng)\n    return PartitionNode(direction=None, first=first, second=second)\n\n\ndef _leaf_area(leaf: \"PartitionNode\", areas: Dict[str, float]) -> float:\n    \"\"\"Area de una hoja -- helper compartido por place_tree y\n    _current_ratio, evita repetir el assert de invariante en cada sitio.\"\"\"\n    assert leaf.room_id is not None, \"Nodo no-hoja pasado a _leaf_area -- invariante violada\"\n    return areas[leaf.room_id]\n\n\ndef place_tree(node: PartitionNode, rectangle: Polygon, areas: Dict[str, float]) -> Dict[str, Polygon]:\n    \"\"\"Recorre el arbol y devuelve, para cada room_id, el rectangulo que\n    le corresponde dentro de `rectangle`, proporcional al area total de\n    estancias de cada subarbol en cada corte.\"\"\"\n    if node.is_leaf:\n        assert node.room_id is not None\n        return {node.room_id: rectangle}\n\n    assert node.first is not None and node.second is not None, \\\n        \"Nodo interno sin first/second -- invariante del arbol violada\"\n    minx, miny, maxx, maxy = rectangle.bounds\n    first_area = sum(_leaf_area(leaf, areas) for leaf in node.first.leaves())\n    second_area = sum(_leaf_area(leaf, areas) for leaf in node.second.leaves())\n    total = first_area + second_area or 1.0\n    ratio = node.ratio_override if node.ratio_override is not None else (first_area / total)\n\n    # direccion EFECTIVA: si no hay override explicito (\"h\"/\"v\" forzado\n    # por flip_direction), cortar por el lado mas largo del rectangulo\n    # actual -- tecnica de squarified treemap (Marson & Musse 2010),\n    # ver docstring de PartitionNode para el porque real de este cambio.\n    if node.direction is not None:\n        effective_direction = node.direction\n    else:\n        width, height = maxx - minx, maxy - miny\n        effective_direction = \"v\" if width > height else \"h\"\n\n    if effective_direction == \"v\":  # corte vertical: reparte a lo largo de X\n        split_x = minx + (maxx - minx) * ratio\n        first_box = box(minx, miny, split_x, maxy)\n        second_box = box(split_x, miny, maxx, maxy)\n    else:  # corte horizontal: reparte a lo largo de Y\n        split_y = miny + (maxy - miny) * ratio\n        first_box = box(minx, miny, maxx, split_y)\n        second_box = box(minx, split_y, maxx, maxy)\n\n    placements: Dict[str, Polygon] = {}\n    placements.update(place_tree(node.first, first_box, areas))\n    placements.update(place_tree(node.second, second_box, areas))\n    return placements\n\n\nSLIDE_WALL_STEP = 0.08          # perturbacion maxima por movimiento (+-8%)\nSLIDE_WALL_MIN_RATIO = 0.15      # limites para evitar cortes degenerados\nSLIDE_WALL_MAX_RATIO = 0.85\n\n\ndef _current_ratio(node: PartitionNode, areas: Dict[str, float]) -> float:\n    \"\"\"Proporcion EFECTIVA actual de un nodo interno: su `ratio_override`\n    si ya tiene uno, o la derivada de las areas declaradas si no -- es\n    el punto de partida real para \"deslizar\" desde ahi, no un valor fijo.\"\"\"\n    if node.ratio_override is not None:\n        return node.ratio_override\n    assert node.first is not None and node.second is not None, \\\n        \"Nodo interno sin first/second -- invariante del arbol violada\"\n    first_area = sum(_leaf_area(leaf, areas) for leaf in node.first.leaves())\n    second_area = sum(_leaf_area(leaf, areas) for leaf in node.second.leaves())\n    total = first_area + second_area or 1.0\n    return first_area / total\n\n\ndef random_neighbor(tree: PartitionNode, rng: random.Random, areas: Dict[str, float]) -> PartitionNode:\n    \"\"\"Genera un arbol vecino mediante UNO de cuatro movimientos aleatorios:\n    - intercambiar la estancia de dos hojas cualesquiera\n    - invertir la direccion de corte (h<->v) de un nodo interno\n    - intercambiar los dos subarboles de un nodo interno (efecto espejo)\n    - \"deslizar pared\": perturbar la proporcion de un corte existente,\n      independientemente de las areas declaradas (`ratio_override`) --\n      inspirado en Merrell/Schkufza/Koltun 2010 (\"Sliding a wall\" como\n      proposal move propio, distinto de \"swapping rooms\"). Los tres\n      primeros son los habituales en recocido simulado sobre slicing\n      floorplans; el cuarto cubre un grado de libertad que antes no\n      existia en absoluto: sin el, la unica forma de corregir una\n      violacion de forma/ancho libre era cambiar topologia (que\n      estancia va con cual), nunca ajustar un corte ya bueno en si mismo.\n      La perturbacion parte de la proporcion EFECTIVA actual (`_current_ratio`),\n      no de un valor fijo -- un deslizamiento real, no un salto.\n    \"\"\"\n    new_tree = copy.deepcopy(tree)\n    move = rng.choice((\"swap_leaves\", \"flip_direction\", \"swap_children\", \"slide_wall\"))\n\n    if move == \"swap_leaves\":\n        leaves = new_tree.leaves()\n        if len(leaves) >= 2:\n            a, b = rng.sample(leaves, 2)\n            a.room_id, b.room_id = b.room_id, a.room_id\n        return new_tree\n\n    internals = new_tree.internal_nodes()\n    if not internals:\n        return new_tree\n    target = rng.choice(internals)\n\n    if move == \"flip_direction\":\n        # ciclo None (automatica, lado mas largo) -> \"h\" forzado ->\n        # \"v\" forzado -> None -- ya no es un toggle ciego h<->v, porque\n        # la direccion \"natural\" ahora depende del rectangulo real en\n        # el momento de colocar, no se puede saber solo mirando el\n        # nodo. Ciclar por los 3 estados le da al recocido la misma\n        # libertad de explorar topologias no-cuadradas cuando haga\n        # falta (p.ej. un pasillo que conviene mantener alargado en la\n        # misma direccion), sin perder el punto de partida \"automatico\"\n        # por defecto.\n        if target.direction is None:\n            target.direction = \"h\"\n        elif target.direction == \"h\":\n            target.direction = \"v\"\n        else:\n            target.direction = None\n    elif move == \"swap_children\":\n        target.first, target.second = target.second, target.first\n    else:  # slide_wall\n        current = _current_ratio(target, areas)\n        delta = rng.uniform(-SLIDE_WALL_STEP, SLIDE_WALL_STEP)\n        target.ratio_override = min(SLIDE_WALL_MAX_RATIO, max(SLIDE_WALL_MIN_RATIO, current + delta))\n    return new_tree\n", "housing_generator/infrastructure/algorithms/layout_generation/__init__.py": "", "housing_generator/infrastructure/algorithms/layout_generation/graph_based_generator.py": "from typing import List, Dict\nfrom shapely.geometry import Polygon, box\nfrom housing_generator.application.ports.layout_generator_port import LayoutGeneratorPort\nfrom housing_generator.domain.entities.program import Program\nfrom housing_generator.domain.entities.lot import Lot\nfrom housing_generator.domain.entities.zone import Zone\nfrom housing_generator.domain.entities.layout import Layout\nfrom housing_generator.domain.value_objects.boundary import Boundary\nfrom housing_generator.domain.enums import ZoneType\n\n# Orden de las zonas a lo largo del eje de \"profundidad\", desde la fachada/\n# acceso hacia el interior, siguiendo el gradiente de privacidad\n# dia -> noche -> servicio habitual en vivienda residencial.\n_ZONE_ORDER = [ZoneType.DAY, ZoneType.NIGHT, ZoneType.SERVICE]\n\n\nclass GraphBasedLayoutGenerator(LayoutGeneratorPort):\n    \"\"\"Generador de particionado (slicing) simplificado:\n\n    1. Divide el solar en franjas horizontales, una por zona, con tamano\n       proporcional al area total de estancias de cada zona (paso de\n       diagrama de zonificacion).\n    2. Dentro de cada franja de zona, vuelve a dividir en cajas por\n       estancia, proporcional al area solicitada de cada una (paso de\n       traduccion diagrama de burbujas -> planta).\n\n    Es deliberadamente simple para que sea facil de testear y entender,\n    y para poder sustituirlo despues por un generador basado en resolucion\n    de restricciones (CSP) o en un algoritmo genetico que implemente el\n    mismo LayoutGeneratorPort sin tocar el resto del sistema.\n    \"\"\"\n\n    def generate(self, program: Program, lot: Lot, zones: List[Zone]) -> Layout:\n        minx, miny, maxx, maxy = lot.boundary.polygon.bounds\n        total_height = maxy - miny\n\n        ordered_zones = sorted(\n            zones,\n            key=lambda z: _ZONE_ORDER.index(z.zone_type) if z.zone_type in _ZONE_ORDER else 99,\n        )\n\n        zone_areas: Dict[ZoneType, float] = {\n            zone.zone_type: sum(\n                program.room_by_id(rid).dimensions.area_m2 for rid in zone.room_ids\n            )\n            for zone in ordered_zones\n        }\n        total_area = sum(zone_areas.values()) or 1.0\n\n        placed_rooms = list(program.rooms)\n        rooms_by_id = {r.id: r for r in placed_rooms}\n\n        cursor_y = miny\n        for zone in ordered_zones:\n            zone_height = total_height * (zone_areas[zone.zone_type] / total_area)\n            zone_box = box(minx, cursor_y, maxx, cursor_y + zone_height)\n            zone.boundary = Boundary(polygon=zone_box)\n\n            self._place_rooms_in_zone(zone, zone_box, rooms_by_id)\n            cursor_y += zone_height\n\n        return Layout(lot=lot, rooms=placed_rooms, zones=ordered_zones)\n\n    def _place_rooms_in_zone(self, zone: Zone, zone_box: Polygon, rooms_by_id: Dict) -> None:\n        minx, miny, maxx, maxy = zone_box.bounds\n        zone_width = maxx - minx\n        zone_rooms = [rooms_by_id[rid] for rid in zone.room_ids]\n\n        # Heuristica para nucleo humedo: las estancias humedas se colocan\n        # PRIMERO (extremo izquierdo) dentro de su zona. Como las zonas se\n        # apilan verticalmente en el mismo orden de X, esto alinea las\n        # estancias humedas de zonas contiguas (p.ej. cocina en dia,\n        # bano en noche) en la misma columna, maximizando la probabilidad\n        # de que compartan pared real -- sin esto, cada zona particiona su\n        # ancho de forma independiente y las estancias humedas casi nunca\n        # coinciden en X. Es una heuristica de orden, no una garantia: con\n        # 3+ estancias humedas repartidas en zonas NO mutuamente contiguas\n        # (dia y servicio nunca se tocan directamente, solo a traves de\n        # noche) sigue siendo geometricamente imposible que todas queden a\n        # distancia <=1 entre si -- eso requeriria cambiar la topologia de\n        # zonificacion (que dia/noche/servicio se toquen entre si en un\n        # punto comun), no solo el orden de colocacion.\n        zone_rooms = sorted(zone_rooms, key=lambda r: not r.is_wet)\n\n        total_area = sum(r.dimensions.area_m2 for r in zone_rooms) or 1.0\n\n        cursor_x = minx\n        for room in zone_rooms:\n            share = room.dimensions.area_m2 / total_area\n            width = zone_width * share\n            room_box = box(cursor_x, miny, cursor_x + width, maxy)\n            room.boundary = Boundary(polygon=room_box)\n            cursor_x += width\n", "housing_generator/infrastructure/algorithms/zoning/__init__.py": "", "housing_generator/infrastructure/algorithms/zoning/treemap_zoning.py": "from typing import List\nfrom collections import defaultdict\nfrom housing_generator.application.ports.zoning_strategy_port import ZoningStrategyPort\nfrom housing_generator.domain.entities.program import Program\nfrom housing_generator.domain.entities.zone import Zone\n\n\nclass TreemapZoningStrategy(ZoningStrategyPort):\n    \"\"\"Agrupa estancias en Zone segun su ZoneType declarado (dia/noche/servicio).\n\n    El dimensionado/posicionamiento de las zonas en si se deja al\n    LayoutGenerator; esta estrategia solo decide el *agrupamiento*,\n    replicando el paso clasico de 'diagrama de zonificacion' previo a\n    la traduccion a diagrama de burbujas y luego a planta.\n    \"\"\"\n\n    def build_zones(self, program: Program) -> List[Zone]:\n        grouped = defaultdict(list)\n        for room in program.rooms:\n            grouped[room.zone].append(room.id)\n\n        return [\n            Zone(zone_type=zone_type, room_ids=room_ids)\n            for zone_type, room_ids in grouped.items()\n        ]\n", "housing_generator/config/container.py": "\"\"\"Composition root: conecta las implementaciones concretas de\ninfraestructura con los casos de uso de aplicacion a traves de sus\npuertos. Este es el UNICO lugar del codebase que puede conocer a la vez\nlas clases concretas y los puertos; el resto del sistema solo conoce\ninterfaces (ports).\n\"\"\"\nfrom typing import Optional, List\nfrom housing_generator.application.use_cases.generate_layout import GenerateLayoutUseCase\nfrom housing_generator.infrastructure.algorithms.zoning.treemap_zoning import TreemapZoningStrategy\nfrom housing_generator.infrastructure.algorithms.layout_generation.simulated_annealing_generator import (\n    SimulatedAnnealingLayoutGenerator,\n)\nfrom housing_generator.infrastructure.algorithms.constraints.adjacency_validator import (\n    AdjacencyConstraintValidator,\n)\nfrom housing_generator.infrastructure.algorithms.constraints.composite_constraint_validator import (\n    CompositeConstraintValidator,\n)\nfrom housing_generator.infrastructure.algorithms.constraints.wet_core_validator import (\n    build_wet_core_validator,\n)\nfrom housing_generator.infrastructure.algorithms.constraints.day_night_zoning_validator import (\n    build_day_zone_grouping_validator,\n    build_night_zone_grouping_validator,\n    build_service_zone_grouping_validator,\n)\nfrom housing_generator.infrastructure.algorithms.constraints.estancia_minimum_area_validator import (\n    EstanciaMinimumAreaValidator,\n)\nfrom housing_generator.infrastructure.algorithms.constraints.servicio_minimum_area_validator import (\n    ServicioMinimumAreaValidator,\n)\nfrom housing_generator.infrastructure.algorithms.constraints.dormitorio_armario_validator import (\n    DormitorioArmarioValidator,\n)\nfrom housing_generator.infrastructure.algorithms.constraints.trastero_minimum_area_validator import (\n    TrasteroMinimumAreaValidator,\n)\nfrom housing_generator.infrastructure.algorithms.constraints.ancho_libre_estancia_validator import (\n    AnchoLibreEstanciaValidator,\n)\nfrom housing_generator.infrastructure.algorithms.constraints.ancho_libre_practico_validator import (\n    AnchoLibrePracticoValidator,\n)\nfrom housing_generator.infrastructure.algorithms.constraints.vivienda_accesible_validator import (\n    ViviendaAccesibleValidator,\n)\nfrom housing_generator.infrastructure.algorithms.constraints.ancho_libre_pasillo_validator import (\n    AnchoLibrePasilloValidator,\n)\nfrom housing_generator.infrastructure.algorithms.constraints.altura_libre_validator import (\n    AlturaLibreValidator,\n)\nfrom housing_generator.infrastructure.algorithms.constraints.exterior_contact_validator import (\n    ExteriorContactValidator,\n)\nfrom housing_generator.infrastructure.algorithms.constraints.cocina_integrada_validator import (\n    CocinaIntegradaValidator,\n)\nfrom housing_generator.infrastructure.algorithms.constraints.vivienda_minima_validator import (\n    ViviendaMinimaValidator,\n)\nfrom housing_generator.infrastructure.algorithms.constraints.espacio_acceso_validator import (\n    EspacioAccesoValidator,\n)\nfrom housing_generator.infrastructure.algorithms.constraints.bano_acceso_validator import (\n    BanoAccesoGeneralValidator,\n)\nfrom housing_generator.infrastructure.algorithms.constraints.escalera_ancho_libre_validator import (\n    EscaleraAnchoLibreValidator,\n)\nfrom housing_generator.infrastructure.algorithms.constraints.pasillo_topologia_validator import (\n    PasilloTopologiaValidator,\n)\nfrom housing_generator.infrastructure.algorithms.constraints.escalera_alineacion_validator import (\n    EscaleraAlineacionValidator,\n)\nfrom housing_generator.infrastructure.algorithms.constraints.nucleo_humedo_vertical_validator import (\n    NucleoHumedoVerticalValidator,\n)\nfrom housing_generator.infrastructure.algorithms.layout_generation.soft_constraint_scorer import (\n    SoftConstraintScorer,\n)\nfrom housing_generator.application.use_cases.generate_building import GenerateBuildingUseCase\nfrom housing_generator.infrastructure.algorithms.adjacency.geometry_adjacency_graph_builder import (\n    GeometryAdjacencyGraphBuilder,\n)\n\n# Umbral de adyacencia interior (pared compartida entre estancias),\n# confirmado por el usuario para el grafo de adyacencia real.\nADJACENCY_MIN_SHARED_EDGE_M = 0.1\n\n\ndef build_per_floor_validators(\n    adjacency_requirements, graph_builder, total_num_estancias=None, global_rank=None,\n    vivienda_accesible: bool = False,\n) -> List:\n    \"\"\"Validadores que tiene sentido aplicar a UNA SOLA planta (Layout).\n\n    IMPORTANTE (encontrado al construir GenerateBuildingUseCase):\n    `ViviendaMinimaValidator` (necesita ver las 6 piezas del programa\n    minimo juntas) y `BanoAccesoGeneralValidator` (podria depender de un\n    bano en OTRA planta) son de ambito de EDIFICIO, no de planta -- se\n    excluyen aqui deliberadamente y se comprueban aparte, a nivel de\n    `Building` completo (ver `generate_building.py`).\n\n    `total_num_estancias` / `global_rank`: numero y ranking de estancias\n    del EDIFICIO COMPLETO (no solo de esta planta), para que Tabla 1/2\n    elijan la fila Y el puesto correctos -- dos bugs reales encontrados\n    al generar el primer edificio de 2 plantas de prueba, ambos\n    [RESUELTOS] ahora. `None` (por defecto, caso de una sola planta)\n    preserva el comportamiento anterior: se calcula localmente, que en\n    ese caso coincide exactamente con el total/ranking del edificio.\n\n    `vivienda_accesible`: OPT-IN (por defecto False, sin cambio de\n    comportamiento) -- activa `ViviendaAccesibleValidator` (circulo de\n    giro Ø1.50m + pasillo 1.20m, DB-SUA/Base 5.4), retomado de un\n    modulo Lua de un proyecto anterior del usuario. La gran mayoria de\n    viviendas NO estan obligadas a esto, de ahi que no sea el\n    comportamiento por defecto.\n    \"\"\"\n    return [\n        AdjacencyConstraintValidator(adjacency_requirements),\n        build_wet_core_validator(graph_builder),\n        build_day_zone_grouping_validator(graph_builder),\n        build_night_zone_grouping_validator(graph_builder),\n        build_service_zone_grouping_validator(graph_builder),\n        EstanciaMinimumAreaValidator(\n            total_num_estancias_override=total_num_estancias, global_rank_override=global_rank,\n        ),\n        ServicioMinimumAreaValidator(total_num_estancias_override=total_num_estancias),\n        DormitorioArmarioValidator(),\n        TrasteroMinimumAreaValidator(),\n        AnchoLibreEstanciaValidator(),\n        AnchoLibrePracticoValidator(),\n        AnchoLibrePasilloValidator(),\n        AlturaLibreValidator(),\n        ExteriorContactValidator(),\n        CocinaIntegradaValidator(total_num_estancias_override=total_num_estancias),\n        EspacioAccesoValidator(),\n        EscaleraAnchoLibreValidator(),\n        PasilloTopologiaValidator(graph_builder),\n        ViviendaAccesibleValidator(activo=vivienda_accesible),\n    ]\n\n\ndef build_generate_layout_use_case(\n    adjacency_requirements: Optional[List] = None,\n    max_iterations: int = 2000,\n    seed: Optional[int] = None,\n    vivienda_accesible: bool = False,\n) -> GenerateLayoutUseCase:\n    \"\"\"Fabrica el caso de uso GenerateLayout con TODAS las reglas\n    construidas hasta ahora, combinadas via CompositeConstraintValidator:\n    geometria/must_be_away, nucleo humedo, zonificacion dia/noche/\n    servicio, Tabla 1 (+ cuadrado inscribible de estancia mayor), Tabla 2,\n    armario empotrado por dormitorio, trastero (B.2.5), ancho libre por\n    estancia (A.3.2.1), ancho libre de pasillo (A.3.2.3) y altura libre\n    (A.3.1.1).\n\n    `vivienda_accesible`: OPT-IN (por defecto False) -- ver docstring de\n    `build_per_floor_validators`.\n\n    Para vivienda de UNA sola planta (caso de uso original, sin cambios\n    de comportamiento): usa `build_per_floor_validators` + los dos que\n    son de ambito de edificio (`ViviendaMinimaValidator`,\n    `BanoAccesoGeneralValidator`) -- con una unica planta, \"edificio\" y\n    \"planta\" son lo mismo, asi que aplicarlos aqui sigue siendo correcto.\n\n    El generador es SimulatedAnnealingLayoutGenerator: construye un unico\n    arbol de particion sobre TODAS las estancias (sin fase previa de\n    zonificacion geometrica) y busca la mejor topologia minimizando el\n    numero de violaciones del mismo composite -- ver docs/architecture.md\n    seccion de limitaciones conocidas para el porque de este cambio.\n    \"\"\"\n    graph_builder = GeometryAdjacencyGraphBuilder(min_shared_edge_m=ADJACENCY_MIN_SHARED_EDGE_M)\n\n    validators = build_per_floor_validators(\n        adjacency_requirements, graph_builder, vivienda_accesible=vivienda_accesible,\n    ) + [\n        ViviendaMinimaValidator(),\n        BanoAccesoGeneralValidator(graph_builder),\n    ]\n    composite = CompositeConstraintValidator(validators)\n    soft_scorer = SoftConstraintScorer(adjacency_requirements or [], graph_builder)\n\n    layout_generator = SimulatedAnnealingLayoutGenerator(\n        constraint_validator=composite,\n        max_iterations=max_iterations,\n        seed=seed,\n        soft_constraint_scorer=soft_scorer,\n    )\n\n    return GenerateLayoutUseCase(\n        zoning_strategy=TreemapZoningStrategy(),\n        layout_generator=layout_generator,\n        constraint_validator=composite,\n    )\n\n\ndef build_generate_building_use_case(\n    adjacency_requirements: Optional[List] = None,\n    max_iterations: int = 2000,\n    seed: Optional[int] = None,\n    vivienda_accesible: bool = False,\n) -> GenerateBuildingUseCase:\n    \"\"\"Fabrica GenerateBuildingUseCase con las fabricas concretas\n    (per_floor_validators_factory, layout_generator_factory) ya\n    resueltas -- unico punto del sistema que conecta el caso de uso\n    multi-planta con las clases de infraestructura reales, siguiendo el\n    mismo patron que build_generate_layout_use_case.\n\n    `vivienda_accesible`: OPT-IN (por defecto False) -- ver docstring de\n    `build_per_floor_validators`. Si la vivienda tiene mas de una\n    planta, el requisito de circulo de giro/pasillo accesible se aplica\n    en TODAS las plantas por igual (la fuente Lua original distinguia\n    \"vivienda accesible duplex\" como caso aparte -- aqui no se modela\n    esa distincion, toda planta declarada accesible se comprueba igual).\n    \"\"\"\n    graph_builder = GeometryAdjacencyGraphBuilder(min_shared_edge_m=ADJACENCY_MIN_SHARED_EDGE_M)\n\n    def per_floor_validators_factory(\n        level_adjacency, reference_stair, reference_wet, total_num_estancias, global_rank, floor_below_exists,\n    ):\n        validators = build_per_floor_validators(\n            level_adjacency, graph_builder, total_num_estancias, global_rank,\n            vivienda_accesible=vivienda_accesible,\n        ) + [\n            EscaleraAlineacionValidator(\n                reference_boundary=reference_stair, floor_below_exists=floor_below_exists,\n            ),\n            NucleoHumedoVerticalValidator(reference_wet_boundaries=reference_wet),\n        ]\n        return CompositeConstraintValidator(validators)\n\n    def layout_generator_factory(composite, level_adjacency):\n        soft_scorer = SoftConstraintScorer(level_adjacency, graph_builder)\n        return SimulatedAnnealingLayoutGenerator(\n            constraint_validator=composite,\n            max_iterations=max_iterations,\n            seed=seed,\n            soft_constraint_scorer=soft_scorer,\n        )\n\n    return GenerateBuildingUseCase(\n        per_floor_validators_factory=per_floor_validators_factory,\n        layout_generator_factory=layout_generator_factory,\n        zoning_strategy=TreemapZoningStrategy(),\n        programa_minimo_validator=ViviendaMinimaValidator(),\n        bano_acceso_validator=BanoAccesoGeneralValidator(graph_builder),\n        adjacency_requirements=adjacency_requirements,\n    )\n", "housing_generator/config/__init__.py": "", "housing_generator/interface/__init__.py": "", "housing_generator/interface/cli/main.py": "\"\"\"Punto de entrada CLI: construye un Program + Lot de ejemplo y ejecuta\nel generador. Sirve como demostracion end-to-end de la arquitectura.\"\"\"\nimport argparse\nfrom shapely.geometry import box\n\nfrom housing_generator.config.container import build_generate_layout_use_case, build_generate_building_use_case\nfrom housing_generator.application.dto.generation_request import GenerationRequest\nfrom housing_generator.domain.entities.program import Program\nfrom housing_generator.domain.entities.room import Room\nfrom housing_generator.domain.entities.lot import Lot\nfrom housing_generator.domain.value_objects.dimensions import Dimensions\nfrom housing_generator.domain.value_objects.boundary import Boundary\nfrom housing_generator.domain.value_objects.adjacency import AdjacencyRequirement\nfrom housing_generator.domain.enums import RoomType, AdjacencyStrength\nfrom housing_generator.domain.exceptions import LayoutGenerationError\nfrom housing_generator.domain.services.type_adjacency_catalog import generate_adjacency_requirements\nfrom housing_generator.infrastructure.persistence.json_layout_repository import JsonLayoutRepository\nfrom housing_generator.infrastructure.persistence.seleccion_plantas_importer import import_seleccion_plantas\n\n\ndef build_sample_program(auto_adjacency: bool = False) -> Program:\n    \"\"\"`auto_adjacency=True`: en vez de la declaracion manual de abajo,\n    deriva los AdjacencyRequirement automaticamente del catalogo\n    formalizado (`generate_adjacency_requirements`) -- retomado de\n    docs/CONTINUIDAD.md (\"conectar como opcion automatica en\n    container.py/CLI\"). Mismas 11 estancias en ambos casos, solo cambia\n    de donde salen las relaciones de adyacencia.\"\"\"\n    rooms = [\n        Room(id=\"living\", name=\"Estar\", room_type=RoomType.LIVING_ROOM, dimensions=Dimensions(area_m2=25)),\n        Room(id=\"dining\", name=\"Comedor\", room_type=RoomType.DINING_ROOM, dimensions=Dimensions(area_m2=15)),\n        Room(id=\"kitchen\", name=\"Cocina\", room_type=RoomType.KITCHEN, dimensions=Dimensions(area_m2=12)),\n        Room(id=\"entrance\", name=\"Recibidor\", room_type=RoomType.ENTRANCE_HALL, dimensions=Dimensions(area_m2=5)),\n        Room(id=\"bed1\", name=\"Dormitorio principal\", room_type=RoomType.MASTER_BEDROOM, dimensions=Dimensions(area_m2=16)),\n        Room(id=\"bed2\", name=\"Dormitorio 2\", room_type=RoomType.BEDROOM, dimensions=Dimensions(area_m2=12)),\n        Room(id=\"bath1\", name=\"Bano\", room_type=RoomType.BATHROOM, dimensions=Dimensions(area_m2=6)),\n        Room(id=\"laundry\", name=\"Lavadero\", room_type=RoomType.LAUNDRY, dimensions=Dimensions(area_m2=6)),\n        Room(id=\"drying\", name=\"Tendedero\", room_type=RoomType.DRYING_AREA, dimensions=Dimensions(area_m2=2)),\n        Room(id=\"storage\", name=\"Almacen\", room_type=RoomType.STORAGE, dimensions=Dimensions(area_m2=4)),\n        Room(id=\"garage\", name=\"Garaje\", room_type=RoomType.GARAGE, dimensions=Dimensions(area_m2=18)),\n    ]\n    if auto_adjacency:\n        adjacency = generate_adjacency_requirements(rooms)\n    else:\n        adjacency = [\n            AdjacencyRequirement(\"living\", \"dining\", AdjacencyStrength.MUST_BE_NEAR),\n            AdjacencyRequirement(\"dining\", \"kitchen\", AdjacencyStrength.MUST_BE_NEAR),\n            AdjacencyRequirement(\"living\", \"entrance\", AdjacencyStrength.MUST_BE_NEAR),\n            AdjacencyRequirement(\"bath1\", \"entrance\", AdjacencyStrength.MUST_BE_NEAR),\n            AdjacencyRequirement(\"living\", \"garage\", AdjacencyStrength.MUST_BE_AWAY),\n            AdjacencyRequirement(\"bed1\", \"kitchen\", AdjacencyStrength.MUST_BE_AWAY),\n        ]\n    return Program(rooms=rooms, adjacency_requirements=adjacency)\n\n\ndef build_sample_lot() -> Lot:\n    return Lot(boundary=Boundary(polygon=box(0, 0, 14, 16)))\n\n\ndef main():\n    parser = argparse.ArgumentParser(description=\"Generador de viviendas por zonificacion dia/noche/servicio\")\n    parser.add_argument(\"--output\", default=\"layout.json\", help=\"Ruta de salida del layout generado\")\n    parser.add_argument(\n        \"--seed\", type=int, default=1,\n        help=\"Semilla del recocido simulado (por defecto 1, fija -- determinista. \"\n             \"Estable de nuevo tras anadir la heuristica de 'cortar por el lado mas \"\n             \"largo' -- Marson & Musse 2010 -- que redujo la aparicion de estancias \"\n             \"como tiras finas lo suficiente para que la semilla 1 volviera a \"\n             \"converger facil). Usa otro valor para explorar variantes distintas.\",\n    )\n    parser.add_argument(\"--max-iterations\", type=int, default=3000, help=\"Iteraciones del recocido simulado\")\n    parser.add_argument(\n        \"--auto-adjacency\", action=\"store_true\",\n        help=\"Derivar Obligatorio/Preferencia automaticamente del catalogo formalizado \"\n             \"de 120 pares (generate_adjacency_requirements) en vez de la declaracion \"\n             \"manual del programa de ejemplo -- genera bastantes mas requisitos \"\n             \"(44 en vez de 6 para las mismas 11 estancias), busqueda mas dificil, \"\n             \"puede necesitar --max-iterations mayor o probar otra --seed.\",\n    )\n    parser.add_argument(\n        \"--vivienda-accesible\", action=\"store_true\",\n        help=\"Exigir circulo de giro Ø1.50m en estancias habitables + bano, y pasillo \"\n             \"≥1.20m (mas exigente que el general 1.00m) -- DB-SUA Anejo A + Base 5.4 \"\n             \"Galicia (vivienda adaptada para usuarios de silla de ruedas). OPT-IN: la \"\n             \"gran mayoria de viviendas NO estan obligadas a esto. Retomado de un modulo \"\n             \"Lua de un proyecto anterior del usuario (accesibilidad.lua) -- solo cubre \"\n             \"lo geometricamente verificable con este proyecto (circulo/ancho), no \"\n             \"mobiliario (altura de encimera, aproximacion a la cama...), que no se \"\n             \"modela aqui.\",\n    )\n    parser.add_argument(\n        \"--import-seleccion\", metavar=\"RUTA\", default=None,\n        help=\"Importar 'seleccion_plantas.json' (exportacion del dashboard) en vez del \"\n             \"programa de ejemplo -- genera un edificio multi-planta real. Con el formato \"\n             \"nuevo (version 2) usa la cantidad y area reales declaradas en el dashboard; \"\n             \"con el formato antiguo (solo nombres de tipo), usa AREAS_POR_DEFECTO_M2 como \"\n             \"aproximacion generica -- revisar antes de un proyecto real en ese caso. \"\n             \"'tipo_vivienda' del JSON (aislada/pareada/adosada) se traduce automaticamente \"\n             \"a Lot.medianera_sides. Ignora --auto-adjacency (las adyacencias siempre se \"\n             \"derivan del catalogo aqui).\",\n    )\n    parser.add_argument(\n        \"--retry-seeds\", type=int, default=5,\n        help=\"Con --import-seleccion, cuantas semillas distintas probar automaticamente \"\n             \"(empezando en --seed, incrementando de 1 en 1) antes de rendirse -- \"\n             \"retomado de un caso real: la primera semilla de un programa concreto no \"\n             \"convergio, la 4a si. Los programas que salen de --import-seleccion no estan \"\n             \"curados a mano (a diferencia del ejemplo del CLI), asi que necesitan mas \"\n             \"margen de busqueda de forma habitual, no como excepcion. Poner a 1 para \"\n             \"desactivar el reintento y usar solo --seed tal cual.\",\n    )\n    parser.add_argument(\n        \"--lot-size\", metavar=\"ANCHOxFONDO\", default=None,\n        help=\"Con --import-seleccion, tamano de parcela en metros (p.ej. '14x16') en vez \"\n             \"del tamano de ejemplo por defecto (14x16, el mismo valor) -- util para \"\n             \"acercarse al tamano real de tu parcela, o para dar mas margen si el \"\n             \"programa importado es grande.\",\n    )\n    args = parser.parse_args()\n\n    if args.import_seleccion:\n        seleccion = import_seleccion_plantas(args.import_seleccion)\n        program = seleccion.program\n        if args.lot_size:\n            w_str, h_str = args.lot_size.lower().split(\"x\")\n            lot = Lot(\n                boundary=Boundary(polygon=box(0, 0, float(w_str), float(h_str))),\n                medianera_sides=seleccion.medianera_sides,\n            )\n        else:\n            base_lot = build_sample_lot()\n            lot = Lot(boundary=base_lot.boundary, medianera_sides=seleccion.medianera_sides)\n        if seleccion.medianera_sides:\n            print(f\"(tipo_vivienda del JSON -> medianera en: {', '.join(sorted(seleccion.medianera_sides))})\")\n\n        building = None\n        last_error = None\n        for attempt in range(max(1, args.retry_seeds)):\n            seed = args.seed + attempt\n            use_case = build_generate_building_use_case(\n                adjacency_requirements=program.adjacency_requirements,\n                seed=seed,\n                max_iterations=args.max_iterations,\n                vivienda_accesible=args.vivienda_accesible,\n            )\n            try:\n                building = use_case.execute(program, lot)\n                if attempt > 0:\n                    print(f\"(semilla {args.seed} no convergio, funciono con semilla {seed} \"\n                          f\"tras {attempt + 1} intentos)\")\n                break\n            except LayoutGenerationError as e:\n                last_error = e\n        if building is None:\n            raise SystemExit(\n                f\"No se pudo generar tras probar {args.retry_seeds} semillas \"\n                f\"(desde {args.seed} hasta {args.seed + args.retry_seeds - 1}). \"\n                f\"Ultimo error: {last_error}\"\n            )\n\n        for level, layout in building.floors.items():\n            output_path = args.output.replace(\".json\", f\"_{level.value}.json\")\n            JsonLayoutRepository().save(layout, output_path, adjacency_requirements=program.adjacency_requirements)\n            print(f\"Planta '{level.value}' generada y guardada en {output_path}\")\n            for room in layout.rooms:\n                b = room.boundary.polygon.bounds\n                print(f\"  - {room.name:22s} zona={room.zone.value:8s} bounds=({b[0]:.1f}, {b[1]:.1f}, {b[2]:.1f}, {b[3]:.1f})\")\n        return\n\n    program = build_sample_program(auto_adjacency=args.auto_adjacency)\n    lot = build_sample_lot()\n\n    use_case = build_generate_layout_use_case(\n        adjacency_requirements=program.adjacency_requirements,\n        seed=args.seed,\n        max_iterations=args.max_iterations,\n        vivienda_accesible=args.vivienda_accesible,\n    )\n    layout = use_case.execute(GenerationRequest(program=program, lot=lot))\n\n    JsonLayoutRepository().save(layout, args.output, adjacency_requirements=program.adjacency_requirements)\n\n    print(f\"Layout generado y guardado en {args.output}\\n\")\n    for room in layout.rooms:\n        b = room.boundary.polygon.bounds\n        print(f\"  - {room.name:22s} zona={room.zone.value:8s} bounds=({b[0]:.1f}, {b[1]:.1f}, {b[2]:.1f}, {b[3]:.1f})\")\n\n\nif __name__ == \"__main__\":\n    main()\n", "housing_generator/interface/cli/__init__.py": "", "housing_generator/application/__init__.py": "", "housing_generator/application/dto/__init__.py": "", "housing_generator/application/dto/validation_result.py": "from dataclasses import dataclass, field\nfrom typing import List\n\n\n@dataclass(frozen=True)\nclass ValidationResult:\n    \"\"\"Resultado de validar un Layout contra una restriccion.\n\n    Separa dos cosas que `nhv.lua` ya distinguia en varios sitios\n    (`esEspacioExteriorDeCalidad`, y ahora `can_inscribe_square`) y que\n    una simple `List[str]` de violaciones no puede expresar:\n\n    - `violations`: la restriccion NO se cumple, con los datos disponibles.\n      Un layout con violaciones se rechaza.\n    - `warnings`: no se puede confirmar NI descartar el cumplimiento con\n      los datos/algoritmos disponibles (\"no verificable\"). Nunca se trata\n      como aprobado por defecto, pero tampoco bloquea la generacion como\n      una violacion real -- es una tercera categoria, no un termino medio\n      entre las otras dos.\n    \"\"\"\n    violations: List[str] = field(default_factory=list)\n    warnings: List[str] = field(default_factory=list)\n\n    @property\n    def is_valid(self) -> bool:\n        return len(self.violations) == 0\n\n    @staticmethod\n    def merge(results: List[\"ValidationResult\"]) -> \"ValidationResult\":\n        violations: List[str] = []\n        warnings: List[str] = []\n        for result in results:\n            violations.extend(result.violations)\n            warnings.extend(result.warnings)\n        return ValidationResult(violations=violations, warnings=warnings)\n", "housing_generator/application/dto/generation_request.py": "from dataclasses import dataclass\nfrom housing_generator.domain.entities.program import Program\nfrom housing_generator.domain.entities.lot import Lot\n\n\n@dataclass(frozen=True)\nclass GenerationRequest:\n    \"\"\"DTO de entrada del caso de uso GenerateLayoutUseCase.\"\"\"\n    program: Program\n    lot: Lot\n    max_attempts: int = 1\n", "housing_generator/application/use_cases/generate_layout.py": "from housing_generator.application.dto.generation_request import GenerationRequest\nfrom housing_generator.application.ports.zoning_strategy_port import ZoningStrategyPort\nfrom housing_generator.application.ports.layout_generator_port import LayoutGeneratorPort\nfrom housing_generator.application.ports.constraint_validator_port import ConstraintValidatorPort\nfrom housing_generator.domain.entities.layout import Layout\nfrom housing_generator.domain.exceptions import LayoutGenerationError\n\n\nclass GenerateLayoutUseCase:\n    \"\"\"Orquesta zonificacion -> colocacion -> validacion para producir un\n    Layout valido.\n\n    Las dependencias se inyectan como puertos (interfaces), asi que el\n    algoritmo concreto (zonificacion por treemap, generador por grafos,\n    genetico...) puede cambiarse sin tocar este caso de uso (principio\n    de inversion de dependencias). `constraint_validator` puede ser un\n    unico validador o un CompositeConstraintValidator que agrupe varios.\n    \"\"\"\n\n    def __init__(\n        self,\n        zoning_strategy: ZoningStrategyPort,\n        layout_generator: LayoutGeneratorPort,\n        constraint_validator: ConstraintValidatorPort,\n    ):\n        self._zoning_strategy = zoning_strategy\n        self._layout_generator = layout_generator\n        self._constraint_validator = constraint_validator\n\n    def execute(self, request: GenerationRequest) -> Layout:\n        zones = self._zoning_strategy.build_zones(request.program)\n\n        last_result = None\n        for _ in range(max(1, request.max_attempts)):\n            layout = self._layout_generator.generate(request.program, request.lot, zones)\n            result = self._constraint_validator.validate(layout)\n            if result.is_valid:\n                layout.metadata[\"violations\"] = 0\n                layout.metadata[\"warnings\"] = len(result.warnings)\n                return layout\n            last_result = result\n\n        last_violations = last_result.violations if last_result else []\n        raise LayoutGenerationError(\n            f\"No se pudo generar un layout valido tras {request.max_attempts} intento(s). \"\n            f\"Ultimas violaciones: {last_violations}\"\n        )\n", "housing_generator/application/use_cases/__init__.py": "", "housing_generator/application/use_cases/validate_layout.py": "from housing_generator.application.ports.constraint_validator_port import ConstraintValidatorPort\nfrom housing_generator.application.dto.validation_result import ValidationResult\nfrom housing_generator.domain.entities.layout import Layout\n\n\nclass ValidateLayoutUseCase:\n    def __init__(self, constraint_validator: ConstraintValidatorPort):\n        self._constraint_validator = constraint_validator\n\n    def execute(self, layout: Layout) -> ValidationResult:\n        return self._constraint_validator.validate(layout)\n", "housing_generator/application/use_cases/generate_building.py": "from typing import Callable, Dict, List, Optional\nfrom shapely.geometry.base import BaseGeometry\nfrom housing_generator.application.ports.zoning_strategy_port import ZoningStrategyPort\nfrom housing_generator.application.ports.layout_generator_port import LayoutGeneratorPort\nfrom housing_generator.application.ports.constraint_validator_port import ConstraintValidatorPort\nfrom housing_generator.domain.entities.building import Building\nfrom housing_generator.domain.entities.program import Program\nfrom housing_generator.domain.entities.lot import Lot\nfrom housing_generator.domain.entities.room import Room\nfrom housing_generator.domain.entities.layout import Layout\nfrom housing_generator.domain.value_objects.boundary import Boundary\nfrom housing_generator.domain.enums import NivelPlanta, NIVEL_PLANTA_ORDEN, RoomType, SpaceCategory\nfrom housing_generator.domain.exceptions import LayoutGenerationError\nfrom housing_generator.domain.value_objects.adjacency import AdjacencyRequirement\n\n# Firma de la fabrica de validadores por planta: recibe los requisitos\n# de adyacencia de ESA planta, la huella de escalera de referencia de la\n# planta inferior (o None), la lista de huellas humedas de referencia\n# (o vacia), y el numero TOTAL de estancias del EDIFICIO COMPLETO (para\n# que Tabla 1/2 elijan la fila correcta -- bug real encontrado al\n# generar el primer edificio de prueba: sin esto, una planta con pocas\n# estancias aplicaba una fila de Tabla 1/2 mas baja de la que\n# corresponderia con el conteo real del edificio). Devuelve el\n# validador COMPLETO (compuesto) para esa planta. Se inyecta como\n# funcion, no como clases concretas, para que esta capa de aplicacion no\n# dependa de infraestructura (regla ya establecida en\n# GenerateLayoutUseCase -- se encontro y corrigio aqui una violacion\n# real de esa regla durante la construccion de este caso de uso: la\n# primera version importaba directamente de config.container).\nPerFloorValidatorsFactory = Callable[\n    [List[AdjacencyRequirement], Optional[BaseGeometry], List[BaseGeometry], int, Dict[str, int], bool],\n    ConstraintValidatorPort,\n]\nLayoutGeneratorFactory = Callable[[ConstraintValidatorPort, List[AdjacencyRequirement]], LayoutGeneratorPort]\n\n\nclass GenerateBuildingUseCase:\n    \"\"\"Orquesta la generacion de una vivienda de VARIAS plantas: agrupa\n    `program.rooms` por `Room.level`, genera cada planta de abajo a\n    arriba (una busqueda independiente por planta, no conjunta -- ver\n    docs/architecture.md), encadenando dos restricciones ENTRE plantas\n    consecutivas a traves de `per_floor_validators_factory`:\n    - alineacion de huella de escalera con la planta de abajo YA\n      RESUELTA (pasada como referencia fija -- no hace falta busqueda\n      conjunta ni un tipo de movimiento nuevo en el recocido simulado).\n    - continuidad vertical de nucleo humedo (solape en planta con alguna\n      humeda de la planta inferior).\n\n    Primer incremento deliberadamente simplificado (ver\n    docs/architecture.md): TODAS las plantas comparten el mismo\n    `lot.buildable_area`; el programa minimo de vivienda se comprueba\n    UNA sola vez, a nivel de EDIFICIO completo (uniendo los tipos de\n    todas las plantas), no por planta -- una vivienda de dos plantas con\n    salon abajo y bano arriba SI cumple el programa minimo, aunque\n    ninguna planta por separado lo cumpla.\n    \"\"\"\n\n    def __init__(\n        self,\n        per_floor_validators_factory: PerFloorValidatorsFactory,\n        layout_generator_factory: LayoutGeneratorFactory,\n        zoning_strategy: ZoningStrategyPort,\n        programa_minimo_validator: ConstraintValidatorPort,\n        bano_acceso_validator: ConstraintValidatorPort,\n        adjacency_requirements: Optional[List[AdjacencyRequirement]] = None,\n    ):\n        self._per_floor_validators_factory = per_floor_validators_factory\n        self._layout_generator_factory = layout_generator_factory\n        self._zoning_strategy = zoning_strategy\n        self._programa_minimo_validator = programa_minimo_validator\n        self._bano_acceso_validator = bano_acceso_validator\n        self._adjacency_requirements = adjacency_requirements or []\n\n    def execute(self, program: Program, lot: Lot) -> Building:\n        rooms_by_level = self._group_by_level(program.rooms)\n        levels = [lvl for lvl in NIVEL_PLANTA_ORDEN if lvl in rooms_by_level]\n        total_num_estancias = sum(1 for r in program.rooms if r.space_category == SpaceCategory.ESTANCIA)\n        global_rank = self._compute_global_rank(program.rooms)\n\n        building = Building()\n        previous_layout: Optional[Layout] = None\n        current_buildable_polygon: BaseGeometry = lot.buildable_area.polygon\n\n        for level in levels:\n            level_rooms = rooms_by_level[level]\n            level_room_ids = {r.id for r in level_rooms}\n            level_adjacency = [\n                req for req in self._adjacency_requirements\n                if req.room_a_id in level_room_ids and req.room_b_id in level_room_ids\n            ]\n            level_program = Program(rooms=level_rooms, adjacency_requirements=level_adjacency)\n\n            reference_stair = self._staircase_boundary(previous_layout)\n            reference_wet = self._wet_boundaries(previous_layout)\n            floor_below_exists = previous_layout is not None\n\n            # encogimiento progresivo del contorno edificable (retomado\n            # de docs/CONTINUIDAD.md) -- solo a partir de la SEGUNDA\n            # planta (la primera usa siempre lot.buildable_area sin\n            # tocar); ver Lot.retranqueo_incremento_por_planta_m para\n            # la investigacion que respalda esta tecnica.\n            if floor_below_exists:\n                current_buildable_polygon = self._shrink_for_next_floor(\n                    current_buildable_polygon, lot.retranqueo_incremento_por_planta_m, level_rooms,\n                )\n            floor_lot = Lot(\n                boundary=Boundary(polygon=current_buildable_polygon),\n                entrance_side=lot.entrance_side,\n                street_side=lot.street_side,\n                retranqueo_m=None,  # ya aplicado al construir current_buildable_polygon\n            )\n\n            composite = self._per_floor_validators_factory(\n                level_adjacency, reference_stair, reference_wet, total_num_estancias, global_rank,\n                floor_below_exists,\n            )\n            generator = self._layout_generator_factory(composite, level_adjacency)\n            zones = self._zoning_strategy.build_zones(level_program)\n            layout = generator.generate(level_program, floor_lot, zones)\n\n            result = composite.validate(layout)\n            if not result.is_valid:\n                raise LayoutGenerationError(\n                    f\"No se pudo generar un layout valido para la planta '{level.value}'. \"\n                    f\"Ultimas violaciones: {result.violations}\"\n                )\n\n            building.floors[level] = layout\n            previous_layout = layout\n\n        self._check_programa_minimo(building)\n        self._check_bano_acceso_general(building)\n        return building\n\n    @staticmethod\n    def _shrink_for_next_floor(\n        previous_polygon: BaseGeometry, increment_m: Optional[float], level_rooms: List[Room],\n    ) -> BaseGeometry:\n        \"\"\"Encoge el contorno de la planta anterior por `increment_m`\n        para esta planta -- mismo mecanismo que `Lot.buildable_area`\n        (`buffer(-x)`), aplicado de forma progresiva planta a planta.\n\n        Red de seguridad (investigacion externa confirmada, patron\n        `MinArea{Action:Shrink, Fallback:...}`): si el area encogida no\n        alcanzaria para la suma de superficies declaradas de esta\n        planta, NO se encoge -- se usa la misma huella que la planta de\n        abajo (la otra opcion valida segun la propia investigacion:\n        \"copia exacta O subconjunto\", nunca una huella inviable).\"\"\"\n        if increment_m is None or increment_m <= 0:\n            return previous_polygon\n\n        shrunk = previous_polygon.buffer(-increment_m)\n        required_area = sum(r.dimensions.area_m2 for r in level_rooms)\n        if shrunk.area < required_area:\n            return previous_polygon  # red de seguridad: copia exacta, no un area inviable\n        return shrunk\n\n    @staticmethod\n    def _compute_global_rank(rooms: List[Room]) -> Dict[str, int]:\n        \"\"\"Puesto de Tabla 1 (1=mayor) de cada estancia entre TODAS las\n        del edificio, precalculado antes de generar ninguna planta --\n        las areas son DECLARADAS en el Program, no dependen de la\n        geometria ya colocada, asi que esto se puede saber de antemano.\"\"\"\n        estancias = [r for r in rooms if r.space_category == SpaceCategory.ESTANCIA]\n        ordenadas = sorted(estancias, key=lambda r: r.dimensions.area_m2, reverse=True)\n        return {room.id: puesto for puesto, room in enumerate(ordenadas, start=1)}\n\n    @staticmethod\n    def _group_by_level(rooms: List[Room]) -> Dict[NivelPlanta, List[Room]]:\n        grouped: Dict[NivelPlanta, List[Room]] = {}\n        for room in rooms:\n            level = room.level or NivelPlanta.PLANTA_BAJA\n            grouped.setdefault(level, []).append(room)\n        return grouped\n\n    @staticmethod\n    def _staircase_boundary(layout: Optional[Layout]) -> Optional[BaseGeometry]:\n        if layout is None:\n            return None\n        for room in layout.rooms:\n            if room.room_type == RoomType.STAIRCASE and room.is_placed:\n                return room.boundary.polygon\n        return None\n\n    @staticmethod\n    def _wet_boundaries(layout: Optional[Layout]) -> List[BaseGeometry]:\n        if layout is None:\n            return []\n        return [r.boundary.polygon for r in layout.rooms if r.is_wet and r.is_placed]\n\n    def _check_bano_acceso_general(self, building: Building) -> None:\n        \"\"\"Reutiliza EL MISMO validador que ya existe para una sola\n        planta (`bano_acceso_validator`), ejecutandolo POR PLANTA con el\n        grafo de adyacencia real de esa planta -- la accesibilidad\n        general de un bano no se \"hereda\" magicamente de otra planta, se\n        necesita conexion directa a circulacion EN LA MISMA PLANTA. A\n        nivel de EDIFICIO basta con que UNA planta con banos tenga\n        alguno accesible; las demas pueden ser todo en-suite.\n\n        Corrige un hueco real senalado explicitamente en el incremento\n        anterior: antes, esta regla no se comprobaba EN ABSOLUTO en modo\n        multi-planta (ni por planta ni a nivel de edificio) -- una\n        vivienda podia generarse con todos los banos en-suite sin que\n        nada lo detectara.\"\"\"\n        any_bathroom_anywhere = any(\n            r.room_type == RoomType.BATHROOM for layout in building.floors.values() for r in layout.rooms\n        )\n        if not any_bathroom_anywhere:\n            return  # ninguna planta tiene banos -- ViviendaMinimaValidator ya lo habria bloqueado antes\n\n        for layout in building.floors.values():\n            has_bathroom_here = any(r.room_type == RoomType.BATHROOM for r in layout.rooms)\n            if not has_bathroom_here:\n                continue\n            if self._bano_acceso_validator.validate(layout).is_valid:\n                return  # esta planta ya tiene al menos un bano con acceso general -- suficiente\n\n        raise LayoutGenerationError(\n            \"Ninguna planta del edificio tiene un baño con acceso directo a circulación \"\n            \"general (CORRIDOR/ENTRANCE_HALL) -- con varias plantas, todos los baños \"\n            \"quedarían en-suite, sin ninguno de acceso general para el conjunto de la vivienda\"\n        )\n\n    def _check_programa_minimo(self, building: Building) -> None:\n        # BUG REAL encontrado en auditoria de logica: este metodo tenia\n        # su cuerpo ENTERO duplicado (dos veces seguidas, idéntico) --\n        # probablemente residuo de una edicion anterior en la que se\n        # perdio y se restauro el metodo (ver el incremento de\n        # \"acceso general de bano a nivel de edificio\", donde un\n        # str_replace se comio este cuerpo por error). No cambiaba el\n        # resultado (idempotente), pero es codigo real duplicado sin\n        # motivo, ni pyflakes ni mypy lo detectan.\n        all_rooms = [room for layout in building.floors.values() for room in layout.rooms]\n        synthetic_layout = Layout(\n            lot=next(iter(building.floors.values())).lot,\n            rooms=all_rooms,\n            zones=[],\n        )\n        result = self._programa_minimo_validator.validate(synthetic_layout)\n        if not result.is_valid:\n            raise LayoutGenerationError(\n                f\"El edificio completo no cumple el programa minimo de vivienda \"\n                f\"(comprobado uniendo todas las plantas): {result.violations}\"\n            )\n", "housing_generator/application/use_cases/build_adjacency_graph.py": "import networkx as nx\nfrom housing_generator.domain.entities.program import Program\n\n\nclass BuildAdjacencyGraphUseCase:\n    \"\"\"Convierte los requisitos de adyacencia de un Program en un grafo\n    ponderado: la estructura de datos detras del clasico 'diagrama de\n    burbujas' que usan los arquitectos en la fase de programacion.\"\"\"\n\n    _WEIGHTS = {\n        \"must_be_near\": 3,\n        \"should_be_near\": 2,\n        \"indifferent\": 1,\n        \"must_be_away\": -3,\n    }\n\n    def execute(self, program: Program) -> nx.Graph:\n        graph = nx.Graph()\n        for room in program.rooms:\n            graph.add_node(room.id, name=room.name, room_type=room.room_type, zone=room.zone)\n\n        for req in program.adjacency_requirements:\n            weight = self._WEIGHTS[req.strength.value]\n            graph.add_edge(req.room_a_id, req.room_b_id, weight=weight, strength=req.strength)\n\n        return graph\n", "housing_generator/application/ports/__init__.py": "", "housing_generator/application/ports/adjacency_graph_builder_port.py": "from abc import ABC, abstractmethod\nimport networkx as nx\nfrom housing_generator.domain.entities.layout import Layout\n\n\nclass AdjacencyGraphBuilderPort(ABC):\n    \"\"\"Construye el grafo de adyacencia REAL a partir de la geometria ya\n    generada de un Layout (quien toca a quien de verdad).\n\n    Distinto de BuildAdjacencyGraphUseCase: aquel construye un grafo a\n    partir de AdjacencyRequirement (intencion declarada antes de generar);\n    este se construye a partir del resultado geometrico ya colocado.\n    \"\"\"\n\n    @abstractmethod\n    def build(self, layout: Layout) -> nx.Graph:\n        ...\n", "housing_generator/application/ports/zoning_strategy_port.py": "from abc import ABC, abstractmethod\nfrom typing import List\nfrom housing_generator.domain.entities.program import Program\nfrom housing_generator.domain.entities.zone import Zone\n\n\nclass ZoningStrategyPort(ABC):\n    \"\"\"Agrupa las estancias de un programa en macro-zonas (dia/noche/servicio).\n\n    Puerto (interfaz) segun arquitectura hexagonal: la capa de aplicacion\n    depende de esta abstraccion, nunca de una implementacion concreta.\n    \"\"\"\n\n    @abstractmethod\n    def build_zones(self, program: Program) -> List[Zone]:\n        ...\n", "housing_generator/application/ports/layout_generator_port.py": "from abc import ABC, abstractmethod\nfrom typing import List\nfrom housing_generator.domain.entities.program import Program\nfrom housing_generator.domain.entities.lot import Lot\nfrom housing_generator.domain.entities.zone import Zone\nfrom housing_generator.domain.entities.layout import Layout\n\n\nclass LayoutGeneratorPort(ABC):\n    \"\"\"Coloca las estancias de un programa dentro de un solar, respetando\n    las zonas dadas. Distintas estrategias (slicing, grafos, geneticos,\n    CSP...) implementan este mismo puerto y son intercambiables.\"\"\"\n\n    @abstractmethod\n    def generate(self, program: Program, lot: Lot, zones: List[Zone]) -> Layout:\n        ...\n", "housing_generator/application/ports/layout_repository_port.py": "from abc import ABC, abstractmethod\nfrom typing import List, Optional\nfrom housing_generator.domain.entities.layout import Layout\nfrom housing_generator.domain.value_objects.adjacency import AdjacencyRequirement\n\n\nclass LayoutRepositoryPort(ABC):\n    \"\"\"Persistencia de layouts generados (JSON, base de datos, etc.).\"\"\"\n\n    @abstractmethod\n    def save(\n        self, layout: Layout, path: str,\n        adjacency_requirements: Optional[List[AdjacencyRequirement]] = None,\n    ) -> None:\n        ...\n\n    @abstractmethod\n    def load(self, path: str) -> Layout:\n        ...\n", "housing_generator/application/ports/constraint_validator_port.py": "from abc import ABC, abstractmethod\nfrom housing_generator.domain.entities.layout import Layout\nfrom housing_generator.application.dto.validation_result import ValidationResult\n\n\nclass ConstraintValidatorPort(ABC):\n    \"\"\"Valida un Layout contra restricciones duras/blandas.\"\"\"\n\n    @abstractmethod\n    def validate(self, layout: Layout) -> ValidationResult:\n        ...\n", "housing_generator/domain/__init__.py": "", "housing_generator/domain/exceptions.py": "\"\"\"Excepciones propias del dominio. Nunca se deben lanzar excepciones\ngenericas (ValueError, Exception) desde la capa de dominio o aplicacion;\nusar siempre estas clases o subclases especificas de infraestructura.\"\"\"\n\n\nclass HousingGeneratorError(Exception):\n    \"\"\"Excepcion base de todo el sistema.\"\"\"\n\n\nclass InvalidProgramError(HousingGeneratorError):\n    \"\"\"El programa (lista de estancias + requisitos) es inconsistente.\"\"\"\n\n\nclass LayoutGenerationError(HousingGeneratorError):\n    \"\"\"No se pudo generar un layout valido para un programa/solar dados.\"\"\"\n\n\nclass ConstraintViolationError(HousingGeneratorError):\n    \"\"\"Un layout generado viola una restriccion dura.\"\"\"\n", "housing_generator/domain/enums.py": "\"\"\"Enumeraciones y mapeos base del dominio de zonificacion residencial.\"\"\"\nfrom enum import Enum\n\n\nclass ZoneType(str, Enum):\n    \"\"\"Macro-zonas segun grado de privacidad y horario de uso.\n\n    Es la division clasica que emplea el diseno residencial: social/dia,\n    privada/noche y de servicio. CIRCULATION es distinta de las otras\n    tres: no es una macro-zona de uso, es la clasificacion honesta para\n    estancias que no pertenecen a ninguna (ver mas abajo, CORRIDOR y\n    ENTRANCE_HALL) -- una circulacion sirve a varias zonas a la vez, y\n    forzarla a DAY por defecto era un dato falso (encontrado en\n    auditoria: generaba violaciones falsas de zonificacion cuando un\n    pasillo servia correctamente a la zona noche).\n    \"\"\"\n    DAY = \"day\"          # Social/publica: estar, comedor, cocina abierta, acceso\n    NIGHT = \"night\"       # Privada: dormitorios, banos privados\n    SERVICE = \"service\"   # Servicio: lavadero, trasteros, garaje, cuarto tecnico\n    CIRCULATION = \"circulation\"  # Vestibulo/pasillo: sirve a varias zonas, no es una\n\n\nclass RoomType(str, Enum):\n    LIVING_ROOM = \"living_room\"\n    DINING_ROOM = \"dining_room\"\n    KITCHEN = \"kitchen\"\n    BEDROOM = \"bedroom\"\n    MASTER_BEDROOM = \"master_bedroom\"\n    BATHROOM = \"bathroom\"\n    TOILET = \"toilet\"              # aseo: sin banera/ducha, min. distinto al de BATHROOM\n    ENTRANCE_HALL = \"entrance_hall\"\n    STUDY = \"study\"\n    LAUNDRY = \"laundry\"\n    DRYING_AREA = \"drying_area\"    # tendedero\n    STORAGE = \"storage\"            # almacenamiento general (Tabla 2: despensa, ropa de cama...)\n    STORAGE_ROOM = \"storage_room\"  # trastero (B.2.5: regla fija, objetos/trastos, distinto de almacenamiento)\n    GARAGE = \"garage\"\n    TECHNICAL_ROOM = \"technical_room\"\n    CORRIDOR = \"corridor\"\n    STAIRCASE = \"staircase\"        # escalera interior -- conecta dos plantas, huella debe alinearse entre ambas\n\n\nclass AdjacencyStrength(str, Enum):\n    \"\"\"Fuerza de un requisito de adyacencia, siguiendo la matriz clasica\n    'debe estar cerca / deberia estar cerca / indiferente / deberia\n    estar lejos / debe estar lejos'.\n\n    SHOULD_BE_NEAR/SHOULD_BE_AWAY (\"Preferencia cerca/alejar\" del\n    catalogo de relaciones_espaciales.md) usan una METRICA DISTINTA a\n    MUST_BE_NEAR/MUST_BE_AWAY -- saltos en el grafo de adyacencia\n    (cerca objetivo <=2, alejar objetivo >=3), no contacto geometrico\n    directo. Decision deliberada (ver architecture.md): no unificar\n    metricas para no perder la precision de \"ancho de puerta\" (1.0m)\n    que ya tiene MUST_BE_NEAR. Ver SoftConstraintScorer.\"\"\"\n    MUST_BE_NEAR = \"must_be_near\"\n    SHOULD_BE_NEAR = \"should_be_near\"\n    INDIFFERENT = \"indifferent\"\n    SHOULD_BE_AWAY = \"should_be_away\"\n    MUST_BE_AWAY = \"must_be_away\"\n\n\n# Zona por defecto de cada tipo de estancia, editable por el llamador\n# (Room.zone se puede sobreescribir explicitamente).\n# CORRIDOR y ENTRANCE_HALL -> CIRCULATION, no DAY: son circulacion, no\n# pertenecen a una macro-zona de uso (ver ZoneType.CIRCULATION arriba).\n# TOILET -> DAY: es un supuesto de diseno (aseo de cortesia, tipicamente\n# cerca del acceso/zona dia para visitas), no una regla normativa -- si\n# tu programa necesita un aseo en zona noche, sobreescribe `zone` a mano.\nDEFAULT_ROOM_ZONE = {\n    RoomType.LIVING_ROOM: ZoneType.DAY,\n    RoomType.DINING_ROOM: ZoneType.DAY,\n    RoomType.KITCHEN: ZoneType.DAY,\n    RoomType.ENTRANCE_HALL: ZoneType.CIRCULATION,\n    RoomType.STUDY: ZoneType.DAY,\n    RoomType.CORRIDOR: ZoneType.CIRCULATION,\n    RoomType.STAIRCASE: ZoneType.CIRCULATION,\n    RoomType.TOILET: ZoneType.DAY,\n    RoomType.BEDROOM: ZoneType.NIGHT,\n    RoomType.MASTER_BEDROOM: ZoneType.NIGHT,\n    RoomType.BATHROOM: ZoneType.NIGHT,\n    RoomType.LAUNDRY: ZoneType.SERVICE,\n    RoomType.DRYING_AREA: ZoneType.SERVICE,\n    RoomType.STORAGE: ZoneType.SERVICE,\n    RoomType.STORAGE_ROOM: ZoneType.SERVICE,\n    RoomType.GARAGE: ZoneType.SERVICE,\n    RoomType.TECHNICAL_ROOM: ZoneType.SERVICE,\n}\n\n\n# \"Local humedo\": estancias con conexion a fontaneria/saneamiento (agua\n# corriente + desague). Confirmado por normativa (CTE DB-HS distingue\n# \"locales secos\" de \"locales humedos\": cocinas, banos, aseos) y por\n# practica de proyecto de fontaneria (cada local humedo lleva su propia\n# llave de corte independiente: banos, aseos, cocinas, cuartos de lavado).\n# `tendedero` se deja fuera por defecto: normalmente es prolongacion del\n# lavadero sin desague propio, no un punto de agua independiente.\nDEFAULT_WET_ROOMS = {\n    RoomType.KITCHEN,\n    RoomType.BATHROOM,\n    RoomType.TOILET,\n    RoomType.LAUNDRY,\n}\n\n\nclass SpaceCategory(str, Enum):\n    \"\"\"Clasificacion normativa para superficie minima (Tabla 1 vs Tabla 2):\n    que cuenta como \"estancia\" (Tabla 1: pieza habitable sin instalaciones\n    propias -- estar, comedor, dormitorios, despacho) frente a \"servicio\"\n    (Tabla 2: cocina, bano, aseo, lavadero, tendedero, almacenamiento --\n    escalan con el numero de estancias, no por puesto de tamano) y\n    \"circulacion\" (vestibulo/pasillo: reglas de anchura, no de superficie).\n    Confirmado contra Decreto 29/2010 (Galicia) y normativas municipales:\n    cocina es \"pieza vividera\" (categoria A.1.1, luz/exterior) pero NO es\n    \"estancia\" a efectos de Tabla 1 -- son dos clasificaciones distintas.\n    \"\"\"\n    ESTANCIA = \"estancia\"\n    SERVICIO = \"servicio\"\n    CIRCULACION = \"circulacion\"\n    OTROS = \"otros\"  # garaje, cuarto tecnico... fuera de Tabla 1 y Tabla 2\n\n\nDEFAULT_SPACE_CATEGORY = {\n    RoomType.LIVING_ROOM: SpaceCategory.ESTANCIA,\n    RoomType.DINING_ROOM: SpaceCategory.ESTANCIA,\n    RoomType.BEDROOM: SpaceCategory.ESTANCIA,\n    RoomType.MASTER_BEDROOM: SpaceCategory.ESTANCIA,\n    RoomType.STUDY: SpaceCategory.ESTANCIA,\n    RoomType.KITCHEN: SpaceCategory.SERVICIO,\n    RoomType.BATHROOM: SpaceCategory.SERVICIO,\n    RoomType.TOILET: SpaceCategory.SERVICIO,\n    RoomType.LAUNDRY: SpaceCategory.SERVICIO,\n    RoomType.DRYING_AREA: SpaceCategory.SERVICIO,\n    RoomType.STORAGE: SpaceCategory.SERVICIO,  # \"almacenamiento\" (Tabla 2), confirmado\n    RoomType.STORAGE_ROOM: SpaceCategory.SERVICIO,  # \"trastero\" (B.2.5, regla fija -- NO Tabla 2)\n    RoomType.ENTRANCE_HALL: SpaceCategory.CIRCULACION,\n    RoomType.CORRIDOR: SpaceCategory.CIRCULACION,\n    RoomType.STAIRCASE: SpaceCategory.CIRCULACION,\n    RoomType.GARAGE: SpaceCategory.OTROS,        # no es pieza vividera, fuera de Tabla 1/2\n    RoomType.TECHNICAL_ROOM: SpaceCategory.OTROS,\n}\n\n\n# Clave de Tabla 2 (A.3.2.2 / nhv.lua) para cada RoomType de categoria\n# SERVICIO. Solo los tipos presentes aqui participan en la validacion de\n# Tabla 2; el resto (ESTANCIA/CIRCULACION/OTROS) queda fuera por diseno.\nDEFAULT_SERVICE_SUBTYPE = {\n    RoomType.KITCHEN: \"cocina\",\n    RoomType.BATHROOM: \"bano\",\n    RoomType.TOILET: \"aseo\",\n    RoomType.LAUNDRY: \"lavadero\",\n    RoomType.DRYING_AREA: \"tendedero\",\n    RoomType.STORAGE: \"almacenamiento\",\n}\n\n\n# Minimo de lados con contacto real al exterior por tipo de estancia\n# (vivienda UNIFAMILIAR -- en bloque de viviendas ENTRANCE_HALL daria al\n# nucleo de comunicaciones, no al exterior real). Confirmado caso por\n# caso con el usuario, no derivado automaticamente de SpaceCategory --\n# BATHROOM y TOILET admiten ventilacion mecanica (0), pero DRYING_AREA\n# exige ventilacion natural directa (1) pese a ser tambien \"servicio\".\n# TECHNICAL_ROOM: 0 exigido, aunque por comodidad de acceso tecnico se\n# prefiera 1 en la practica -- eso es preferencia de diseno, no regla.\n#\n# GARAGE: 0 -- **[CORREGIDO tras investigacion, antes era 1]**. La\n# exigencia anterior de contacto exterior para GARAGE nunca estuvo\n# respaldada por ninguna fuente real: ni el Decreto 29/2010 (donde el\n# unico apartado sobre garajes, B.2.6 \"Garajes colectivos\", esta\n# confirmado -- por un hilo real de arquitectos en soloarquitectura.com\n# discutiendo la aplicacion practica del decreto -- que NO aplica a\n# vivienda unifamiliar, \"ya que no disponen de ninguno de ellos por\n# tipologia\") ni siquiera nhv.lua (que declara explicitamente en su\n# propio comentario: \"garajes de viviendas unifamiliares... no se\n# modela aqui -- ese es GARAJE colectivo\"). GARAGE ya es\n# SpaceCategory.OTROS (excluido de A.1.2, iluminacion/ventilacion de\n# piezas habitables) -- consistente con que la norma de habitabilidad\n# no lo trata como pieza vividera. El acceso vehicular real es un\n# asunto de urbanismo/acceso a parcela (A.2.1), no de habitabilidad por\n# estancia. Sigue siendo OPCIONAL por proyecto: `Room.min_exterior_sides`\n# admite override explicito (`Room(room_type=GARAGE, ...,\n# min_exterior_sides=1)`) para quien quiera exigirlo por motivos\n# practicos propios, sin que sea la exigencia por defecto del sistema.\n# Nombres legibles en espanol -- mismo mapeo EXACTO que DISPLAY en\n# docs/visualizador/relaciones_espaciales.html (las dos copias deben\n# coincidir; si una cambia, cambiar la otra). Bug real encontrado\n# haciendo el recorrido de extremo a extremo: seleccion_plantas_importer.py\n# usaba el nombre TECNICO del tipo (\"living_room\") como `Room.name`\n# tambien, en vez de un nombre legible -- se veia en el plano final,\n# no solo en el JSON intermedio. STAIRCASE incluido aqui (no aparece en\n# el catalogo del dashboard, que es solo de los 16 tipos no-circulacion).\nDISPLAY_NAMES = {\n    RoomType.LIVING_ROOM: \"Salón\",\n    RoomType.DINING_ROOM: \"Comedor\",\n    RoomType.KITCHEN: \"Cocina\",\n    RoomType.BEDROOM: \"Dormitorio\",\n    RoomType.MASTER_BEDROOM: \"Dormitorio principal\",\n    RoomType.BATHROOM: \"Baño\",\n    RoomType.TOILET: \"Aseo\",\n    RoomType.ENTRANCE_HALL: \"Recibidor\",\n    RoomType.STUDY: \"Despacho\",\n    RoomType.LAUNDRY: \"Lavadero\",\n    RoomType.DRYING_AREA: \"Tendedero\",\n    RoomType.STORAGE: \"Almacén\",\n    RoomType.STORAGE_ROOM: \"Trastero\",\n    RoomType.GARAGE: \"Garaje\",\n    RoomType.TECHNICAL_ROOM: \"Cuarto técnico\",\n    RoomType.CORRIDOR: \"Pasillo\",\n    RoomType.STAIRCASE: \"Escalera\",\n}\n\nDEFAULT_MIN_EXTERIOR_SIDES = {\n    RoomType.LIVING_ROOM: 1,\n    RoomType.DINING_ROOM: 1,\n    RoomType.KITCHEN: 1,\n    RoomType.BEDROOM: 1,\n    RoomType.MASTER_BEDROOM: 1,\n    RoomType.BATHROOM: 0,\n    RoomType.TOILET: 0,\n    RoomType.ENTRANCE_HALL: 1,\n    RoomType.STUDY: 1,\n    RoomType.LAUNDRY: 0,\n    RoomType.DRYING_AREA: 1,\n    RoomType.STORAGE: 0,\n    RoomType.STORAGE_ROOM: 0,\n    RoomType.GARAGE: 0,\n    RoomType.TECHNICAL_ROOM: 0,\n    RoomType.CORRIDOR: 0,\n    RoomType.STAIRCASE: 0,\n}\n\n\n# Niveles/plantas de una vivienda -- formaliza como enum lo que hasta\n# ahora solo vivia como texto en docs/niveles_plantas.md y en el\n# dashboard (JS). SOTANO=-2 ... BAJO_CUBIERTA=4 permite comparar\n# \"por encima/por debajo de\" con < > directamente sobre el valor.\nclass NivelPlanta(str, Enum):\n    SOTANO = \"sotano\"\n    SEMISOTANO = \"semisotano\"\n    PLANTA_BAJA = \"planta_baja\"\n    PLANTA_SUPERIOR = \"planta_superior\"\n    BAJO_CUBIERTA = \"bajo_cubierta\"\n\n\n# Orden vertical de abajo a arriba -- indice = posicion relativa, no un\n# numero de planta real (SEMISOTANO no siempre existe entre SOTANO y\n# PLANTA_BAJA, pero cuando ambos existen este es su orden correcto).\nNIVEL_PLANTA_ORDEN = [\n    NivelPlanta.SOTANO,\n    NivelPlanta.SEMISOTANO,\n    NivelPlanta.PLANTA_BAJA,\n    NivelPlanta.PLANTA_SUPERIOR,\n    NivelPlanta.BAJO_CUBIERTA,\n]\n", "housing_generator/domain/services/type_adjacency_catalog.py": "\"\"\"Catalogo de 120 pares de relaciones espaciales entre tipos de estancia,\nformalizado como estructura ejecutable del dominio.\n\nGenerado PROGRAMATICAMENTE desde docs/relaciones_espaciales.md (no\ntranscrito a mano -- fuente de errores dado el volumen). Si el\ncatalogo cambia en el Markdown, regenerar este archivo con el mismo\nscript (ver docs/architecture.md, seccion de este incremento).\n\nLos tres huecos de modelo que bloqueaban esta formalizacion (acceso/\npuertas, topologia de paso/terminal, cardinalidad) estan resueltos --\nver docs/CONTINUIDAD.md. El propio catalogo ya reclasificado a 5\ncategorias reales + Neutro documental + un caso especial (ver\nrelaciones_espaciales.md, seccion \"Terminologia\").\n\nDeliberadamente OMITIDOS de este diccionario (82 entradas de las 120\npares totales):\n- 35 pares \"Neutro\": ausencia de entrada = sin requisito generado, no\n  hace falta un valor especial.\n- 2 pares \"Condicional\" (BEDROOM/MASTER_BEDROOM x BATHROOM): NO son un\n  valor estatico de tabla -- se resuelven con logica evaluada contra el\n  Program real (ver BanoAccesoGeneralValidator), generar aqui un\n  AdjacencyRequirement fijo seria incorrecto (depende del nº de banos\n  del Program completo, no del par en si).\n- 1 par \"Ya cubierto\" (KITCHEN-BATHROOM): ya exigido por el validador\n  de nucleo humedo (ambas son is_wet) -- generar un AdjacencyRequirement\n  aqui duplicaria la misma exigencia por dos caminos distintos.\n\"\"\"\nfrom typing import Dict, List, Optional, Tuple\nfrom housing_generator.domain.entities.room import Room\nfrom housing_generator.domain.entities.program import Program\nfrom housing_generator.domain.enums import RoomType, AdjacencyStrength\nfrom housing_generator.domain.value_objects.adjacency import AdjacencyRequirement\n\n# Pares deliberadamente fuera de este catalogo estatico -- ver docstring\n# del modulo. Se declaran aqui (no solo en un comentario) para que\n# quien formalice reglas nuevas pueda comprobar programaticamente que\n# un par \"Condicional\" no deberia tener tambien una entrada aqui.\nCONDICIONAL_PAIRS = {\n    (RoomType.BEDROOM, RoomType.BATHROOM),\n    (RoomType.MASTER_BEDROOM, RoomType.BATHROOM),\n}\nYA_CUBIERTO_PAIRS = {\n    (RoomType.KITCHEN, RoomType.BATHROOM),\n}\n\nDEFAULT_TYPE_ADJACENCY: Dict[Tuple[RoomType, RoomType], AdjacencyStrength] = {\n    (RoomType.BATHROOM, RoomType.CORRIDOR): AdjacencyStrength.SHOULD_BE_NEAR,\n    (RoomType.BATHROOM, RoomType.DRYING_AREA): AdjacencyStrength.SHOULD_BE_NEAR,\n    (RoomType.BATHROOM, RoomType.ENTRANCE_HALL): AdjacencyStrength.SHOULD_BE_AWAY,\n    (RoomType.BATHROOM, RoomType.GARAGE): AdjacencyStrength.SHOULD_BE_AWAY,\n    (RoomType.BATHROOM, RoomType.LAUNDRY): AdjacencyStrength.SHOULD_BE_NEAR,\n    (RoomType.BATHROOM, RoomType.STORAGE): AdjacencyStrength.SHOULD_BE_NEAR,\n    (RoomType.BATHROOM, RoomType.STORAGE_ROOM): AdjacencyStrength.SHOULD_BE_AWAY,\n    (RoomType.BEDROOM, RoomType.CORRIDOR): AdjacencyStrength.SHOULD_BE_NEAR,\n    (RoomType.BEDROOM, RoomType.DRYING_AREA): AdjacencyStrength.SHOULD_BE_NEAR,\n    (RoomType.BEDROOM, RoomType.ENTRANCE_HALL): AdjacencyStrength.SHOULD_BE_AWAY,\n    (RoomType.BEDROOM, RoomType.GARAGE): AdjacencyStrength.SHOULD_BE_AWAY,\n    (RoomType.BEDROOM, RoomType.LAUNDRY): AdjacencyStrength.SHOULD_BE_NEAR,\n    (RoomType.BEDROOM, RoomType.STORAGE): AdjacencyStrength.SHOULD_BE_NEAR,\n    (RoomType.BEDROOM, RoomType.STORAGE_ROOM): AdjacencyStrength.SHOULD_BE_AWAY,\n    (RoomType.BEDROOM, RoomType.STUDY): AdjacencyStrength.SHOULD_BE_NEAR,\n    (RoomType.BEDROOM, RoomType.TECHNICAL_ROOM): AdjacencyStrength.SHOULD_BE_AWAY,\n    (RoomType.DINING_ROOM, RoomType.BATHROOM): AdjacencyStrength.SHOULD_BE_AWAY,\n    (RoomType.DINING_ROOM, RoomType.BEDROOM): AdjacencyStrength.SHOULD_BE_AWAY,\n    (RoomType.DINING_ROOM, RoomType.CORRIDOR): AdjacencyStrength.SHOULD_BE_NEAR,\n    (RoomType.DINING_ROOM, RoomType.DRYING_AREA): AdjacencyStrength.SHOULD_BE_AWAY,\n    (RoomType.DINING_ROOM, RoomType.GARAGE): AdjacencyStrength.SHOULD_BE_AWAY,\n    (RoomType.DINING_ROOM, RoomType.KITCHEN): AdjacencyStrength.MUST_BE_NEAR,\n    (RoomType.DINING_ROOM, RoomType.LAUNDRY): AdjacencyStrength.SHOULD_BE_AWAY,\n    (RoomType.DINING_ROOM, RoomType.MASTER_BEDROOM): AdjacencyStrength.SHOULD_BE_AWAY,\n    (RoomType.DINING_ROOM, RoomType.STORAGE): AdjacencyStrength.SHOULD_BE_NEAR,\n    (RoomType.DINING_ROOM, RoomType.STORAGE_ROOM): AdjacencyStrength.SHOULD_BE_AWAY,\n    (RoomType.DINING_ROOM, RoomType.TECHNICAL_ROOM): AdjacencyStrength.SHOULD_BE_AWAY,\n    (RoomType.DINING_ROOM, RoomType.TOILET): AdjacencyStrength.SHOULD_BE_NEAR,\n    (RoomType.DRYING_AREA, RoomType.CORRIDOR): AdjacencyStrength.SHOULD_BE_NEAR,\n    (RoomType.ENTRANCE_HALL, RoomType.DRYING_AREA): AdjacencyStrength.SHOULD_BE_AWAY,\n    (RoomType.ENTRANCE_HALL, RoomType.LAUNDRY): AdjacencyStrength.SHOULD_BE_AWAY,\n    (RoomType.ENTRANCE_HALL, RoomType.STORAGE): AdjacencyStrength.SHOULD_BE_NEAR,\n    (RoomType.ENTRANCE_HALL, RoomType.STORAGE_ROOM): AdjacencyStrength.SHOULD_BE_AWAY,\n    (RoomType.KITCHEN, RoomType.BEDROOM): AdjacencyStrength.SHOULD_BE_AWAY,\n    (RoomType.KITCHEN, RoomType.CORRIDOR): AdjacencyStrength.SHOULD_BE_NEAR,\n    (RoomType.KITCHEN, RoomType.DRYING_AREA): AdjacencyStrength.SHOULD_BE_NEAR,\n    (RoomType.KITCHEN, RoomType.ENTRANCE_HALL): AdjacencyStrength.SHOULD_BE_NEAR,\n    (RoomType.KITCHEN, RoomType.GARAGE): AdjacencyStrength.SHOULD_BE_NEAR,\n    (RoomType.KITCHEN, RoomType.LAUNDRY): AdjacencyStrength.SHOULD_BE_NEAR,\n    (RoomType.KITCHEN, RoomType.MASTER_BEDROOM): AdjacencyStrength.SHOULD_BE_AWAY,\n    (RoomType.KITCHEN, RoomType.STORAGE): AdjacencyStrength.SHOULD_BE_NEAR,\n    (RoomType.KITCHEN, RoomType.STORAGE_ROOM): AdjacencyStrength.SHOULD_BE_AWAY,\n    (RoomType.KITCHEN, RoomType.TECHNICAL_ROOM): AdjacencyStrength.SHOULD_BE_NEAR,\n    (RoomType.LAUNDRY, RoomType.CORRIDOR): AdjacencyStrength.SHOULD_BE_NEAR,\n    (RoomType.LAUNDRY, RoomType.DRYING_AREA): AdjacencyStrength.MUST_BE_NEAR,\n    (RoomType.LIVING_ROOM, RoomType.BATHROOM): AdjacencyStrength.SHOULD_BE_AWAY,\n    (RoomType.LIVING_ROOM, RoomType.BEDROOM): AdjacencyStrength.SHOULD_BE_AWAY,\n    (RoomType.LIVING_ROOM, RoomType.CORRIDOR): AdjacencyStrength.SHOULD_BE_NEAR,\n    (RoomType.LIVING_ROOM, RoomType.DINING_ROOM): AdjacencyStrength.MUST_BE_NEAR,\n    (RoomType.LIVING_ROOM, RoomType.DRYING_AREA): AdjacencyStrength.SHOULD_BE_AWAY,\n    (RoomType.LIVING_ROOM, RoomType.ENTRANCE_HALL): AdjacencyStrength.MUST_BE_NEAR,\n    (RoomType.LIVING_ROOM, RoomType.GARAGE): AdjacencyStrength.MUST_BE_AWAY,\n    (RoomType.LIVING_ROOM, RoomType.KITCHEN): AdjacencyStrength.SHOULD_BE_NEAR,\n    (RoomType.LIVING_ROOM, RoomType.LAUNDRY): AdjacencyStrength.SHOULD_BE_AWAY,\n    (RoomType.LIVING_ROOM, RoomType.MASTER_BEDROOM): AdjacencyStrength.SHOULD_BE_AWAY,\n    (RoomType.LIVING_ROOM, RoomType.STORAGE): AdjacencyStrength.SHOULD_BE_NEAR,\n    (RoomType.LIVING_ROOM, RoomType.STORAGE_ROOM): AdjacencyStrength.SHOULD_BE_AWAY,\n    (RoomType.LIVING_ROOM, RoomType.STUDY): AdjacencyStrength.SHOULD_BE_NEAR,\n    (RoomType.LIVING_ROOM, RoomType.TECHNICAL_ROOM): AdjacencyStrength.SHOULD_BE_AWAY,\n    (RoomType.LIVING_ROOM, RoomType.TOILET): AdjacencyStrength.SHOULD_BE_NEAR,\n    (RoomType.MASTER_BEDROOM, RoomType.CORRIDOR): AdjacencyStrength.SHOULD_BE_NEAR,\n    (RoomType.MASTER_BEDROOM, RoomType.DRYING_AREA): AdjacencyStrength.SHOULD_BE_NEAR,\n    (RoomType.MASTER_BEDROOM, RoomType.ENTRANCE_HALL): AdjacencyStrength.SHOULD_BE_AWAY,\n    (RoomType.MASTER_BEDROOM, RoomType.GARAGE): AdjacencyStrength.SHOULD_BE_AWAY,\n    (RoomType.MASTER_BEDROOM, RoomType.LAUNDRY): AdjacencyStrength.SHOULD_BE_NEAR,\n    (RoomType.MASTER_BEDROOM, RoomType.STORAGE): AdjacencyStrength.SHOULD_BE_NEAR,\n    (RoomType.MASTER_BEDROOM, RoomType.STORAGE_ROOM): AdjacencyStrength.SHOULD_BE_AWAY,\n    (RoomType.MASTER_BEDROOM, RoomType.STUDY): AdjacencyStrength.SHOULD_BE_NEAR,\n    (RoomType.MASTER_BEDROOM, RoomType.TECHNICAL_ROOM): AdjacencyStrength.SHOULD_BE_AWAY,\n    (RoomType.STORAGE, RoomType.CORRIDOR): AdjacencyStrength.SHOULD_BE_NEAR,\n    (RoomType.STORAGE_ROOM, RoomType.CORRIDOR): AdjacencyStrength.SHOULD_BE_NEAR,\n    (RoomType.STORAGE_ROOM, RoomType.GARAGE): AdjacencyStrength.SHOULD_BE_NEAR,\n    (RoomType.STUDY, RoomType.CORRIDOR): AdjacencyStrength.SHOULD_BE_NEAR,\n    (RoomType.STUDY, RoomType.DRYING_AREA): AdjacencyStrength.SHOULD_BE_AWAY,\n    (RoomType.STUDY, RoomType.GARAGE): AdjacencyStrength.SHOULD_BE_AWAY,\n    (RoomType.STUDY, RoomType.LAUNDRY): AdjacencyStrength.SHOULD_BE_AWAY,\n    (RoomType.STUDY, RoomType.STORAGE): AdjacencyStrength.SHOULD_BE_NEAR,\n    (RoomType.STUDY, RoomType.STORAGE_ROOM): AdjacencyStrength.SHOULD_BE_AWAY,\n    (RoomType.STUDY, RoomType.TECHNICAL_ROOM): AdjacencyStrength.SHOULD_BE_AWAY,\n    (RoomType.TOILET, RoomType.CORRIDOR): AdjacencyStrength.SHOULD_BE_NEAR,\n    (RoomType.TOILET, RoomType.ENTRANCE_HALL): AdjacencyStrength.SHOULD_BE_NEAR,\n    (RoomType.TOILET, RoomType.STORAGE_ROOM): AdjacencyStrength.SHOULD_BE_AWAY,\n}\n\n\ndef get_type_adjacency(type_a: RoomType, type_b: RoomType) -> Optional[AdjacencyStrength]:\n    \"\"\"Consulta el catalogo para un par de tipos, sin importar el orden\n    (el diccionario se genero directamente de una tabla fila/columna,\n    no con claves canonicamente ordenadas).\"\"\"\n    return DEFAULT_TYPE_ADJACENCY.get((type_a, type_b)) or DEFAULT_TYPE_ADJACENCY.get((type_b, type_a))\n\n\ndef generate_adjacency_requirements(rooms: List[Room]) -> List[AdjacencyRequirement]:\n    \"\"\"Genera automaticamente los AdjacencyRequirement (Obligatorio y\n    Preferencia) que aplican a un conjunto de estancias, segun sus\n    RoomType y el catalogo formalizado.\n\n    Se aplica a CADA PAR de estancias existentes cuyo (tipo_a, tipo_b)\n    tenga entrada en el catalogo -- si un Program tiene dos BEDROOM,\n    ambos reciben la misma relacion hacia, por ejemplo, BATHROOM (el\n    catalogo es por TIPO, no por instancia unica). Pares del mismo tipo\n    nunca generan nada (el catalogo no tiene entradas tipo-tipo consigo\n    mismo: son 120 pares de tipos DISTINTOS, C(16,2)).\n\n    No genera nada para pares CONDICIONAL_PAIRS ni YA_CUBIERTO_PAIRS\n    (ver docstring del modulo) -- esos se resuelven con sus propios\n    validadores, no con un AdjacencyRequirement estatico.\n    \"\"\"\n    requirements: List[AdjacencyRequirement] = []\n    for i, room_a in enumerate(rooms):\n        for room_b in rooms[i + 1:]:\n            if room_a.room_type == room_b.room_type:\n                continue\n            type_pair_a = (room_a.room_type, room_b.room_type)\n            type_pair_b = (room_b.room_type, room_a.room_type)\n            if type_pair_a in CONDICIONAL_PAIRS or type_pair_b in CONDICIONAL_PAIRS:\n                continue\n            if type_pair_a in YA_CUBIERTO_PAIRS or type_pair_b in YA_CUBIERTO_PAIRS:\n                continue\n\n            strength = get_type_adjacency(room_a.room_type, room_b.room_type)\n            if strength is not None:\n                requirements.append(AdjacencyRequirement(room_a.id, room_b.id, strength))\n\n    return requirements\n\n\ndef build_program_with_auto_adjacency(rooms: List[Room]) -> Program:\n    \"\"\"Conveniencia que cierra el circulo del catalogo formalizado:\n    construye un `Program` derivando sus `AdjacencyRequirement`\n    automaticamente (`generate_adjacency_requirements`) en vez de\n    exigir declararlos a mano -- retomado de docs/CONTINUIDAD.md\n    (\"conectar generate_adjacency_requirements como opcion automatica\").\n\n    Vive aqui (domain/services), no en config/container.py: es logica\n    de dominio pura (RoomType -> AdjacencyStrength), sin ninguna\n    dependencia de infraestructura -- container.py sigue siendo el\n    unico sitio que conecta clases CONCRETAS de infraestructura, esto\n    no lo es.\"\"\"\n    return Program(rooms=rooms, adjacency_requirements=generate_adjacency_requirements(rooms))\n", "housing_generator/domain/value_objects/adjacency.py": "from dataclasses import dataclass\nfrom housing_generator.domain.enums import AdjacencyStrength\n\n\n@dataclass(frozen=True)\nclass AdjacencyRequirement:\n    \"\"\"Requisito de adyacencia (no dirigido) entre dos estancias, por id.\n\n    Es la unidad minima de datos de la clasica 'matriz de adyacencia' /\n    'diagrama de burbujas' empleada en programacion arquitectonica.\n    \"\"\"\n    room_a_id: str\n    room_b_id: str\n    strength: AdjacencyStrength\n\n    def involves(self, room_id: str) -> bool:\n        return room_id in (self.room_a_id, self.room_b_id)\n\n    def other(self, room_id: str) -> str:\n        if room_id == self.room_a_id:\n            return self.room_b_id\n        if room_id == self.room_b_id:\n            return self.room_a_id\n        raise ValueError(f\"La estancia {room_id} no pertenece a este requisito\")\n", "housing_generator/domain/value_objects/__init__.py": "", "housing_generator/domain/value_objects/dimensions.py": "from dataclasses import dataclass\nfrom typing import Optional\n\n\n@dataclass(frozen=True)\nclass Dimensions:\n    \"\"\"Requisito de area/proporcion/altura de una estancia. Inmutable (value object).\"\"\"\n    area_m2: float\n    min_width_m: float = 2.0\n    max_aspect_ratio: float = 2.5\n    ceiling_height_m: Optional[float] = None  # A.3.1.1: None = no declarada, no se asume\n\n    def __post_init__(self):\n        if self.area_m2 <= 0:\n            raise ValueError(\"area_m2 debe ser positivo\")\n        if self.min_width_m <= 0:\n            raise ValueError(\"min_width_m debe ser positivo\")\n        if self.ceiling_height_m is not None and self.ceiling_height_m <= 0:\n            raise ValueError(\"ceiling_height_m debe ser positivo si se declara\")\n", "housing_generator/domain/value_objects/boundary.py": "from dataclasses import dataclass\nfrom shapely.geometry import Polygon\n\n\n@dataclass(frozen=True)\nclass Boundary:\n    \"\"\"Envuelve un Polygon de shapely: la huella de un solar o de una estancia.\"\"\"\n    polygon: Polygon\n\n    @property\n    def area_m2(self) -> float:\n        return self.polygon.area\n\n    @property\n    def centroid(self):\n        return self.polygon.centroid\n\n    def contains(self, other: \"Boundary\") -> bool:\n        return self.polygon.contains(other.polygon)\n", "housing_generator/domain/entities/lot.py": "from dataclasses import dataclass\nfrom typing import FrozenSet, List, Optional\nfrom shapely.geometry import box, LineString, Polygon\nfrom housing_generator.domain.value_objects.boundary import Boundary\n\n\n@dataclass(frozen=True)\nclass Lot:\n    \"\"\"Solar/parcela edificable, con datos simplificados de orientacion.\n\n    `retranqueo_m`: separacion minima obligatoria a los lindes de\n    parcela (vivienda unifamiliar AISLADA -- sin medianeras, todos los\n    lados pueden tener contacto exterior real). NO es un valor fijo de\n    la normativa de habitabilidad: el propio Decreto 29/2010 remite esta\n    cuestion a \"la legislacion urbanistica vigente segun la\n    clasificacion del suelo\" (Ley 2/2016 do solo de Galicia + PXOM de\n    cada ayuntamiento) -- por eso es un parametro que declara quien usa\n    este proyecto, no una constante que este proyecto pueda asumir.\n    `None` significa \"sin retranqueo declarado\", y el area edificable\n    coincide con la parcela completa (comportamiento actual, sin cambios).\n\n    `retranqueo_incremento_por_planta_m`: **[RESUELTO]** retomado de\n    docs/CONTINUIDAD.md (\"reducir el contorno edificable planta a\n    planta\"). Investigacion externa confirmada antes de implementar\n    (Devans, \"Procedural Generation For Dummies: Building Footprints\"):\n    la tecnica estandar en generacion procedural de edificios es\n    \"subtractive generation... empezando por la forma de la parcela y\n    recortando trozos -- un buen enfoque para generar huellas de plantas\n    superiores, ya que la segunda planta suele parecerse a la primera\"\n    -- con una red de seguridad si el area resultante queda demasiado\n    pequena (patron `MinArea{Action:Shrink, Fallback:...}` del mismo\n    articulo). Aplicado aqui via `GenerateBuildingUseCase`, que encoge\n    progresivamente (`buffer(-incremento)`, mismo mecanismo que\n    `buildable_area`) el area de cada planta respecto a la de abajo,\n    saltando el encogimiento de esa planta si el resultado no alcanzaria\n    para las estancias declaradas (misma huella que la planta inferior\n    en ese caso -- la otra opcion valida segun la propia investigacion:\n    \"copia exacta O subconjunto\", nunca invalido, nunca silenciosamente\n    mas pequeño de lo necesario). `None` (por defecto) preserva el\n    comportamiento anterior: todas las plantas comparten el mismo\n    contorno edificable, sin decrecer.\n\n    `medianera_sides`: **[RESUELTO]** retomado de docs/CONTINUIDAD.md\n    (\"vivienda pareada/adosada\"). Vivienda con 1 o 2 lados en medianera\n    (pared compartida con la parcela vecina, sin separacion): esos lados\n    NO llevan retranqueo (la edificacion llega hasta el linde) y NO\n    cuentan como contacto exterior real para habitabilidad (una pared\n    de medianera no tiene luz ni ventilacion propia -- confirma\n    `ExteriorContactValidator`). Subconjunto de\n    `{\"north\",\"south\",\"east\",\"west\"}`; vacio (por defecto) = vivienda\n    AISLADA, comportamiento anterior sin cambios. Requiere parcela\n    rectangular con lados ortogonales (norte=+y, sur=-y, este=+x,\n    oeste=-x) -- misma simplificacion geometrica que el resto del\n    proyecto (particion guillotina, todo rectangular).\n    \"\"\"\n    boundary: Boundary\n    entrance_side: str = \"south\"   # north | south | east | west\n    street_side: str = \"south\"\n    retranqueo_m: Optional[float] = None\n    retranqueo_incremento_por_planta_m: Optional[float] = None\n    medianera_sides: FrozenSet[str] = frozenset()\n\n    @property\n    def buildable_area(self) -> Boundary:\n        \"\"\"Area edificable real: la parcela reducida hacia dentro por el\n        retranqueo declarado -- EXCEPTO en los lados de medianera\n        (`medianera_sides`), donde la edificacion llega hasta el linde\n        sin retranqueo. Sin retranqueo Y sin medianeras, coincide con la\n        parcela completa (comportamiento original sin cambios).\"\"\"\n        if (self.retranqueo_m is None or self.retranqueo_m <= 0) and not self.medianera_sides:\n            return self.boundary\n\n        minx, miny, maxx, maxy = self.boundary.polygon.bounds\n        r = self.retranqueo_m or 0.0\n        new_minx = minx if \"west\" in self.medianera_sides else minx + r\n        new_maxx = maxx if \"east\" in self.medianera_sides else maxx - r\n        new_miny = miny if \"south\" in self.medianera_sides else miny + r\n        new_maxy = maxy if \"north\" in self.medianera_sides else maxy - r\n\n        if new_minx >= new_maxx or new_miny >= new_maxy:\n            # retranqueo excesivo: colapsa a vacio, no a un rectangulo\n            # invertido -- mismo comportamiento que el buffer(-x) previo\n            # cuando el retranqueo superaba la mitad de la parcela.\n            return Boundary(polygon=Polygon())\n        return Boundary(polygon=box(new_minx, new_miny, new_maxx, new_maxy))\n\n    def medianera_boundary_segments(self) -> List[LineString]:\n        \"\"\"Los segmentos de linde que son medianera (posicion ORIGINAL de\n        la parcela, no del area edificable ya encogida) -- usado por\n        `count_exterior_sides` para no contar contacto con estos lados\n        como contacto exterior real.\"\"\"\n        minx, miny, maxx, maxy = self.boundary.polygon.bounds\n        segments = []\n        if \"north\" in self.medianera_sides:\n            segments.append(LineString([(minx, maxy), (maxx, maxy)]))\n        if \"south\" in self.medianera_sides:\n            segments.append(LineString([(minx, miny), (maxx, miny)]))\n        if \"east\" in self.medianera_sides:\n            segments.append(LineString([(maxx, miny), (maxx, maxy)]))\n        if \"west\" in self.medianera_sides:\n            segments.append(LineString([(minx, miny), (minx, maxy)]))\n        return segments\n", "housing_generator/domain/entities/__init__.py": "", "housing_generator/domain/entities/layout.py": "from dataclasses import dataclass, field\nfrom typing import List, Dict\nfrom housing_generator.domain.entities.room import Room\nfrom housing_generator.domain.entities.zone import Zone\nfrom housing_generator.domain.entities.lot import Lot\nfrom housing_generator.domain.enums import ZoneType\n\n\n@dataclass\nclass Layout:\n    \"\"\"Resultado generado: estancias colocadas en el espacio, agrupadas en zonas.\"\"\"\n    lot: Lot\n    rooms: List[Room]\n    zones: List[Zone]\n    metadata: Dict[str, float] = field(default_factory=dict)  # p.ej. score de fitness\n\n    @property\n    def is_complete(self) -> bool:\n        return all(r.is_placed for r in self.rooms)\n\n    def rooms_in_zone(self, zone_type: ZoneType) -> List[Room]:\n        zone_room_ids = {\n            rid for z in self.zones if z.zone_type == zone_type for rid in z.room_ids\n        }\n        return [r for r in self.rooms if r.id in zone_room_ids]\n", "housing_generator/domain/entities/zone.py": "from dataclasses import dataclass, field\nfrom typing import List, Optional\nfrom housing_generator.domain.enums import ZoneType\nfrom housing_generator.domain.value_objects.boundary import Boundary\n\n\n@dataclass\nclass Zone:\n    \"\"\"Macro-zona (dia / noche / servicio) que agrupa varias estancias.\"\"\"\n    zone_type: ZoneType\n    room_ids: List[str] = field(default_factory=list)\n    boundary: Optional[Boundary] = None\n\n    def add_room(self, room_id: str) -> None:\n        if room_id not in self.room_ids:\n            self.room_ids.append(room_id)\n", "housing_generator/domain/entities/program.py": "from dataclasses import dataclass, field\nfrom typing import List\nfrom housing_generator.domain.entities.room import Room\nfrom housing_generator.domain.value_objects.adjacency import AdjacencyRequirement\nfrom housing_generator.domain.exceptions import InvalidProgramError\n\n\n@dataclass\nclass Program:\n    \"\"\"El encargo de diseno: estancias solicitadas + requisitos de adyacencia.\"\"\"\n    rooms: List[Room]\n    adjacency_requirements: List[AdjacencyRequirement] = field(default_factory=list)\n\n    def __post_init__(self):\n        ids = [r.id for r in self.rooms]\n        if len(ids) != len(set(ids)):\n            raise InvalidProgramError(\"Hay ids de estancia duplicados en el programa\")\n\n        room_ids = set(ids)\n        for req in self.adjacency_requirements:\n            if req.room_a_id not in room_ids or req.room_b_id not in room_ids:\n                raise InvalidProgramError(\n                    f\"Un requisito de adyacencia referencia una estancia inexistente: {req}\"\n                )\n\n    @property\n    def total_area_m2(self) -> float:\n        return sum(r.dimensions.area_m2 for r in self.rooms)\n\n    def room_by_id(self, room_id: str) -> Room:\n        for r in self.rooms:\n            if r.id == room_id:\n                return r\n        raise KeyError(room_id)\n", "housing_generator/domain/entities/building.py": "from dataclasses import dataclass, field\nfrom typing import Dict, List, Optional\nfrom housing_generator.domain.entities.layout import Layout\nfrom housing_generator.domain.enums import NivelPlanta, NIVEL_PLANTA_ORDEN\n\n\n@dataclass\nclass Building:\n    \"\"\"Vivienda de varias plantas: una `Layout` completa por cada\n    `NivelPlanta` presente, generada de forma independiente pero\n    coordinada entre plantas verticalmente adyacentes (huella de\n    escalera alineada, nucleo humedo solapado -- ver validadores\n    entre plantas en `infrastructure/algorithms/constraints`).\n\n    Deliberadamente NO reemplaza a `Layout` para el caso de una sola\n    planta: `Layout` sigue siendo el resultado de una vivienda simple,\n    `Building` es la composicion de varias cuando hace falta.\n    \"\"\"\n    floors: Dict[NivelPlanta, Layout] = field(default_factory=dict)\n\n    @property\n    def is_complete(self) -> bool:\n        return bool(self.floors) and all(layout.is_complete for layout in self.floors.values())\n\n    def ordered_levels(self) -> List[NivelPlanta]:\n        \"\"\"Los niveles realmente presentes en este Building, de abajo a\n        arriba -- subconjunto de NIVEL_PLANTA_ORDEN, no todos los 5\n        tienen por que existir.\"\"\"\n        return [level for level in NIVEL_PLANTA_ORDEN if level in self.floors]\n\n    def level_below(self, level: NivelPlanta) -> Optional[NivelPlanta]:\n        \"\"\"El nivel inmediatamente inferior YA PRESENTE en este Building\n        (no necesariamente el anterior en NIVEL_PLANTA_ORDEN si ese nivel\n        intermedio no existe en esta vivienda concreta).\"\"\"\n        present = self.ordered_levels()\n        idx = present.index(level) if level in present else -1\n        if idx <= 0:\n            return None\n        return present[idx - 1]\n", "housing_generator/domain/entities/room.py": "from dataclasses import dataclass\nfrom typing import Optional\nfrom housing_generator.domain.enums import (\n    RoomType,\n    ZoneType,\n    SpaceCategory,\n    NivelPlanta,\n    DEFAULT_ROOM_ZONE,\n    DEFAULT_WET_ROOMS,\n    DEFAULT_SPACE_CATEGORY,\n    DEFAULT_SERVICE_SUBTYPE,\n    DEFAULT_MIN_EXTERIOR_SIDES,\n)\nfrom housing_generator.domain.value_objects.dimensions import Dimensions\nfrom housing_generator.domain.value_objects.boundary import Boundary\n\n\n@dataclass\nclass Room:\n    \"\"\"Una estancia a ubicar en la vivienda (entidad de dominio).\n\n    `boundary` es None hasta que un LayoutGenerator la coloca en el espacio;\n    hasta entonces Room solo representa el requisito programatico.\n    \"\"\"\n    id: str\n    name: str\n    room_type: RoomType\n    dimensions: Dimensions\n    zone: Optional[ZoneType] = None\n    is_wet: Optional[bool] = None\n    space_category: Optional[SpaceCategory] = None\n    service_subtype: Optional[str] = None\n    min_exterior_sides: Optional[int] = None\n    # Solo relevante para RoomType.KITCHEN: cocina abierta en un unico\n    # espacio con el salon (caso tipico de estudio/loft). Ver\n    # CocinaIntegradaValidator -- confirmado contra nhv.lua\n    # (validarCocinaIntegrada), no un supuesto propio.\n    integrated_in_largest_room: bool = False\n    vertical_opening_m2: Optional[float] = None\n    boundary: Optional[Boundary] = None\n    requires_natural_light: bool = True\n    requires_direct_access_exterior: bool = False\n    # Planta a la que pertenece esta estancia (multi-planta). `None` =\n    # vivienda de una sola planta (comportamiento previo sin cambios) --\n    # se asume PLANTA_BAJA implicitamente en ese caso por el resto del\n    # sistema, sin necesidad de declararlo.\n    level: Optional[NivelPlanta] = None\n\n    def __post_init__(self):\n        if self.zone is None:\n            self.zone = DEFAULT_ROOM_ZONE.get(self.room_type, ZoneType.DAY)\n        if self.is_wet is None:\n            self.is_wet = self.room_type in DEFAULT_WET_ROOMS\n        if self.space_category is None:\n            self.space_category = DEFAULT_SPACE_CATEGORY.get(self.room_type, SpaceCategory.OTROS)\n        if self.service_subtype is None:\n            self.service_subtype = DEFAULT_SERVICE_SUBTYPE.get(self.room_type)\n        if self.min_exterior_sides is None:\n            self.min_exterior_sides = DEFAULT_MIN_EXTERIOR_SIDES.get(self.room_type, 0)\n\n    @property\n    def is_placed(self) -> bool:\n        return self.boundary is not None\n"};

