const TYPES = Object.keys(DISPLAY);

const LEVEL_ORDER = ['SOTANO','SEMISOTANO','PLANTA_BAJA','PLANTA_SUPERIOR','BAJO_CUBIERTA'];
const LEVEL_LABEL = {SOTANO:'Sótano',SEMISOTANO:'Semisótano',PLANTA_BAJA:'Planta baja',PLANTA_SUPERIOR:'Planta superior',BAJO_CUBIERTA:'Bajo cubierta'};
const LEVEL_RASANTE = {PLANTA_BAJA:'± 0.00 rasante'};

function classify(relation){
  const r = relation.toLowerCase();
  if(r.includes('ya cubierto')) return 'cov';
  if(r.includes('condicional')) return 'cond';
  if(r.includes('obligatorio') && r.includes('lejo')) return 'ol';
  if(r.includes('obligatorio')) return 'oc';
  if(r.includes('neutro')) return 'n';
  if(r.includes('alejar')) return 'pa';
  if(r.includes('cerca')) return 'pc';
  return 'n';
}
// Reclasificado tras auditoria (antes 7 etiquetas, incluyendo "muy
// cerca" como nivel aparte -- sin distincion operativa real, fusionada
// en "pc"). "cond" ya no es un valor de relacion en si -- es un
// marcador de "ver regla aparte" (nº de banos). "cov" = ya cubierto por
// otro validador (nucleo humedo), no necesita entrada propia.
const LABELS = {oc:'Obligatorio cerca', ol:'Obligatorio lejos', pc:'Preferencia (cerca)', pa:'Preferencia (alejar)', n:'Neutro', cond:'Condicional (ver regla aparte)', cov:'Ya cubierto (núcleo húmedo)'};
const COLORVAR = {oc:'--oc', ol:'--ol', pc:'--pc', pa:'--pa', n:'--n', cond:'--cond', cov:'--cyan-dim'};

function findPair(a,b){
  return PAIRS.find(p => (p.a===a&&p.b===b) || (p.a===b&&p.b===a));
}

// ---------------- MATRIZ ----------------
function buildMatrix(){
  const table = document.getElementById('matrix-table');
  let html = '<tr><th></th>';
  TYPES.forEach(t => html += `<th class="colhead" data-type="${t}">${DISPLAY[t]}</th>`);
  html += '</tr>';
  TYPES.forEach((rowType,i) => {
    html += `<tr><th class="rowhead" data-type="${rowType}">${DISPLAY[rowType]}</th>`;
    TYPES.forEach((colType,j) => {
      if(i===j){ html += '<td class="diag"></td>'; return; }
      if(j<i){ html += '<td class="lower"></td>'; return; }
      const pair = findPair(rowType,colType);
      const cls = pair ? classify(pair.relation) : 'n';
      html += `<td class="cell" style="background:var(${COLORVAR[cls]})" data-a="${rowType}" data-b="${colType}" title="${DISPLAY[rowType]} × ${DISPLAY[colType]}"></td>`;
    });
    html += '</tr>';
  });
  table.innerHTML = html;

  table.querySelectorAll('td.cell').forEach(td => {
    td.addEventListener('click', () => showDetail(td.dataset.a, td.dataset.b));
  });
}

function showDetail(a,b){
  const pair = findPair(a,b);
  if(!pair) return;
  document.getElementById('detail-a').textContent = DISPLAY[a];
  document.getElementById('detail-b').textContent = DISPLAY[b];
  const cls = classify(pair.relation);
  const tag = document.getElementById('detail-tag');
  tag.textContent = pair.relation.replace(/\*\*/g,'');
  tag.style.background = `var(${COLORVAR[cls]})`;
  document.getElementById('detail-motivo').textContent = pair.motivo;
  document.getElementById('detail-panel').classList.add('show');
}

function buildLegend(){
  const el = document.getElementById('legend-matrix');
  el.innerHTML = Object.keys(LABELS).map(k =>
    `<span class="item"><span class="sw" style="background:var(${COLORVAR[k]})"></span>${LABELS[k]}</span>`
  ).join('');
}

function filterMatrix(query){
  const q = query.trim().toLowerCase();
  const match = t => !q || DISPLAY[t].toLowerCase().includes(q) || t.toLowerCase().includes(q);
  document.querySelectorAll('#matrix-table th.colhead, #matrix-table th.rowhead').forEach(th => {
    th.classList.toggle('dim', !match(th.dataset.type));
  });
  document.querySelectorAll('#matrix-table td.cell').forEach(td => {
    const dim = q && !match(td.dataset.a) && !match(td.dataset.b);
    td.classList.toggle('dim', dim);
  });
}

// ---------------- SECCION (plantas) ----------------
function parseLevels(nivelesStr){
  // separa "SOTANO / SEMISOTANO / PLANTA_BAJA" (indiferente) o
  // "PLANTA_BAJA → PLANTA_SUPERIOR" (cadena de respaldo)
  const isChain = nivelesStr.includes('→');
  const parts = nivelesStr.split(isChain ? '→' : '/').map(s => s.trim());
  return {isChain, levels: parts.map(p => p.replace(/\(opcional\)/,'').trim().match(/[A-Z_]+/)?.[0]).filter(Boolean)};
}

// Estancias adicionales disponibles SOLO en esta herramienta (uso
// practico del arquitecto), no forman parte de la cadena normativa de
// niveles_plantas.md -- se muestran con un estilo distinto (borde
// ambar) para que quede claro que no proceden del catalogo.
const EXTRA_TYPES_BY_LEVEL = {
  BAJO_CUBIERTA: ['BEDROOM', 'MASTER_BEDROOM', 'BATHROOM'],
  SEMISOTANO: ['STUDY'],
};

// Mismos valores que AREAS_POR_DEFECTO_M2 en
// seleccion_plantas_importer.py -- punto de partida razonable que el
// usuario ajusta, no un minimo normativo ni una imposicion.
const DEFAULT_AREA_M2 = {
  LIVING_ROOM:25, DINING_ROOM:14, KITCHEN:10, BEDROOM:12, MASTER_BEDROOM:15,
  BATHROOM:5.5, TOILET:3, ENTRANCE_HALL:4.5, STUDY:9, LAUNDRY:3, DRYING_AREA:2,
  STORAGE:3, STORAGE_ROOM:4, GARAGE:18, TECHNICAL_ROOM:3, CORRIDOR:4,
};

const SECTION = { selected: {} };  // level -> Map(RoomType -> {count, area})
let AREAS_LOCKED = false;  // si true, los campos de area son readonly (bloqueados al minimo normativo)
let TIPO_VIVIENDA = 'aislada';  // metadato guardado en la exportacion, no cambia la seleccion de estancias

function ensureSectionSelected(level){
  if(!SECTION.selected[level]) SECTION.selected[level] = new Map();
  return SECTION.selected[level];
}

function candidateTypesForLevel(level){
  const fromCatalog = FLOORS.filter(f => {
    if(f.type === 'CORRIDOR') return false;
    const {levels} = parseLevels(f.niveles);
    return levels.includes(level);
  }).map(f => f.type);
  const extra = EXTRA_TYPES_BY_LEVEL[level] || [];
  return [...fromCatalog, 'CORRIDOR', ...extra];
}

// Mismas 6 piezas que ViviendaMinimaValidator.REQUIRED_TYPES en Python
// (programa minimo, Decreto 29/2010 I.A.2.3) -- para dar feedback
// inmediato en el dashboard, antes de exportar y descubrirlo solo al
// intentar generar.
const PROGRAMA_MINIMO_TYPES = ['LIVING_ROOM', 'KITCHEN', 'BATHROOM', 'LAUNDRY', 'DRYING_AREA', 'STORAGE'];

function renderSectionSummary(){
  const el = document.getElementById('section-summary');
  if(!el) return;

  let totalRooms = 0, totalArea = 0;
  const presentTypes = new Set();
  const perLevel = [];

  LEVEL_ORDER.forEach(level => {
    const sel = ensureSectionSelected(level);
    if(sel.size === 0) return;
    let levelRooms = 0, levelArea = 0;
    sel.forEach((v, t) => {
      levelRooms += v.count;
      levelArea += v.count * v.area;
      presentTypes.add(t);
    });
    totalRooms += levelRooms;
    totalArea += levelArea;
    perLevel.push(`${LEVEL_LABEL[level]}: ${levelRooms} estancias, ${levelArea.toFixed(1)}m²`);
  });

  const faltan = PROGRAMA_MINIMO_TYPES.filter(t => !presentTypes.has(t));
  const programaHtml = faltan.length === 0
    ? `<span class="stat programa-ok">✓ programa mínimo completo</span>`
    : `<span class="stat programa-falta">✗ falta: ${faltan.map(t => DISPLAY[t]).join(', ')}</span>`;

  el.innerHTML = totalRooms === 0
    ? `<span class="stat">Sin estancias seleccionadas todavía.</span>`
    : `<span class="stat"><b>${totalRooms}</b> estancias, <b>${totalArea.toFixed(1)}m²</b> en total</span>`
      + perLevel.map(s => `<span class="stat">${s}</span>`).join('')
      + programaHtml;
}

// Mismos valores EXACTOS que TABLA_1/TABLA_2 en Python (ver
// estancia_minimum_area_validator.py, servicio_minimum_area_validator.py)
// -- retomado a peticion del usuario: las areas editables no avisaban
// si el valor declarado no alcanzaba el minimo real segun el numero
// total de estancias, dejando al usuario sin saber si "se estan
// ajustando en funcion del numero de estancias y de los requisitos".
const TABLA_1 = {1:[25], 2:[16,12], 3:[18,12,8], 4:[20,12,8,8], 5:[22,12,8,8,6]};
const TABLA_1_MAS_DE_CINCO = [25,12,8,8,8];
const MINIMO_ESTANCIA_ADICIONAL = 6.0;
const TABLA_2 = {
  1:{cocina:5, bano:5, lavadero:1.5, tendedero:1.5, almacenamiento:1},
  2:{cocina:7, bano:5, lavadero:1.5, tendedero:1.5, almacenamiento:2},
  3:{cocina:7, bano:5, lavadero:1.5, tendedero:1.5, almacenamiento:3},
  4:{cocina:9, bano:5, aseo:1.5, lavadero:1.5, tendedero:1.5, almacenamiento:4},
  5:{cocina:9, bano:5, aseo:1.5, lavadero:1.5, tendedero:1.5, almacenamiento:5},
};
const TABLA_2_MAS_DE_CINCO = {cocina:10, bano:5, aseo:1.5, lavadero:1.5, tendedero:1.5, almacenamiento:6};

function minimoEstancia(numEstancias, puesto){
  if(numEstancias <= 5){
    const fila = TABLA_1[numEstancias];
    if(!fila || puesto > fila.length) return null;
    return fila[puesto-1];
  }
  if(puesto <= 5) return TABLA_1_MAS_DE_CINCO[puesto-1];
  return MINIMO_ESTANCIA_ADICIONAL;
}

function tablaServiciosPara(numEstancias){
  if(TABLA_2[numEstancias]) return TABLA_2[numEstancias];
  if(numEstancias < 1) return TABLA_2[1];
  return TABLA_2_MAS_DE_CINCO;
}

// Calcula, para TODAS las estancias seleccionadas (todas las plantas a
// la vez, igual que hace GenerateBuildingUseCase con el ranking global),
// cuales no alcanzan el minimo real de Tabla 1/2 -- devuelve un Map
// "level|type" -> mensaje de aviso, para pintar cada chip en rojo si
// corresponde.
function computeAreaWarnings(){
  const allEntries = [];  // {level, type, count, area, category, subtype}
  LEVEL_ORDER.forEach(level => {
    const sel = ensureSectionSelected(level);
    sel.forEach((v, t) => {
      const p = PROPS[t];
      if(!p) return;
      allEntries.push({level, type:t, count:v.count, area:v.area, category:p.category, subtype:p.subtype});
    });
  });

  // total de ESTANCIAS (categoria "estancia", cuenta cada instancia -- 2
  // dormitorios cuentan como 2) -- mismo criterio que GenerateBuildingUseCase
  const totalEstancias = allEntries.filter(e => e.category === 'estancia')
    .reduce((s,e) => s + e.count, 0);

  const warnings = new Map();  // "level|type" -> mensaje

  // Tabla 1: ordenar TODAS las instancias de estancia por area declarada
  // descendente, asignar puesto 1..N (una entrada con count=2 genera 2
  // "instancias" del mismo tamano para el ranking, igual que en Python)
  const estanciaInstances = [];
  allEntries.filter(e => e.category === 'estancia').forEach(e => {
    for(let i=0;i<e.count;i++) estanciaInstances.push(e);
  });
  estanciaInstances.sort((a,b) => b.area - a.area);
  estanciaInstances.forEach((e, i) => {
    const puesto = i+1;
    const minimo = minimoEstancia(totalEstancias, puesto);
    if(minimo !== null && e.area < minimo){
      const key = `${e.level}|${e.type}`;
      warnings.set(key, `Tabla 1: puesto ${puesto} de ${totalEstancias} exige ≥${minimo}m² (declarado ${e.area}m²)`);
    }
  });

  // Tabla 2: por subtipo, minimo segun el total de estancias
  const tabla2Fila = tablaServiciosPara(totalEstancias);
  allEntries.filter(e => e.category === 'servicio' && e.subtype).forEach(e => {
    const minimo = tabla2Fila[e.subtype];
    if(minimo !== undefined && e.area < minimo){
      const key = `${e.level}|${e.type}`;
      warnings.set(key, `Tabla 2 (${e.subtype}): ${totalEstancias} estancias exige ≥${minimo}m² (declarado ${e.area}m²)`);
    }
  });

  return warnings;
}

function applyAreaWarnings(){
  const warnings = computeAreaWarnings();
  document.querySelectorAll('.chip.selected').forEach(chip => {
    const key = `${chip.dataset.level}|${chip.dataset.type}`;
    const areaInput = chip.querySelector('.chip-area');
    if(!areaInput) return;
    const msg = warnings.get(key);
    areaInput.classList.toggle('area-warn', !!msg);
    areaInput.title = msg || 'Área en m² de cada una';
  });
}

// Orden canonico para asignar "puesto" de Tabla 1 ANTES de saber areas
// reales (la generacion automatica calcula el area a partir del
// puesto, no al reves) -- salon siempre el mayor, luego el dormitorio
// principal, luego el resto. Coincide con la convencion ya usada en
// todo el proyecto (LIVING_ROOM = estancia mayor).
const CANONICAL_ESTANCIA_ORDER = ['LIVING_ROOM', 'MASTER_BEDROOM', 'BEDROOM', 'DINING_ROOM', 'STUDY'];

function recalculateAutoAreas(){
  const allEntries = [];
  LEVEL_ORDER.forEach(level => {
    const sel = ensureSectionSelected(level);
    sel.forEach((v, t) => allEntries.push({level, type:t, v}));
  });

  const estanciaEntries = allEntries.filter(e => PROPS[e.type] && PROPS[e.type].category === 'estancia');
  estanciaEntries.sort((a,b) => CANONICAL_ESTANCIA_ORDER.indexOf(a.type) - CANONICAL_ESTANCIA_ORDER.indexOf(b.type));
  const totalEstancias = estanciaEntries.reduce((s,e) => s + e.v.count, 0);

  let puesto = 1;
  estanciaEntries.forEach(e => {
    // si count>1 (varios dormitorios del mismo tipo), cada instancia
    // ocupa un puesto consecutivo -- se usa el MAS EXIGENTE (area mayor)
    // de los puestos que ocupa, para que TODAS las instancias cumplan
    // aunque compartan un unico valor de area en esta entrada.
    const puestosDeEsteGrupo = [];
    for(let i=0;i<e.v.count;i++){ puestosDeEsteGrupo.push(puesto); puesto++; }
    const minimo = Math.max(...puestosDeEsteGrupo.map(p => minimoEstancia(totalEstancias, p) || 0));
    e.v.area = minimo;
  });

  const tabla2Fila = tablaServiciosPara(totalEstancias);
  allEntries.filter(e => PROPS[e.type] && PROPS[e.type].category === 'servicio').forEach(e => {
    const subtype = PROPS[e.type].subtype;
    e.v.area = (subtype && tabla2Fila[subtype]) || DEFAULT_AREA_M2[e.type] || 10;
  });

  // circulacion (ENTRANCE_HALL, CORRIDOR) -- sin fila de Tabla 1/2 propia
  allEntries.filter(e => PROPS[e.type] && PROPS[e.type].category === 'circulacion').forEach(e => {
    e.v.area = DEFAULT_AREA_M2[e.type] || 4;
  });
}

function applyAutoConfig(){
  const dormitorios = Math.max(1, parseInt(document.getElementById('auto-dormitorios').value, 10) || 1);
  const plantas = parseInt(document.getElementById('auto-plantas').value, 10);
  TIPO_VIVIENDA = document.getElementById('auto-tipo-vivienda').value;

  SECTION.selected = {};
  const pbSet = ensureSectionSelected('PLANTA_BAJA');
  const nocheSet = plantas === 2 ? ensureSectionSelected('PLANTA_SUPERIOR') : pbSet;

  // programa minimo (dia/servicio) -- siempre en planta baja
  pbSet.set('LIVING_ROOM', {count:1, area:0});
  pbSet.set('KITCHEN', {count:1, area:0});
  pbSet.set('ENTRANCE_HALL', {count:1, area:0});
  pbSet.set('LAUNDRY', {count:1, area:0});
  pbSet.set('DRYING_AREA', {count:1, area:0});
  pbSet.set('STORAGE', {count:1, area:0});

  // dormitorios: 1 principal + (N-1) normales -- reglas confirmadas con
  // el usuario antes de implementar, no supuestas
  nocheSet.set('MASTER_BEDROOM', {count:1, area:0});
  const bedCount = dormitorios - 1;
  if(bedCount > 0) nocheSet.set('BEDROOM', {count:bedCount, area:0});

  // banos: 1 bano siempre (arriba, junto a los dormitorios); +1 aseo si
  // hay 3 o mas dormitorios -- el aseo va en PLANTA_BAJA, no arriba con
  // el resto de banos: el propio catalogo (FLOORS) ya declara TOILET
  // como "Fijo, sirve a zona social/visitas, no depende de dormitorios"
  // -- bug real encontrado al probar: colocarlo en planta superior
  // haria que el chip no se renderizase nunca (no esta en la lista de
  // tipos candidatos de esa planta segun el propio catalogo).
  nocheSet.set('BATHROOM', {count:1, area:0});
  if(dormitorios >= 3) pbSet.set('TOILET', {count:1, area:0});

  // pasillo en planta superior si hay 2 plantas -- necesario para que
  // el bano de arriba tenga acceso general (BanoAccesoGeneralValidator),
  // confirmado con un caso real que fallaba sin esto
  if(plantas === 2) nocheSet.set('CORRIDOR', {count:1, area:0});

  recalculateAutoAreas();

  AREAS_LOCKED = true;
  const lockCheckbox = document.getElementById('areas-lock-checkbox');
  if(lockCheckbox) lockCheckbox.checked = false;
  buildSection();
}

function buildSection(){
  const wrap = document.getElementById('section-wrap');
  let html = '';
  LEVEL_ORDER.slice().reverse().forEach(level => {
    const types = candidateTypesForLevel(level);
    const selected = ensureSectionSelected(level);
    const extraSet = new Set(EXTRA_TYPES_BY_LEVEL[level] || []);

    html += `<div class="level" data-level="${level}">
      <div class="lvl-label">${LEVEL_LABEL[level]}${LEVEL_RASANTE[level] ? `<span class="rasante">${LEVEL_RASANTE[level]}</span>` : ''}</div>`;
    types.forEach(t => {
      const isExtra = extraSet.has(t);
      const isSel = selected.has(t);
      const cls = ['chip', isExtra ? 'extra' : '', isSel ? 'selected' : ''].filter(Boolean).join(' ');
      const title = t === 'CORRIDOR' ? 'Circulación, disponible en todas las plantas' :
        (isExtra ? 'Adicional de esta herramienta, no procede de niveles_plantas.md' : (FLOORS.find(f=>f.type===t)||{}).notas || '');
      const vals = isSel ? selected.get(t) : {count:1, area: DEFAULT_AREA_M2[t] || 10};
      const readonlyAttr = AREAS_LOCKED ? 'readonly' : '';
      const controls = isSel ? `<span class="chip-controls">
          <input type="number" class="chip-count" min="1" step="1" value="${vals.count}" title="Cantidad de estancias de este tipo">
          <span class="unit">×</span>
          <input type="number" class="chip-area" min="1" step="0.5" value="${vals.area}" ${readonlyAttr} title="Área en m² de cada una">
          <span class="unit">m²</span>
        </span>` : '';
      html += `<span class="${cls}" data-type="${t}" data-level="${level}" title="${title}">${DISPLAY[t]}${controls}</span>`;
    });
    html += `</div>`;
  });
  wrap.innerHTML = html;

  wrap.querySelectorAll('.chip').forEach(chip => {
    chip.addEventListener('click', (ev) => {
      if(ev.target.closest('.chip-controls')) return;  // click en los inputs no debe (des)seleccionar
      const level = chip.dataset.level, t = chip.dataset.type;
      const sel = ensureSectionSelected(level);
      if(sel.has(t)) sel.delete(t);
      else sel.set(t, {count: 1, area: DEFAULT_AREA_M2[t] || 10});
      buildSection();  // re-renderiza para mostrar/ocultar los controles de este chip
    });
  });

  wrap.querySelectorAll('.chip-count, .chip-area').forEach(input => {
    input.addEventListener('click', ev => ev.stopPropagation());
    input.addEventListener('change', () => {
      const chip = input.closest('.chip');
      const level = chip.dataset.level, t = chip.dataset.type;
      const sel = ensureSectionSelected(level);
      const current = sel.get(t) || {count:1, area: DEFAULT_AREA_M2[t] || 10};
      if(input.classList.contains('chip-count')) current.count = Math.max(1, parseInt(input.value, 10) || 1);
      else current.area = Math.max(0.5, parseFloat(input.value) || (DEFAULT_AREA_M2[t] || 10));
      sel.set(t, current);
      renderSectionSummary();
      applyAreaWarnings();
    });
  });

  renderSectionSummary();
  applyAreaWarnings();
}

function filterSection(query){
  const q = query.trim().toLowerCase();
  document.querySelectorAll('#section-wrap .chip').forEach(chip => {
    const t = chip.dataset.type;
    const match = !q || DISPLAY[t].toLowerCase().includes(q) || t.toLowerCase().includes(q);
    chip.style.display = match ? '' : 'none';
  });
}

function buildSeleccionPayload(){
  const levels = {};
  LEVEL_ORDER.forEach(level => {
    const sel = ensureSectionSelected(level);
    if(sel.size > 0){
      levels[level] = Array.from(sel.entries()).map(([type, v]) => (
        {type, count: v.count, area_m2: v.area}
      ));
    }
  });
  return {
    version: 2,
    levels,
    tipo_vivienda: TIPO_VIVIENDA,
    nota: 'Seleccion de esta herramienta de exploracion (catalogo), con cantidad y area '
        + 'declaradas por el usuario -- ya no son valores genericos de relleno, pero siguen '
        + 'siendo una PRIMERA aproximacion a revisar antes de un proyecto real. '
        + 'Las estancias bajo "extra" (bajo cubierta: dormitorios/bano; semisotano: despacho) '
        + 'son uso practico de esta herramienta, no proceden de niveles_plantas.md. '
        + 'Para generar directamente, usa el boton "Generar plano ahora" -- este archivo '
        + 'exportado es solo para quien prefiera el CLI a mano '
        + '(python -m housing_generator.interface.cli.main --import-seleccion '
        + 'seleccion_plantas.json --output edificio.json) o quiera archivar la seleccion.',
  };
}

function exportSectionSelection(){
  const payload = buildSeleccionPayload();

  const blob = new Blob([JSON.stringify(payload, null, 2)], {type: 'application/json'});
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = 'seleccion_plantas.json';
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
  URL.revokeObjectURL(url);
}

// ---------------- FICHAS ----------------
function buildCards(){
  const wrap = document.getElementById('cards-wrap');
  const catColor = {estancia:'--cat-estancia', servicio:'--pa', circulacion:'--cyan-dim', otros:'--n'};
  wrap.innerHTML = TYPES.map(t => {
    const p = PROPS[t];
    const floor = FLOORS.find(f => f.type === t);
    const obligatorias = PAIRS.filter(pr => (pr.a===t || pr.b===t) && ['oc','ol'].includes(classify(pr.relation)));
    const obligatoriasHtml = obligatorias.length > 0 ? `<div class="floor-note" style="margin-top:8px;">
        <b>Relaciones obligatorias:</b><br>
        ${obligatorias.map(pr => {
          const other = pr.a===t ? pr.b : pr.a;
          const cls = classify(pr.relation);
          return `<span style="color:var(${COLORVAR[cls]})">${cls==='oc'?'cerca de':'lejos de'} ${DISPLAY[other]}</span>`;
        }).join(' · ')}
      </div>` : '';
    return `
    <div class="card" data-type="${t}">
      <h3>${DISPLAY[t]} <span style="color:var(--ink-faint); font-size:11px; font-weight:400;">(${t.toLowerCase()})</span></h3>
      <div class="row"><span class="k">zona</span><span class="v">${p.zone}</span></div>
      <div class="row"><span class="k">categoría</span><span class="v"><span class="pill" style="background:var(${catColor[p.category]||'--n'}); color:#2B2622;">${p.category}</span></span></div>
      <div class="row"><span class="k">estancia húmeda</span><span class="v ${p.is_wet?'yes':''}">${p.is_wet ? 'sí' : 'no'}</span></div>
      <div class="row"><span class="k">subtipo (Tabla 2)</span><span class="v">${p.subtype || '—'}</span></div>
      <div class="row"><span class="k">lados a exterior (mín.)</span><span class="v ${p.min_exterior>0?'yes':''}">${p.min_exterior}</span></div>
      ${floor ? `<div class="floor-note"><b>Planta:</b> ${floor.niveles.replace(/\*\*/g,'')} · <b>${floor.fuerza}</b><br>${floor.notas}</div>` : ''}
      ${obligatoriasHtml}
    </div>`;
  }).join('');
}

function filterCards(query){
  const q = query.trim().toLowerCase();
  document.querySelectorAll('#cards-wrap .card').forEach(card => {
    const t = card.dataset.type;
    const match = !q || DISPLAY[t].toLowerCase().includes(q) || t.toLowerCase().includes(q);
    card.style.display = match ? '' : 'none';
  });
}

// ---------------- SINERGIAS ----------------
const WEIGHT = {oc:3, ol:-3, pc:1, pa:-1, n:0, cond:0, cov:2};
const ZONE_GROUP_ORDER = ['day','night','service','circulation'];
const CAT_COLOR = {estancia:'--cat-estancia', servicio:'--pa', circulacion:'--cyan-dim', otros:'--n'};

// Por defecto solo se muestran las relaciones ESTRUCTURALES (obligatorio
// cerca/lejos + ya cubierto) -- retomado a peticion del usuario: con las
// ~85 aristas no neutras del catalogo completo, el diagrama era
// demasiado denso para comprender de un vistazo. Las de Preferencia se
// activan aparte, sin perder ningun dato (todo sigue disponible, solo
// no se muestra todo a la vez por defecto).
let NETWORK_FILTER = new Set(['oc', 'ol', 'cov']);

function renderNetFilters(){
  const el = document.getElementById('net-filters');
  const options = [
    {k:'oc', label:'Obligatorio cerca'}, {k:'ol', label:'Obligatorio lejos'},
    {k:'cov', label:'Ya cubierto'}, {k:'pc', label:'Preferencia cerca'}, {k:'pa', label:'Preferencia alejar'},
  ];
  el.innerHTML = options.map(({k,label}) => `
    <label><input type="checkbox" data-k="${k}" ${NETWORK_FILTER.has(k)?'checked':''}>
      <span style="color:var(${COLORVAR[k]})">${label}</span></label>
  `).join('');
  el.querySelectorAll('input').forEach(cb => {
    cb.addEventListener('change', () => {
      if(cb.checked) NETWORK_FILTER.add(cb.dataset.k); else NETWORK_FILTER.delete(cb.dataset.k);
      buildNetwork(SCORES);
    });
  });
}

function computeScores(){
  const scores = {}; TYPES.forEach(t => scores[t] = 0);
  PAIRS.forEach(p => {
    const w = WEIGHT[classify(p.relation)];
    scores[p.a] += w; scores[p.b] += w;
  });
  return scores;
}

// Retomado de la metodologia de matriz de relaciones ponderadas
// (clasica en programacion arquitectonica): "el orden descendente de
// las sumatorias define el rango de jerarquia y ubicacion central o
// periferica". Puntuacion mas alta -> rango mas bajo (0) -> posicion
// mas CENTRAL. Empates comparten el mismo rango (rango promedio,
// "competition ranking" estandar) -- misma jerarquia, misma posicion,
// no un desempate arbitrario.
function computeRanks(scores){
  const sorted = TYPES.slice().sort((a,b) => scores[b]-scores[a]);
  const ranks = {};
  let i = 0;
  while(i < sorted.length){
    let j = i;
    while(j+1 < sorted.length && scores[sorted[j+1]] === scores[sorted[i]]) j++;
    const avgRank = (i+j)/2;  // 0-indexado, promedio del grupo empatado
    for(let k=i;k<=j;k++) ranks[sorted[k]] = avgRank;
    i = j+1;
  }
  return ranks;
}

function networkOrder(){
  return TYPES.slice().sort((a,b) => {
    const za = ZONE_GROUP_ORDER.indexOf(PROPS[a].zone), zb = ZONE_GROUP_ORDER.indexOf(PROPS[b].zone);
    return za !== zb ? za - zb : TYPES.indexOf(a) - TYPES.indexOf(b);
  });
}

function hasNonNeutralEdge(t, other){
  return PAIRS.some(p => {
    const cls = classify(p.relation);
    return NETWORK_FILTER.has(cls) && ((p.a===t&&p.b===other)||(p.a===other&&p.b===t));
  });
}

function buildNetwork(scores){
  const order = networkOrder();
  const ranks = computeRanks(scores);
  const n = order.length, cx = 310, cy = 310;
  const MIN_R = 70, MAX_R = 260;  // rango 0 (mas "necesario") = mas central
  const pos = {};
  order.forEach((t,i) => {
    const angle = (i/n)*2*Math.PI - Math.PI/2;
    const radius = n > 1 ? MIN_R + (ranks[t]/(n-1))*(MAX_R-MIN_R) : (MIN_R+MAX_R)/2;
    pos[t] = {x: cx + radius*Math.cos(angle), y: cy + radius*Math.sin(angle)};
  });

  // anillos guia -- confirman visualmente que la posicion central/
  // periferica sigue el rango, no solo el tamano del nodo
  let ringsHtml = '';
  [MIN_R, (MIN_R+MAX_R)/2, MAX_R].forEach(r => {
    ringsHtml += `<circle cx="${cx}" cy="${cy}" r="${r}" fill="none" stroke="var(--line)" stroke-width="0.75" stroke-dasharray="3,5" opacity="0.5"></circle>`;
  });

  let edgesHtml = '';
  PAIRS.forEach(p => {
    const cls = classify(p.relation);
    if(cls === 'n' || cls === 'cond') return;
    if(!NETWORK_FILTER.has(cls)) return;  // respeta el filtro de tipos activos
    const a = pos[p.a], b = pos[p.b];
    const dashed = (cls==='ol' || cls==='pa') ? 'stroke-dasharray="5,4"' : '';
    const width = (cls==='oc'||cls==='ol') ? 2.4 : 1.3;
    edgesHtml += `<line class="net-edge" data-a="${p.a}" data-b="${p.b}" x1="${a.x}" y1="${a.y}" x2="${b.x}" y2="${b.y}" stroke="var(${COLORVAR[cls]})" stroke-width="${width}" opacity="0.55" ${dashed}></line>`;
  });
  edgesHtml = ringsHtml + edgesHtml;

  const maxAbs = Math.max(...Object.values(scores).map(v=>Math.abs(v)), 1);
  let nodesHtml = '';
  order.forEach(t => {
    const p = pos[t];
    const r = 8 + (scores[t] > 0 ? (scores[t]/maxAbs)*9 : 1);
    const ang = Math.atan2(p.y-cy, p.x-cx);
    const lx = p.x + Math.cos(ang)*(r+36), ly = p.y + Math.sin(ang)*(r+14);
    nodesHtml += `<g class="net-node" data-type="${t}">
      <circle class="net-hitarea" cx="${p.x}" cy="${p.y}" r="${r+14}" fill="transparent"></circle>
      <circle cx="${p.x}" cy="${p.y}" r="${r}" fill="var(${CAT_COLOR[PROPS[t].category]||'--n'})" stroke="#2B2622" stroke-width="1.5"></circle>
      <text class="net-label" x="${lx}" y="${ly}" text-anchor="middle">${DISPLAY[t]}</text>
    </g>`;
  });

  const svg = document.getElementById('net-svg');
  svg.innerHTML = edgesHtml + nodesHtml;

  svg.querySelectorAll('.net-node').forEach(node => {
    node.addEventListener('click', () => {
      const t = node.dataset.type;
      const wasActive = node.classList.contains('active-node');
      svg.querySelectorAll('.net-node').forEach(n2 => n2.classList.remove('active-node'));
      if(wasActive){
        svg.querySelectorAll('.net-edge').forEach(e => e.style.opacity = '0.55');
        svg.querySelectorAll('.net-node circle').forEach(c => c.style.opacity = '1');
        return;
      }
      node.classList.add('active-node');
      svg.querySelectorAll('.net-edge').forEach(e => {
        e.style.opacity = (e.dataset.a===t || e.dataset.b===t) ? '0.95' : '0.05';
      });
      svg.querySelectorAll('.net-node').forEach(n2 => {
        const nt = n2.dataset.type;
        n2.querySelector('circle').style.opacity = (nt===t || hasNonNeutralEdge(t,nt)) ? '1' : '0.2';
      });
    });
  });
}

function buildScoreBars(scores){
  const wrap = document.getElementById('score-bars');
  const maxAbs = Math.max(...Object.values(scores).map(v=>Math.abs(v)), 1);
  const sorted = TYPES.slice().sort((a,b) => scores[b]-scores[a]);
  wrap.innerHTML = sorted.map(t => {
    const s = scores[t], pct = Math.abs(s)/maxAbs*50, isNeg = s < 0;
    const left = isNeg ? (50-pct) : 50;
    return `<div class="score-row">
      <span class="lbl">${DISPLAY[t]}</span>
      <div class="bartrack"><div class="barfill ${isNeg?'neg':''}" style="left:${left}%; width:${pct}%;"></div></div>
      <span class="val">${s>0?'+':''}${s}</span>
    </div>`;
  }).join('');
}

function rankItemHtml(p){
  const cls = classify(p.relation);
  return `<div class="rank-item">
    <span class="names">${DISPLAY[p.a]} <span style="color:var(--ink-faint)">×</span> ${DISPLAY[p.b]}</span>
    <span class="tagmini" style="background:var(${COLORVAR[cls]})">${LABELS[cls]}</span>
  </div>`;
}

function csvEscape(v){
  const s = String(v);
  return /[",\n]/.test(s) ? '"' + s.replace(/"/g,'""') + '"' : s;
}

function exportScheduleCSV(){
  // "tabla de planificacion" (Schedule, en terminologia Revit) -- a
  // diferencia del flujo manual habitual (exportar a Excel, cruzar
  // valores 4/2/0 y sumar rangos a mano), aqui la puntuacion y el
  // rango ya estan calculados automaticamente (computeScores/
  // computeRanks) -- esta exportacion solo vuelca esos datos ya
  // calculados a una tabla real, para usar fuera del dashboard.
  const scores = computeScores();
  const ranks = computeRanks(scores);
  const rows = [['tipo','nombre','zona','categoria','area_representativa_m2','puntuacion_sinergia','rango']];

  TYPES.slice().sort((a,b) => ranks[a]-ranks[b]).forEach(t => {
    const p = PROPS[t];
    rows.push([t, DISPLAY[t], p.zone, p.category, DEFAULT_AREA_M2[t] || '', scores[t], ranks[t]]);
  });

  const csv = rows.map(r => r.map(csvEscape).join(',')).join('\n');
  const blob = new Blob([csv], {type: 'text/csv;charset=utf-8'});
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = 'tabla_estancias.csv';
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
  URL.revokeObjectURL(url);
}

function buildRankings(){
  const withW = PAIRS.map(p => ({...p, w: WEIGHT[classify(p.relation)]}));
  const top = withW.filter(p=>p.w>0).sort((a,b)=>b.w-a.w).slice(0,5);
  const bottom = withW.filter(p=>p.w<0).sort((a,b)=>a.w-b.w).slice(0,5);
  document.getElementById('rank-top').innerHTML = top.map(rankItemHtml).join('');
  document.getElementById('rank-bottom').innerHTML = bottom.map(rankItemHtml).join('');
}

function buildSynergyLegend(){
  const el = document.getElementById('legend-synergy');
  el.innerHTML = ['oc','ol','pc','pa','cov'].map(k =>
    `<span class="item"><span class="sw" style="background:var(${COLORVAR[k]})"></span>${LABELS[k]}</span>`
  ).join('');
}

// ---------------- VISOR DE PLANO ----------------
// (fusionado desde plano_viewer.html a peticion del usuario -- "FLOORS"
// ya existe arriba con otro significado del todo distinto, de ahi
// LOADED_PLANS/ACTIVE_PLAN en vez de FLOORS/ACTIVE)
const PLANO_ZONE_COLOR = {day:'var(--zone-day)', night:'var(--zone-night)', service:'var(--zone-service)', circulation:'var(--zone-circulation)'};
const PLANO_ZONE_LABEL = {day:'Día', night:'Noche', service:'Servicio', circulation:'Circulación'};

let LOADED_PLANS = [];   // [{label, data}], data = el JSON tal cual ({rooms, doors, metadata})
let ACTIVE_PLAN = 0;

function labelForPlanFile(filename){
  const m = filename.match(/planta_(\w+)/i) || filename.match(/(sotano|semisotano|bajo_cubierta)/i);
  if(m) return m[0].replace(/_/g,' ').replace(/^\w/, c => c.toUpperCase());
  return filename.replace(/\.json$/i, '');
}

function renderPlanoTabs(){
  const wrap = document.getElementById('floor-tabs');
  if(LOADED_PLANS.length <= 1){ wrap.innerHTML = ''; return; }
  wrap.innerHTML = LOADED_PLANS.map((f, i) => {
    const hv = f.data.metadata && f.data.metadata.hard_violations;
    const badge = (hv === 0) ? '<span class="badge ok">✓</span>' : (hv > 0 ? `<span class="badge bad">${hv}</span>` : '');
    return `<button class="floor-tab ${i===ACTIVE_PLAN?'active':''}" data-i="${i}">${f.label}${badge}</button>`;
  }).join('');
  wrap.querySelectorAll('.floor-tab').forEach(btn => {
    btn.addEventListener('click', () => { ACTIVE_PLAN = parseInt(btn.dataset.i,10); renderPlanoTabs(); renderPlano(); });
  });
}

// ---------------- MODO ESPEJO (visor de plano) ----------------
// Retomado de una sugerencia del usuario: el generador no considera
// orientacion solar (SolarExposureValidator sigue aparcado) -- un
// plano puede ser funcionalmente bueno pero con la zona de dia mirando
// al lado "equivocado". Reflejar/rotar un plano YA generado es una
// transformacion geometrica pura que conserva EXACTAMENTE las
// relaciones de adyacencia (las marcas de puerta se recalculan solas a
// partir de los bounds nuevos, via sharedWallMidpoint) -- no toca el
// generador Python en absoluto, es puro cliente.
let PLANO_TRANSFORM = { mirrorH: false, mirrorV: false, rotation: 0 };  // rotation en {0,90,180,270}

function planoCanvasBounds(rooms){
  let minX=Infinity, minY=Infinity, maxX=-Infinity, maxY=-Infinity;
  rooms.forEach(r => {
    const [x0,y0,x1,y1] = r.bounds;
    minX=Math.min(minX,x0); minY=Math.min(minY,y0); maxX=Math.max(maxX,x1); maxY=Math.max(maxY,y1);
  });
  return {minX, minY, maxX, maxY};
}

function applyPlanoTransform(rooms, transform){
  if(!transform.mirrorH && !transform.mirrorV && transform.rotation === 0) return rooms;
  const canvas = planoCanvasBounds(rooms);
  const W0 = canvas.maxX - canvas.minX, H0 = canvas.maxY - canvas.minY;

  return rooms.map(r => {
    let [x0,y0,x1,y1] = r.bounds;
    // normalizar al origen del lote (por si no empieza en 0,0)
    x0 -= canvas.minX; x1 -= canvas.minX; y0 -= canvas.minY; y1 -= canvas.minY;
    let W = W0, H = H0;

    if(transform.mirrorH){ const nx0=W-x1, nx1=W-x0; x0=nx0; x1=nx1; }
    if(transform.mirrorV){ const ny0=H-y1, ny1=H-y0; y0=ny0; y1=ny1; }

    const steps = (transform.rotation / 90) % 4;
    for(let i=0;i<steps;i++){
      // rotacion 90 grados horaria: (x,y) -> (y, W-x); el nuevo lienzo es HxW
      const nx0=y0, nx1=y1, ny0=W-x1, ny1=W-x0;
      x0=nx0; x1=nx1; y0=ny0; y1=ny1;
      const tmp=W; W=H; H=tmp;
    }
    return Object.assign({}, r, {bounds: [x0,y0,x1,y1]});
  });
}

function setPlanoTransform(partial){
  PLANO_TRANSFORM = Object.assign({}, PLANO_TRANSFORM, partial);
  renderPlano();
}

// Punto medio del segmento de pared compartida entre dos rectangulos
// axis-aligned (bounds [x0,y0,x1,y1]) -- para marcar puertas. Sin
// libreria de geometria en el cliente: logica directa de bordes,
// suficiente porque toda la geometria del proyecto es rectangular.
function sharedWallMidpoint(a, b){
  const EPS = 0.05;
  if(Math.abs(a[2]-b[0]) < EPS || Math.abs(b[2]-a[0]) < EPS){
    const x = Math.abs(a[2]-b[0]) < EPS ? a[2] : a[0];
    const oy0 = Math.max(a[1], b[1]), oy1 = Math.min(a[3], b[3]);
    if(oy1 > oy0) return {x, y: (oy0+oy1)/2, vertical:true};
  }
  if(Math.abs(a[3]-b[1]) < EPS || Math.abs(b[3]-a[1]) < EPS){
    const y = Math.abs(a[3]-b[1]) < EPS ? a[3] : a[1];
    const ox0 = Math.max(a[0], b[0]), ox1 = Math.min(a[2], b[2]);
    if(ox1 > ox0) return {x: (ox0+ox1)/2, y, vertical:false};
  }
  return null;
}

function renderPlano(){
  const content = document.getElementById('plano-content');
  const floor = LOADED_PLANS[ACTIVE_PLAN];
  if(!floor){ content.innerHTML = '<div class="plano-empty">Carga un archivo para ver la planta generada.</div>'; return; }

  const rooms = applyPlanoTransform(floor.data.rooms.filter(r => r.bounds), PLANO_TRANSFORM);
  if(rooms.length === 0){
    content.innerHTML = '<div class="plano-empty">Este archivo no tiene estancias con geometría resuelta.</div>';
    return;
  }

  let minX=Infinity, minY=Infinity, maxX=-Infinity, maxY=-Infinity;
  rooms.forEach(r => {
    const [x0,y0,x1,y1] = r.bounds;
    minX=Math.min(minX,x0); minY=Math.min(minY,y0); maxX=Math.max(maxX,x1); maxY=Math.max(maxY,y1);
  });
  const pad = Math.max((maxX-minX), (maxY-minY)) * 0.04;
  const vbX = minX-pad, vbY = minY-pad, vbW = (maxX-minX)+pad*2, vbH = (maxY-minY)+pad*2;

  // SVG usa Y creciendo hacia abajo; nuestros planos usan Y creciendo
  // hacia arriba (norte = +y, ver Lot) -- se invierte con un transform,
  // no recalculando coordenadas a mano (mas facil de verificar).
  let svgBody = `<g transform="translate(0, ${vbY*2+vbH}) scale(1,-1)">`;
  rooms.forEach(r => {
    const [x0,y0,x1,y1] = r.bounds;
    const color = PLANO_ZONE_COLOR[r.zone] || 'var(--ink-faint)';
    svgBody += `<rect class="room-rect" x="${x0}" y="${y0}" width="${x1-x0}" height="${y1-y0}" fill="${color}" fill-opacity="0.55" data-id="${r.id}"></rect>`;
  });

  (floor.data.doors || []).forEach(d => {
    const ra = rooms.find(r => r.id === d.room_a), rb = rooms.find(r => r.id === d.room_b);
    if(!ra || !rb) return;
    const mid = sharedWallMidpoint(ra.bounds, rb.bounds);
    if(!mid) return;
    const doorWidth = 0.9;
    if(mid.vertical) svgBody += `<line class="door-mark" x1="${mid.x}" y1="${mid.y-doorWidth/2}" x2="${mid.x}" y2="${mid.y+doorWidth/2}"></line>`;
    else svgBody += `<line class="door-mark" x1="${mid.x-doorWidth/2}" y1="${mid.y}" x2="${mid.x+doorWidth/2}" y2="${mid.y}"></line>`;
  });
  svgBody += `</g>`;

  // etiquetas FUERA del grupo invertido, para que el texto no salga en espejo
  let labelsBody = '';
  rooms.forEach(r => {
    const [x0,y0,x1,y1] = r.bounds;
    const cx = (x0+x1)/2, cy = vbY*2+vbH - (y0+y1)/2;
    const w = x1-x0, h = y1-y0;
    // el tamano de fuente considera TANTO las dimensiones de la estancia
    // COMO la longitud del nombre (bug real encontrado en verificacion:
    // "Dormitorio principal" desbordaba su propio rectangulo si solo se
    // miraban las dimensiones) -- el minimo de ambos criterios.
    const fontByRoom = Math.max(0.28, Math.min(w,h) * 0.16);
    const fontByTextWidth = (w * 0.85) / (Math.max(r.name.length, 6) * 0.6);
    const fontSize = Math.max(0.18, Math.min(fontByRoom, fontByTextWidth));
    labelsBody += `<text class="room-label" x="${cx}" y="${cy}" font-size="${fontSize}">
        <tspan class="name" x="${cx}" dy="-0.6em">${escapeXml(r.name)}</tspan>
        <tspan class="area" x="${cx}" dy="1.3em">${r.area_m2.toFixed(1)}m²</tspan>
      </text>`;
  });

  const svg = `<svg viewBox="${vbX} ${vbY} ${vbW} ${vbH}" xmlns="http://www.w3.org/2000/svg">${svgBody}${labelsBody}</svg>`;

  const md = floor.data.metadata || {};
  const hv = md.hard_violations ?? 0;
  const sp = md.soft_penalty ?? 0;
  const warnings = md.warnings ?? 0;
  const totalArea = rooms.reduce((s,r) => s+r.area_m2, 0);
  const zonesPresent = [...new Set(rooms.map(r=>r.zone))];

  content.innerHTML = `
    <div class="plano-stage">
      <div class="plano-canvas">${svg}</div>
      <div class="plano-side">
        <div class="plano-box">
          <h3>Resumen</h3>
          <div class="plano-stat"><span>Estancias</span><b>${rooms.length}</b></div>
          <div class="plano-stat"><span>Superficie total</span><b>${totalArea.toFixed(1)}m²</b></div>
          <div class="plano-stat ${hv>0?'bad':'ok'}"><span>Violaciones duras</span><b>${hv}</b></div>
          <div class="plano-stat"><span>Penalización blanda</span><b>${typeof sp === 'number' ? sp.toFixed(1) : sp}</b></div>
          <div class="plano-stat"><span>Avisos</span><b>${warnings}</b></div>
        </div>
        <div class="plano-box">
          <h3>Zonas</h3>
          <div class="legend">${zonesPresent.map(z => `<span class="item"><span class="sw" style="background:${PLANO_ZONE_COLOR[z]}"></span>${PLANO_ZONE_LABEL[z]||z}</span>`).join('')}</div>
        </div>
        <div class="plano-box">
          <h3>Estancias (${rooms.length})</h3>
          ${rooms.slice().sort((a,b)=>b.area_m2-a.area_m2).map(r =>
            `<div class="plano-room-item" data-id="${r.id}"><span><span class="sw" style="background:${PLANO_ZONE_COLOR[r.zone]}"></span>${escapeXml(r.name)}</span><span>${r.area_m2.toFixed(1)}m²</span></div>`
          ).join('')}
        </div>
      </div>
    </div>`;

  content.querySelectorAll('.plano-room-item').forEach(item => {
    item.addEventListener('mouseenter', () => {
      const rect = content.querySelector(`.room-rect[data-id="${item.dataset.id}"]`);
      if(rect) rect.setAttribute('fill-opacity', '0.9');
    });
    item.addEventListener('mouseleave', () => {
      const rect = content.querySelector(`.room-rect[data-id="${item.dataset.id}"]`);
      if(rect) rect.setAttribute('fill-opacity', '0.55');
    });
  });
}

// ---------------- GENERADOR REAL EN EL NAVEGADOR (Pyodide) ----------------
// Retomado de una pregunta directa del usuario: el flujo anterior obligaba
// a exportar un JSON, salir al terminal a ejecutar el CLI, y volver a
// cargar el resultado en el visor -- un puente MANUAL entre dos mundos
// que nunca se hablaban. Esto ejecuta el generador real (housing_generator,
// el mismo codigo Python de siempre, sin reescribirlo) DENTRO del propio
// navegador via Pyodide (Python compilado a WebAssembly) -- nada de
// terminal, nada de descargar/subir archivos para el caso normal.
// shapely/geos estan oficialmente soportados por Pyodide (confirmado en
// el changelog oficial antes de construir esto, no asumido); scipy/numpy
// son parte del stack cientifico estandar; networkx es Python puro, se
// instala via micropip sin problema.
let PYODIDE_INSTANCE = null;
let PYODIDE_LOADING = null;

function setGenerateStatus(msg, kind){
  const el = document.getElementById('generate-status');
  el.className = 'generate-status' + (kind ? ' '+kind : '');
  el.innerHTML = kind === 'loading' ? '<span class="bar"></span>' + escapeXml(msg) : escapeXml(msg);
}

async function ensurePyodideReady(onProgress){
  if(PYODIDE_INSTANCE) return PYODIDE_INSTANCE;
  if(PYODIDE_LOADING) return PYODIDE_LOADING;

  PYODIDE_LOADING = (async () => {
    onProgress('Cargando Python en el navegador (Pyodide, primera vez tarda unos segundos)...');
    const pyodide = await loadPyodide();

    onProgress('Instalando shapely, numpy, scipy...');
    await pyodide.loadPackage(['shapely', 'numpy', 'scipy']);

    onProgress('Instalando networkx...');
    await pyodide.loadPackage('micropip');
    const micropip = pyodide.pyimport('micropip');
    await micropip.install('networkx');

    onProgress('Cargando housing_generator...');
    pyodide.FS.mkdirTree('/home/pyodide/src');
    for(const [relPath, content] of Object.entries(PY_BUNDLE)){
      const fullPath = '/home/pyodide/src/' + relPath;
      const dir = fullPath.substring(0, fullPath.lastIndexOf('/'));
      pyodide.FS.mkdirTree(dir);
      pyodide.FS.writeFile(fullPath, content);
    }
    pyodide.runPython("import sys\nsys.path.insert(0, '/home/pyodide/src')\n");

    PYODIDE_INSTANCE = pyodide;
    return pyodide;
  })();

  return PYODIDE_LOADING;
}

async function generarEdificioReal(seleccionPayload, lotW, lotH, seed, maxIterations, retrySeeds, viviendaAccesible, onProgress){
  const pyodide = await ensurePyodideReady(onProgress);
  onProgress('Buscando una distribucion valida (puede reintentar varias semillas)...');

  pyodide.globals.set('payload_json_str', JSON.stringify(seleccionPayload));
  pyodide.globals.set('lot_w_js', lotW);
  pyodide.globals.set('lot_h_js', lotH);
  pyodide.globals.set('seed_js', seed);
  pyodide.globals.set('max_it_js', maxIterations);
  pyodide.globals.set('retry_js', retrySeeds);
  pyodide.globals.set('accesible_js', viviendaAccesible);

  const pyCode = [
    'import json',
    'from housing_generator.interface.browser.bridge import generar_edificio',
    'payload = json.loads(payload_json_str)',
    'resultado = generar_edificio(',
    '    payload, float(lot_w_js), float(lot_h_js),',
    '    seed=int(seed_js), max_iterations=int(max_it_js),',
    '    retry_seeds=int(retry_js), vivienda_accesible=bool(accesible_js),',
    ')',
    'json.dumps(resultado)',
  ].join('\n');
  const resultStr = await pyodide.runPythonAsync(pyCode);
  return JSON.parse(resultStr);
}

async function handleGenerateNow(){
  const btn = document.getElementById('generate-now');
  const payload = buildSeleccionPayload();
  if(Object.keys(payload.levels).length === 0){
    setGenerateStatus('Selecciona al menos una estancia antes de generar (o usa "Generar seleccion" arriba).', 'error');
    return;
  }

  const lotW = parseFloat(document.getElementById('gen-lot-w').value) || 14;
  const lotH = parseFloat(document.getElementById('gen-lot-h').value) || 16;
  const seed = parseInt(document.getElementById('gen-seed').value, 10) || 1;
  const maxIterations = parseInt(document.getElementById('gen-iterations').value, 10) || 4000;
  const accesible = document.getElementById('gen-accesible').checked;

  btn.disabled = true;
  setGenerateStatus('Iniciando...', 'loading');
  try{
    const result = await generarEdificioReal(payload, lotW, lotH, seed, maxIterations, 5, accesible, (msg) => setGenerateStatus(msg, 'loading'));
    if(!result.ok){
      setGenerateStatus('No se pudo generar: ' + result.error, 'error');
      return;
    }
    LOADED_PLANS = Object.entries(result.floors).map(([level, data]) => ({
      label: labelForPlanFile(level + '.json'), data,
    }));
    ACTIVE_PLAN = 0;
    PLANO_TRANSFORM = {mirrorH: false, mirrorV: false, rotation: 0};
    const semillaMsg = result.reintentos > 0
      ? ' (semilla ' + seed + ' no convergio, funciono la ' + result.semilla_usada + ' tras ' + (result.reintentos+1) + ' intentos)'
      : ' (semilla ' + result.semilla_usada + ')';
    setGenerateStatus('Generado correctamente' + semillaMsg + '. Mostrando en el Visor de plano.', 'ok');

    document.querySelector('[data-tab="plano"]').dispatchEvent(new Event('click', {bubbles:true}));
    renderPlanoTabs();
    renderPlano();
  } catch(err){
    setGenerateStatus('Error inesperado: ' + (err && err.message ? err.message : err), 'error');
  } finally {
    btn.disabled = false;
  }
}

function escapeXml(s){
  return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
}

